window.BIBLE["Daniel"] = {"1":{"chapter":"1","title":"DANIEL'S CHOICE IN BABYLON","verses":{"1":{"text":"In the third year of the reign of Jehoiakim king of Judah came Nebuchadnezzar king of Babylon unto Jerusalem, and besieged it.","ref":"Daniel 1:1","synthesized":"In the third year of the reign of Jehoiakim king of Judah, Nebuchadnezzar king of Babylon came to Jerusalem and besieged it.","sources":{"KJV":{"text":"In the third year of the reign of Jehoiakim king of Judah came Nebuchadnezzar king of Babylon unto Jerusalem, and besieged it."},"BSB":{"text":"In the third year of the reign of Jehoiakim king of Judah, Nebuchadnezzar king of Babylon came to Jerusalem and besieged it."}},"definableWords":["year","reign","king","Judah","King","Babylon","Jerusalem"],"peopleInVerse":["Nebuchadnezzar"]},"2":{"text":"And the Lord gave Jehoiakim king of Judah into his hand, with part of the vessels of the house of God: which he carried into the land of Shinar to the house of his god; and he brought the vessels into the treasure house of his god.","ref":"Daniel 1:2","synthesized":"And the Lord delivered into his hand Jehoiakim king of Judah, along with some of the articles from the house of God. He carried these off to the land of Shinar, to the house of his god, where he put them in the treasury of his god.","sources":{"KJV":{"text":"And the Lord gave Jehoiakim king of Judah into his hand, with part of the vessels of the house of God: which he carried into the land of Shinar to the house of his god; and he brought the vessels into the treasure house of his god."},"BSB":{"text":"And the Lord delivered into his hand Jehoiakim king of Judah, along with some of the articles from the house of God. He carried these off to the land of Shinar, to the house of his god, where he put them in the treasury of his god."}},"definableWords":["Lord","king","Judah","house","God","land"],"peopleInVerse":[]},"3":{"text":"And the king spake unto Ashpenaz the master of his eunuchs, that he should bring certain of the children of Israel, and of the king’s seed, and of the princes;","ref":"Daniel 1:3","synthesized":"Then the king ordered Ashpenaz, the chief of his court officials, to bring in some Israelites from the royal family and the nobility—","sources":{"KJV":{"text":"And the king spake unto Ashpenaz the master of his eunuchs, that he should bring certain of the children of Israel, and of the king’s seed, and of the princes;"},"BSB":{"text":"Then the king ordered Ashpenaz, the chief of his court officials, to bring in some Israelites from the royal family and the nobility—"}},"definableWords":["king","Israelites","family"],"peopleInVerse":[]},"4":{"text":"Children in whom was no blemish, but well favoured, and skilful in all wisdom, and cunning in knowledge, and understanding science, and such as had ability in them to stand in the king’s palace, and whom they might teach the learning and the tongue of the Chaldeans.","ref":"Daniel 1:4","synthesized":"young men without blemish, handsome, gifted in all wisdom, knowledgeable, quick to understand, and qualified to serve in the king’s palace—and to teach them the language and literature of the Chaldeans.","sources":{"KJV":{"text":"Children in whom was no blemish, but well favoured, and skilful in all wisdom, and cunning in knowledge, and understanding science, and such as had ability in them to stand in the king’s palace, and whom they might teach the learning and the tongue of the Chaldeans."},"BSB":{"text":"young men without blemish, handsome, gifted in all wisdom, knowledgeable, quick to understand, and qualified to serve in the king’s palace—and to teach them the language and literature of the Chaldeans."}},"definableWords":["men","wisdom","king"],"peopleInVerse":[]},"5":{"text":"And the king appointed them a daily provision of the king’s meat, and of the wine which he drank: so nourishing them three years, that at the end thereof they might stand before the king.","ref":"Daniel 1:5","synthesized":"The king assigned them daily provisions of the royal food and wine. They were to be trained for three years, after which they were to enter the king’s service.","sources":{"KJV":{"text":"And the king appointed them a daily provision of the king’s meat, and of the wine which he drank: so nourishing them three years, that at the end thereof they might stand before the king."},"BSB":{"text":"The king assigned them daily provisions of the royal food and wine. They were to be trained for three years, after which they were to enter the king’s service."}},"definableWords":["king","years","King"],"peopleInVerse":[]},"6":{"text":"Now among these were of the children of Judah, Daniel, Hananiah, Mishael, and Azariah:","ref":"Daniel 1:6","synthesized":"Among these young men were some from Judah: Daniel, Hananiah, Mishael, and Azariah.","sources":{"KJV":{"text":"Now among these were of the children of Judah, Daniel, Hananiah, Mishael, and Azariah:"},"BSB":{"text":"Among these young men were some from Judah: Daniel, Hananiah, Mishael, and Azariah."}},"definableWords":["men","Judah"],"peopleInVerse":["Daniel"]},"7":{"text":"Unto whom the prince of the eunuchs gave names: for he gave unto Daniel the name of Belteshazzar; and to Hananiah, of Shadrach; and to Mishael, of Meshach; and to Azariah, of Abednego.","ref":"Daniel 1:7","synthesized":"The chief official gave them new names: To Daniel he gave the name Belteshazzar; to Hananiah, Shadrach; to Mishael, Meshach; and to Azariah, Abednego.","sources":{"KJV":{"text":"Unto whom the prince of the eunuchs gave names: for he gave unto Daniel the name of Belteshazzar; and to Hananiah, of Shadrach; and to Mishael, of Meshach; and to Azariah, of Abednego."},"BSB":{"text":"The chief official gave them new names: To Daniel he gave the name Belteshazzar; to Hananiah, Shadrach; to Mishael, Meshach; and to Azariah, Abednego."}},"definableWords":["name"],"peopleInVerse":["Daniel"]},"8":{"text":"But Daniel purposed in his heart that he would not defile himself with the portion of the king’s meat, nor with the wine which he drank: therefore he requested of the prince of the eunuchs that he might not defile himself.","ref":"Daniel 1:8","synthesized":"But Daniel made up his mind that he would not defile himself with the king’s food or wine. So he asked the chief official for permission not to defile himself.","sources":{"KJV":{"text":"But Daniel purposed in his heart that he would not defile himself with the portion of the king’s meat, nor with the wine which he drank: therefore he requested of the prince of the eunuchs that he might not defile himself."},"BSB":{"text":"But Daniel made up his mind that he would not defile himself with the king’s food or wine. So he asked the chief official for permission not to defile himself."}},"definableWords":["made","mind","king","or"],"peopleInVerse":["Daniel"]},"9":{"text":"Now God had brought Daniel into favour and tender love with the prince of the eunuchs.","ref":"Daniel 1:9","synthesized":"Now God had granted Daniel favor and compassion from the chief official,","sources":{"KJV":{"text":"Now God had brought Daniel into favour and tender love with the prince of the eunuchs."},"BSB":{"text":"Now God had granted Daniel favor and compassion from the chief official,"}},"definableWords":["God"],"peopleInVerse":["Daniel"]},"10":{"text":"And the prince of the eunuchs said unto Daniel, I fear my lord the king, who hath appointed your meat and your drink: for why should he see your faces worse liking than the children which are of your sort? then shall ye make me endanger my head to the king.","ref":"Daniel 1:10","synthesized":"but he said to Daniel, “I fear my lord the king, who has assigned your food and drink. For why should he see your faces looking thinner than those of the other young men your age? You would endanger my head before the king!”","sources":{"KJV":{"text":"And the prince of the eunuchs said unto Daniel, I fear my lord the king, who hath appointed your meat and your drink: for why should he see your faces worse liking than the children which are of your sort? then shall ye make me endanger my head to the king."},"BSB":{"text":"but he said to Daniel, “I fear my lord the king, who has assigned your food and drink. For why should he see your faces looking thinner than those of the other young men your age? You would endanger my head before the king!”"}},"definableWords":["fear","Lord","king","see","men","King"],"peopleInVerse":["Daniel"]},"11":{"text":"Then said Daniel to Melzar, whom the prince of the eunuchs had set over Daniel, Hananiah, Mishael, and Azariah,","ref":"Daniel 1:11","synthesized":"Then Daniel said to the steward whom the chief official had appointed over Daniel, Hananiah, Mishael, and Azariah,","sources":{"KJV":{"text":"Then said Daniel to Melzar, whom the prince of the eunuchs had set over Daniel, Hananiah, Mishael, and Azariah,"},"BSB":{"text":"Then Daniel said to the steward whom the chief official had appointed over Daniel, Hananiah, Mishael, and Azariah,"}},"definableWords":[],"peopleInVerse":["Daniel"]},"12":{"text":"Prove thy servants, I beseech thee, ten days; and let them give us pulse to eat, and water to drink.","ref":"Daniel 1:12","synthesized":"“Please test your servants for ten days. Let us be given only vegetables to eat and water to drink.","sources":{"KJV":{"text":"Prove thy servants, I beseech thee, ten days; and let them give us pulse to eat, and water to drink."},"BSB":{"text":"“Please test your servants for ten days. Let us be given only vegetables to eat and water to drink."}},"definableWords":["servants","days","water"],"peopleInVerse":[]},"13":{"text":"Then let our countenances be looked upon before thee, and the countenance of the children that eat of the portion of the king’s meat: and as thou seest, deal with thy servants.","ref":"Daniel 1:13","synthesized":"Then compare our appearances with those of the young men who are eating the royal food, and deal with your servants according to what you see.”","sources":{"KJV":{"text":"Then let our countenances be looked upon before thee, and the countenance of the children that eat of the portion of the king’s meat: and as thou seest, deal with thy servants."},"BSB":{"text":"Then compare our appearances with those of the young men who are eating the royal food, and deal with your servants according to what you see.”"}},"definableWords":["men","servants","see"],"peopleInVerse":[]},"14":{"text":"So he consented to them in this matter, and proved them ten days.","ref":"Daniel 1:14","synthesized":"So he consented to this and tested them for ten days.","sources":{"KJV":{"text":"So he consented to them in this matter, and proved them ten days."},"BSB":{"text":"So he consented to this and tested them for ten days."}},"definableWords":["days"],"peopleInVerse":[]},"15":{"text":"And at the end of ten days their countenances appeared fairer and fatter in flesh than all the children which did eat the portion of the king’s meat.","ref":"Daniel 1:15","synthesized":"And at the end of ten days, they looked healthier and better nourished than all the young men who were eating the king’s food.","sources":{"KJV":{"text":"And at the end of ten days their countenances appeared fairer and fatter in flesh than all the children which did eat the portion of the king’s meat."},"BSB":{"text":"And at the end of ten days, they looked healthier and better nourished than all the young men who were eating the king’s food."}},"definableWords":["days","men","king"],"peopleInVerse":[]},"16":{"text":"Thus Melzar took away the portion of their meat, and the wine that they should drink; and gave them pulse.","ref":"Daniel 1:16","synthesized":"So the steward continued to withhold their choice food and the wine they were to drink, and he gave them vegetables instead.","sources":{"KJV":{"text":"Thus Melzar took away the portion of their meat, and the wine that they should drink; and gave them pulse."},"BSB":{"text":"So the steward continued to withhold their choice food and the wine they were to drink, and he gave them vegetables instead."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"As for these four children, God gave them knowledge and skill in all learning and wisdom: and Daniel had understanding in all visions and dreams.","ref":"Daniel 1:17","synthesized":"To these four young men God gave knowledge and understanding in every kind of literature and wisdom. And Daniel had insight into all kinds of visions and dreams.","sources":{"KJV":{"text":"As for these four children, God gave them knowledge and skill in all learning and wisdom: and Daniel had understanding in all visions and dreams."},"BSB":{"text":"To these four young men God gave knowledge and understanding in every kind of literature and wisdom. And Daniel had insight into all kinds of visions and dreams."}},"definableWords":["men","God","knowledge","wisdom"],"peopleInVerse":["Daniel"]},"18":{"text":"Now at the end of the days that the king had said he should bring them in, then the prince of the eunuchs brought them in before Nebuchadnezzar.","ref":"Daniel 1:18","synthesized":"Now at the end of the time specified by the king, the chief official presented them to Nebuchadnezzar.","sources":{"KJV":{"text":"Now at the end of the days that the king had said he should bring them in, then the prince of the eunuchs brought them in before Nebuchadnezzar."},"BSB":{"text":"Now at the end of the time specified by the king, the chief official presented them to Nebuchadnezzar."}},"definableWords":["king"],"peopleInVerse":["Nebuchadnezzar"]},"19":{"text":"And the king communed with them; and among them all was found none like Daniel, Hananiah, Mishael, and Azariah: therefore stood they before the king.","ref":"Daniel 1:19","synthesized":"And the king spoke with them, and among all the young men he found no one equal to Daniel, Hananiah, Mishael, and Azariah. So they entered the king’s service.","sources":{"KJV":{"text":"And the king communed with them; and among them all was found none like Daniel, Hananiah, Mishael, and Azariah: therefore stood they before the king."},"BSB":{"text":"And the king spoke with them, and among all the young men he found no one equal to Daniel, Hananiah, Mishael, and Azariah. So they entered the king’s service."}},"definableWords":["king","men","one","King"],"peopleInVerse":["Daniel"]},"20":{"text":"And in all matters of wisdom and understanding, that the king enquired of them, he found them ten times better than all the magicians and astrologers that were in all his realm.","ref":"Daniel 1:20","synthesized":"In every matter of wisdom and understanding about which the king consulted them, he found them ten times better than all the magicians and enchanters in his entire kingdom.","sources":{"KJV":{"text":"And in all matters of wisdom and understanding, that the king enquired of them, he found them ten times better than all the magicians and astrologers that were in all his realm."},"BSB":{"text":"In every matter of wisdom and understanding about which the king consulted them, he found them ten times better than all the magicians and enchanters in his entire kingdom."}},"definableWords":["wisdom","king","kingdom"],"peopleInVerse":[]},"21":{"text":"And Daniel continued even unto the first year of king Cyrus.","ref":"Daniel 1:21","synthesized":"And Daniel remained there until the first year of King Cyrus.","sources":{"KJV":{"text":"And Daniel continued even unto the first year of king Cyrus."},"BSB":{"text":"And Daniel remained there until the first year of King Cyrus."}},"definableWords":["year","King"],"peopleInVerse":["Daniel","Cyrus"]}}},"2":{"chapter":"2","title":"NEBUCHADNEZZAR'S STATUE DREAM","verses":{"1":{"text":"And in the second year of the reign of Nebuchadnezzar Nebuchadnezzar dreamed dreams, wherewith his spirit was troubled, and his sleep brake from him.","ref":"Daniel 2:1","synthesized":"In the second year of his reign, Nebuchadnezzar had dreams that troubled his spirit, and sleep escaped him.","sources":{"KJV":{"text":"And in the second year of the reign of Nebuchadnezzar Nebuchadnezzar dreamed dreams, wherewith his spirit was troubled, and his sleep brake from him."},"BSB":{"text":"In the second year of his reign, Nebuchadnezzar had dreams that troubled his spirit, and sleep escaped him."}},"definableWords":["year","reign","spirit"],"peopleInVerse":["Nebuchadnezzar"]},"2":{"text":"Then the king commanded to call the magicians, and the astrologers, and the sorcerers, and the Chaldeans, for to shew the king his dreams. So they came and stood before the king.","ref":"Daniel 2:2","synthesized":"So the king gave orders to summon the magicians, enchanters, sorcerers, and astrologers to explain his dreams. When they came and stood before the king,","sources":{"KJV":{"text":"Then the king commanded to call the magicians, and the astrologers, and the sorcerers, and the Chaldeans, for to shew the king his dreams. So they came and stood before the king."},"BSB":{"text":"So the king gave orders to summon the magicians, enchanters, sorcerers, and astrologers to explain his dreams. When they came and stood before the king,"}},"definableWords":["king","King"],"peopleInVerse":[]},"3":{"text":"And the king said unto them, I have dreamed a dream, and my spirit was troubled to know the dream.","ref":"Daniel 2:3","synthesized":"he said to them, “I have had a dream, and my spirit is anxious to understand it.”","sources":{"KJV":{"text":"And the king said unto them, I have dreamed a dream, and my spirit was troubled to know the dream."},"BSB":{"text":"he said to them, “I have had a dream, and my spirit is anxious to understand it.”"}},"definableWords":["spirit"],"peopleInVerse":[]},"4":{"text":"Then spake the Chaldeans to the king in Syriack, O king, live for ever: tell thy servants the dream, and we will shew the interpretation.","ref":"Daniel 2:4","synthesized":"Then the astrologers answered the king in Aramaic, “O king, may you live forever! Tell your servants the dream, and we will give the interpretation.”","sources":{"KJV":{"text":"Then spake the Chaldeans to the king in Syriack, O king, live for ever: tell thy servants the dream, and we will shew the interpretation."},"BSB":{"text":"Then the astrologers answered the king in Aramaic, “O king, may you live forever! Tell your servants the dream, and we will give the interpretation.”"}},"definableWords":["king","King","live","servants"],"peopleInVerse":[]},"5":{"text":"The king answered and said to the Chaldeans, The thing is gone from me: if ye will not make known unto me the dream, with the interpretation thereof, ye shall be cut in pieces, and your houses shall be made a dunghill.","ref":"Daniel 2:5","synthesized":"The king replied to the astrologers, “My word is final: If you do not tell me the dream and its interpretation, you will be cut into pieces and your houses will be reduced to rubble.","sources":{"KJV":{"text":"The king answered and said to the Chaldeans, The thing is gone from me: if ye will not make known unto me the dream, with the interpretation thereof, ye shall be cut in pieces, and your houses shall be made a dunghill."},"BSB":{"text":"The king replied to the astrologers, “My word is final: If you do not tell me the dream and its interpretation, you will be cut into pieces and your houses will be reduced to rubble."}},"definableWords":["king","word"],"peopleInVerse":[]},"6":{"text":"But if ye shew the dream, and the interpretation thereof, ye shall receive of me gifts and rewards and great honour: therefore shew me the dream, and the interpretation thereof.","ref":"Daniel 2:6","synthesized":"But if you tell me the dream and its interpretation, you will receive from me gifts and rewards and great honor. So tell me the dream and its interpretation.”","sources":{"KJV":{"text":"But if ye shew the dream, and the interpretation thereof, ye shall receive of me gifts and rewards and great honour: therefore shew me the dream, and the interpretation thereof."},"BSB":{"text":"But if you tell me the dream and its interpretation, you will receive from me gifts and rewards and great honor. So tell me the dream and its interpretation.”"}},"definableWords":["great"],"peopleInVerse":[]},"7":{"text":"They answered again and said, Let the king tell his servants the dream, and we will shew the interpretation of it.","ref":"Daniel 2:7","synthesized":"They answered a second time, “Let the king tell the dream to his servants, and we will give the interpretation.”","sources":{"KJV":{"text":"They answered again and said, Let the king tell his servants the dream, and we will shew the interpretation of it."},"BSB":{"text":"They answered a second time, “Let the king tell the dream to his servants, and we will give the interpretation.”"}},"definableWords":["king","servants"],"peopleInVerse":[]},"8":{"text":"The king answered and said, I know of certainty that ye would gain the time, because ye see the thing is gone from me.","ref":"Daniel 2:8","synthesized":"The king replied, “I know for sure that you are stalling for time, because you see that my word is final.","sources":{"KJV":{"text":"The king answered and said, I know of certainty that ye would gain the time, because ye see the thing is gone from me."},"BSB":{"text":"The king replied, “I know for sure that you are stalling for time, because you see that my word is final."}},"definableWords":["king","see","word"],"peopleInVerse":[]},"9":{"text":"But if ye will not make known unto me the dream, there is but one decree for you: for ye have prepared lying and corrupt words to speak before me, till the time be changed: therefore tell me the dream, and I shall know that ye can shew me the interpretation thereof.","ref":"Daniel 2:9","synthesized":"If you do not tell me the dream, there is only one decree for you. You have conspired to speak before me false and fraudulent words, hoping the situation will change. Therefore tell me the dream, and I will know that you can give me its interpretation.”","sources":{"KJV":{"text":"But if ye will not make known unto me the dream, there is but one decree for you: for ye have prepared lying and corrupt words to speak before me, till the time be changed: therefore tell me the dream, and I shall know that ye can shew me the interpretation thereof."},"BSB":{"text":"If you do not tell me the dream, there is only one decree for you. You have conspired to speak before me false and fraudulent words, hoping the situation will change. Therefore tell me the dream, and I will know that you can give me its interpretation.”"}},"definableWords":["one"],"peopleInVerse":[]},"10":{"text":"The Chaldeans answered before the king, and said, There is not a man upon the earth that can shew the king’s matter: therefore there is no king, lord, nor ruler, that asked such things at any magician, or astrologer, or Chaldean.","ref":"Daniel 2:10","synthesized":"The astrologers answered the king, “No one on earth can do what the king requests! No king, however great and powerful, has ever asked anything like this of any magician, enchanter, or astrologer.","sources":{"KJV":{"text":"The Chaldeans answered before the king, and said, There is not a man upon the earth that can shew the king’s matter: therefore there is no king, lord, nor ruler, that asked such things at any magician, or astrologer, or Chaldean."},"BSB":{"text":"The astrologers answered the king, “No one on earth can do what the king requests! No king, however great and powerful, has ever asked anything like this of any magician, enchanter, or astrologer."}},"definableWords":["king","one","earth","King","great","or"],"peopleInVerse":[]},"11":{"text":"And it is a rare thing that the king requireth, and there is none other that can shew it before the king, except the gods, whose dwelling is not with flesh.","ref":"Daniel 2:11","synthesized":"What the king requests is so difficult that no one can tell it to him except the gods, whose dwelling is not with mortals.”","sources":{"KJV":{"text":"And it is a rare thing that the king requireth, and there is none other that can shew it before the king, except the gods, whose dwelling is not with flesh."},"BSB":{"text":"What the king requests is so difficult that no one can tell it to him except the gods, whose dwelling is not with mortals.”"}},"definableWords":["king","one"],"peopleInVerse":[]},"12":{"text":"For this cause the king was angry and very furious, and commanded to destroy all the wise men of Babylon.","ref":"Daniel 2:12","synthesized":"This response made the king so furious with anger that he gave orders to destroy all the wise men of Babylon.","sources":{"KJV":{"text":"For this cause the king was angry and very furious, and commanded to destroy all the wise men of Babylon."},"BSB":{"text":"This response made the king so furious with anger that he gave orders to destroy all the wise men of Babylon."}},"definableWords":["made","king","anger","men","Babylon"],"peopleInVerse":[]},"13":{"text":"And the decree went forth that the wise men should be slain; and they sought Daniel and his fellows to be slain.","ref":"Daniel 2:13","synthesized":"So the decree went out that the wise men were to be executed, and men went to look for Daniel and his friends to execute them.","sources":{"KJV":{"text":"And the decree went forth that the wise men should be slain; and they sought Daniel and his fellows to be slain."},"BSB":{"text":"So the decree went out that the wise men were to be executed, and men went to look for Daniel and his friends to execute them."}},"definableWords":["men"],"peopleInVerse":["Daniel"]},"14":{"text":"Then Daniel answered with counsel and wisdom to Arioch the captain of the king’s guard, which was gone forth to slay the wise men of Babylon:","ref":"Daniel 2:14","synthesized":"When Arioch, the commander of the king’s guard, had gone out to execute the wise men of Babylon, Daniel replied with discretion and tact.","sources":{"KJV":{"text":"Then Daniel answered with counsel and wisdom to Arioch the captain of the king’s guard, which was gone forth to slay the wise men of Babylon:"},"BSB":{"text":"When Arioch, the commander of the king’s guard, had gone out to execute the wise men of Babylon, Daniel replied with discretion and tact."}},"definableWords":["king","men","Babylon"],"peopleInVerse":["Daniel"]},"15":{"text":"He answered and said to Arioch the king’s captain, Why is the decree so hasty from the king? Then Arioch made the thing known to Daniel.","ref":"Daniel 2:15","synthesized":"“Why is the decree from the king so harsh?” he asked.  At this time Arioch explained the situation to Daniel.","sources":{"KJV":{"text":"He answered and said to Arioch the king’s captain, Why is the decree so hasty from the king? Then Arioch made the thing known to Daniel."},"BSB":{"text":"“Why is the decree from the king so harsh?” he asked.  At this time Arioch explained the situation to Daniel."}},"definableWords":["king"],"peopleInVerse":["Daniel"]},"16":{"text":"Then Daniel went in, and desired of the king that he would give him time, and that he would shew the king the interpretation.","ref":"Daniel 2:16","synthesized":"So Daniel went in and asked the king to give him some time, so that he could give him the interpretation.","sources":{"KJV":{"text":"Then Daniel went in, and desired of the king that he would give him time, and that he would shew the king the interpretation."},"BSB":{"text":"So Daniel went in and asked the king to give him some time, so that he could give him the interpretation."}},"definableWords":["king"],"peopleInVerse":["Daniel"]},"17":{"text":"Then Daniel went to his house, and made the thing known to Hananiah, Mishael, and Azariah, his companions:","ref":"Daniel 2:17","synthesized":"Then Daniel returned to his house and explained the matter to his friends Hananiah, Mishael, and Azariah,","sources":{"KJV":{"text":"Then Daniel went to his house, and made the thing known to Hananiah, Mishael, and Azariah, his companions:"},"BSB":{"text":"Then Daniel returned to his house and explained the matter to his friends Hananiah, Mishael, and Azariah,"}},"definableWords":["house"],"peopleInVerse":["Daniel"]},"18":{"text":"That they would desire mercies of the God of heaven concerning this secret; that Daniel and his fellows should not perish with the rest of the wise men of Babylon.","ref":"Daniel 2:18","synthesized":"urging them to plead for mercy from the God of heaven concerning this mystery, so that Daniel and his friends would not be killed with the rest of the wise men of Babylon.","sources":{"KJV":{"text":"That they would desire mercies of the God of heaven concerning this secret; that Daniel and his fellows should not perish with the rest of the wise men of Babylon."},"BSB":{"text":"urging them to plead for mercy from the God of heaven concerning this mystery, so that Daniel and his friends would not be killed with the rest of the wise men of Babylon."}},"definableWords":["mercy","God","heaven","rest","men","Babylon"],"peopleInVerse":["Daniel"]},"19":{"text":"Then was the secret revealed unto Daniel in a night vision. Then Daniel blessed the God of heaven.","ref":"Daniel 2:19","synthesized":"During the night, the mystery was revealed to Daniel in a vision, and he blessed the God of heaven","sources":{"KJV":{"text":"Then was the secret revealed unto Daniel in a night vision. Then Daniel blessed the God of heaven."},"BSB":{"text":"During the night, the mystery was revealed to Daniel in a vision, and he blessed the God of heaven"}},"definableWords":["night","blessed","God","heaven"],"peopleInVerse":["Daniel"]},"20":{"text":"Daniel answered and said, Blessed be the name of God for ever and ever: for wisdom and might are his:","ref":"Daniel 2:20","synthesized":"and declared:  “Blessed be the name of God forever and ever, for wisdom and power belong to Him.","sources":{"KJV":{"text":"Daniel answered and said, Blessed be the name of God for ever and ever: for wisdom and might are his:"},"BSB":{"text":"and declared:  “Blessed be the name of God forever and ever, for wisdom and power belong to Him."}},"definableWords":["blessed","name","God","wisdom"],"peopleInVerse":[]},"21":{"text":"And he changeth the times and the seasons: he removeth kings, and setteth up kings: he giveth wisdom unto the wise, and knowledge to them that know understanding:","ref":"Daniel 2:21","synthesized":"He changes the times and seasons; He removes kings and establishes them. He gives wisdom to the wise and knowledge to the discerning.","sources":{"KJV":{"text":"And he changeth the times and the seasons: he removeth kings, and setteth up kings: he giveth wisdom unto the wise, and knowledge to them that know understanding:"},"BSB":{"text":"He changes the times and seasons; He removes kings and establishes them. He gives wisdom to the wise and knowledge to the discerning."}},"definableWords":["kings","wisdom","knowledge"],"peopleInVerse":[]},"22":{"text":"He revealeth the deep and secret things: he knoweth what is in the darkness, and the light dwelleth with him.","ref":"Daniel 2:22","synthesized":"He reveals the deep and hidden things; He knows what lies in darkness, and light dwells with Him.","sources":{"KJV":{"text":"He revealeth the deep and secret things: he knoweth what is in the darkness, and the light dwelleth with him."},"BSB":{"text":"He reveals the deep and hidden things; He knows what lies in darkness, and light dwells with Him."}},"definableWords":["deep","darkness","light"],"peopleInVerse":[]},"23":{"text":"I thank thee, and praise thee, O thou God of my fathers, who hast given me wisdom and might, and hast made known unto me now what we desired of thee: for thou hast now made known unto us the king’s matter.","ref":"Daniel 2:23","synthesized":"To You, O God of my fathers, I give thanks and praise, because You have given me wisdom and power. And now You have made known to me what we have requested, for You have made known to us the dream of the king.”","sources":{"KJV":{"text":"I thank thee, and praise thee, O thou God of my fathers, who hast given me wisdom and might, and hast made known unto me now what we desired of thee: for thou hast now made known unto us the king’s matter."},"BSB":{"text":"To You, O God of my fathers, I give thanks and praise, because You have given me wisdom and power. And now You have made known to me what we have requested, for You have made known to us the dream of the king.”"}},"definableWords":["God","fathers","praise","wisdom","made","king"],"peopleInVerse":[]},"24":{"text":"Therefore Daniel went in unto Arioch, whom the king had ordained to destroy the wise men of Babylon: he went and said thus unto him; Destroy not the wise men of Babylon: bring me in before the king, and I will shew unto the king the interpretation.","ref":"Daniel 2:24","synthesized":"Therefore Daniel went to Arioch, whom the king had appointed to destroy the wise men of Babylon, and said to him, “Do not execute the wise men of Babylon! Bring me before the king, and I will give him the interpretation.”","sources":{"KJV":{"text":"Therefore Daniel went in unto Arioch, whom the king had ordained to destroy the wise men of Babylon: he went and said thus unto him; Destroy not the wise men of Babylon: bring me in before the king, and I will shew unto the king the interpretation."},"BSB":{"text":"Therefore Daniel went to Arioch, whom the king had appointed to destroy the wise men of Babylon, and said to him, “Do not execute the wise men of Babylon! Bring me before the king, and I will give him the interpretation.”"}},"definableWords":["king","men","Babylon","King"],"peopleInVerse":["Daniel"]},"25":{"text":"Then Arioch brought in Daniel before the king in haste, and said thus unto him, I have found a man of the captives of Judah, that will make known unto the king the interpretation.","ref":"Daniel 2:25","synthesized":"Arioch hastily brought Daniel before the king and said to him, “I have found a man among the exiles from Judah who will tell the king the interpretation.”","sources":{"KJV":{"text":"Then Arioch brought in Daniel before the king in haste, and said thus unto him, I have found a man of the captives of Judah, that will make known unto the king the interpretation."},"BSB":{"text":"Arioch hastily brought Daniel before the king and said to him, “I have found a man among the exiles from Judah who will tell the king the interpretation.”"}},"definableWords":["king","man","Judah","King"],"peopleInVerse":["Daniel"]},"26":{"text":"The king answered and said to Daniel, whose name was Belteshazzar, Art thou able to make known unto me the dream which I have seen, and the interpretation thereof?","ref":"Daniel 2:26","synthesized":"The king responded to Daniel, whose name was Belteshazzar, “Are you able to tell me what I saw in the dream, as well as its interpretation?”","sources":{"KJV":{"text":"The king answered and said to Daniel, whose name was Belteshazzar, Art thou able to make known unto me the dream which I have seen, and the interpretation thereof?"},"BSB":{"text":"The king responded to Daniel, whose name was Belteshazzar, “Are you able to tell me what I saw in the dream, as well as its interpretation?”"}},"definableWords":["king","name","saw"],"peopleInVerse":["Daniel"]},"27":{"text":"Daniel answered in the presence of the king, and said, The secret which the king hath demanded cannot the wise men, the astrologers, the magicians, the soothsayers, shew unto the king;","ref":"Daniel 2:27","synthesized":"Daniel answered the king, “No wise man, enchanter, medium, or magician can explain to the king the mystery of which he inquires.","sources":{"KJV":{"text":"Daniel answered in the presence of the king, and said, The secret which the king hath demanded cannot the wise men, the astrologers, the magicians, the soothsayers, shew unto the king;"},"BSB":{"text":"Daniel answered the king, “No wise man, enchanter, medium, or magician can explain to the king the mystery of which he inquires."}},"definableWords":["king","man","or","King"],"peopleInVerse":["Daniel"]},"28":{"text":"But there is a God in heaven that revealeth secrets, and maketh known to the king Nebuchadnezzar what shall be in the latter days. Thy dream, and the visions of thy head upon thy bed, are these;","ref":"Daniel 2:28","synthesized":"But there is a God in heaven who reveals mysteries, and He has made known to King Nebuchadnezzar what will happen in the latter days. Your dream and the visions that came into your mind as you lay on your bed were these:","sources":{"KJV":{"text":"But there is a God in heaven that revealeth secrets, and maketh known to the king Nebuchadnezzar what shall be in the latter days. Thy dream, and the visions of thy head upon thy bed, are these;"},"BSB":{"text":"But there is a God in heaven who reveals mysteries, and He has made known to King Nebuchadnezzar what will happen in the latter days. Your dream and the visions that came into your mind as you lay on your bed were these:"}},"definableWords":["God","heaven","made","King","days","mind"],"peopleInVerse":["Nebuchadnezzar"]},"29":{"text":"As for thee, O king, thy thoughts came into thy mind upon thy bed, what should come to pass hereafter: and he that revealeth secrets maketh known to thee what shall come to pass.","ref":"Daniel 2:29","synthesized":"As you lay on your bed, O king, your thoughts turned to the future, and the Revealer of Mysteries made known to you what will happen.","sources":{"KJV":{"text":"As for thee, O king, thy thoughts came into thy mind upon thy bed, what should come to pass hereafter: and he that revealeth secrets maketh known to thee what shall come to pass."},"BSB":{"text":"As you lay on your bed, O king, your thoughts turned to the future, and the Revealer of Mysteries made known to you what will happen."}},"definableWords":["king","made"],"peopleInVerse":[]},"30":{"text":"But as for me, this secret is not revealed to me for any wisdom that I have more than any living, but for their sakes that shall make known the interpretation to the king, and that thou mightest know the thoughts of thy heart.","ref":"Daniel 2:30","synthesized":"And to me this mystery has been revealed, not because I have more wisdom than any man alive, but in order that the interpretation might be made known to the king, and that you may understand the thoughts of your mind.","sources":{"KJV":{"text":"But as for me, this secret is not revealed to me for any wisdom that I have more than any living, but for their sakes that shall make known the interpretation to the king, and that thou mightest know the thoughts of thy heart."},"BSB":{"text":"And to me this mystery has been revealed, not because I have more wisdom than any man alive, but in order that the interpretation might be made known to the king, and that you may understand the thoughts of your mind."}},"definableWords":["wisdom","man","made","king","mind"],"peopleInVerse":[]},"31":{"text":"Thou, O king, sawest, and behold a great image. This great image, whose brightness was excellent, stood before thee; and the form thereof was terrible.","ref":"Daniel 2:31","synthesized":"As you, O king, were watching, a great statue appeared. A great and dazzling statue stood before you, and its form was awesome.","sources":{"KJV":{"text":"Thou, O king, sawest, and behold a great image. This great image, whose brightness was excellent, stood before thee; and the form thereof was terrible."},"BSB":{"text":"As you, O king, were watching, a great statue appeared. A great and dazzling statue stood before you, and its form was awesome."}},"definableWords":["king","great","form"],"peopleInVerse":[]},"32":{"text":"This image’s head was of fine gold, his breast and his arms of silver, his belly and his thighs of brass,","ref":"Daniel 2:32","synthesized":"The head of the statue was pure gold, its chest and arms were silver, its belly and thighs were bronze,","sources":{"KJV":{"text":"This image’s head was of fine gold, his breast and his arms of silver, his belly and his thighs of brass,"},"BSB":{"text":"The head of the statue was pure gold, its chest and arms were silver, its belly and thighs were bronze,"}},"definableWords":[],"peopleInVerse":[]},"33":{"text":"His legs of iron, his feet part of iron and part of clay.","ref":"Daniel 2:33","synthesized":"its legs were iron, and its feet were part iron and part clay.","sources":{"KJV":{"text":"His legs of iron, his feet part of iron and part of clay."},"BSB":{"text":"its legs were iron, and its feet were part iron and part clay."}},"definableWords":[],"peopleInVerse":[]},"34":{"text":"Thou sawest till that a stone was cut out without hands, which smote the image upon his feet that were of iron and clay, and brake them to pieces.","ref":"Daniel 2:34","synthesized":"As you watched, a stone was cut out, but not by human hands. It struck the statue on its feet of iron and clay, and crushed them.","sources":{"KJV":{"text":"Thou sawest till that a stone was cut out without hands, which smote the image upon his feet that were of iron and clay, and brake them to pieces."},"BSB":{"text":"As you watched, a stone was cut out, but not by human hands. It struck the statue on its feet of iron and clay, and crushed them."}},"definableWords":["stone"],"peopleInVerse":[]},"35":{"text":"Then was the iron, the clay, the brass, the silver, and the gold, broken to pieces together, and became like the chaff of the summer threshingfloors; and the wind carried them away, that no place was found for them: and the stone that smote the image became a great mountain, and filled the whole earth.","ref":"Daniel 2:35","synthesized":"Then the iron, clay, bronze, silver, and gold were shattered and became like chaff on the threshing floor in summer. The wind carried them away, and not a trace of them could be found. But the stone that had struck the statue became a great mountain and filled the whole earth.","sources":{"KJV":{"text":"Then was the iron, the clay, the brass, the silver, and the gold, broken to pieces together, and became like the chaff of the summer threshingfloors; and the wind carried them away, that no place was found for them: and the stone that smote the image became a great mountain, and filled the whole earth."},"BSB":{"text":"Then the iron, clay, bronze, silver, and gold were shattered and became like chaff on the threshing floor in summer. The wind carried them away, and not a trace of them could be found. But the stone that had struck the statue became a great mountain and filled the whole earth."}},"definableWords":["stone","great","earth"],"peopleInVerse":[]},"36":{"text":"This is the dream; and we will tell the interpretation thereof before the king.","ref":"Daniel 2:36","synthesized":"This was the dream; now we will tell the king its interpretation.","sources":{"KJV":{"text":"This is the dream; and we will tell the interpretation thereof before the king."},"BSB":{"text":"This was the dream; now we will tell the king its interpretation."}},"definableWords":["king"],"peopleInVerse":[]},"37":{"text":"Thou, O king, art a king of kings: for the God of heaven hath given thee a kingdom, power, and strength, and glory.","ref":"Daniel 2:37","synthesized":"You, O king, are the king of kings, to whom the God of heaven has given sovereignty, power, strength, and glory.","sources":{"KJV":{"text":"Thou, O king, art a king of kings: for the God of heaven hath given thee a kingdom, power, and strength, and glory."},"BSB":{"text":"You, O king, are the king of kings, to whom the God of heaven has given sovereignty, power, strength, and glory."}},"definableWords":["king","King","kings","God","heaven","glory"],"peopleInVerse":[]},"38":{"text":"And wheresoever the children of men dwell, the beasts of the field and the fowls of the heaven hath he given into thine hand, and hath made thee ruler over them all. Thou art this head of gold.","ref":"Daniel 2:38","synthesized":"Wherever the sons of men or beasts of the field or birds of the air dwell, He has given them into your hand and has made you ruler over them all. You are that head of gold.","sources":{"KJV":{"text":"And wheresoever the children of men dwell, the beasts of the field and the fowls of the heaven hath he given into thine hand, and hath made thee ruler over them all. Thou art this head of gold."},"BSB":{"text":"Wherever the sons of men or beasts of the field or birds of the air dwell, He has given them into your hand and has made you ruler over them all. You are that head of gold."}},"definableWords":["sons","men","or","field","birds","made","ruler"],"peopleInVerse":[]},"39":{"text":"And after thee shall arise another kingdom inferior to thee, and another third kingdom of brass, which shall bear rule over all the earth.","ref":"Daniel 2:39","synthesized":"But after you, there will arise another kingdom, inferior to yours.  Next, a third kingdom, one of bronze, will rule the whole earth.","sources":{"KJV":{"text":"And after thee shall arise another kingdom inferior to thee, and another third kingdom of brass, which shall bear rule over all the earth."},"BSB":{"text":"But after you, there will arise another kingdom, inferior to yours.  Next, a third kingdom, one of bronze, will rule the whole earth."}},"definableWords":["kingdom","one","rule","earth"],"peopleInVerse":[]},"40":{"text":"And the fourth kingdom shall be strong as iron: forasmuch as iron breaketh in pieces and subdueth all things: and as iron that breaketh all these, shall it break in pieces and bruise.","ref":"Daniel 2:40","synthesized":"Finally, there will be a fourth kingdom as strong as iron; for iron shatters and crushes all things, and like iron that crushes all things, it will shatter and crush all the others.","sources":{"KJV":{"text":"And the fourth kingdom shall be strong as iron: forasmuch as iron breaketh in pieces and subdueth all things: and as iron that breaketh all these, shall it break in pieces and bruise."},"BSB":{"text":"Finally, there will be a fourth kingdom as strong as iron; for iron shatters and crushes all things, and like iron that crushes all things, it will shatter and crush all the others."}},"definableWords":["kingdom","strong"],"peopleInVerse":[]},"41":{"text":"And whereas thou sawest the feet and toes, part of potters’ clay, and part of iron, the kingdom shall be divided; but there shall be in it of the strength of the iron, forasmuch as thou sawest the iron mixed with miry clay.","ref":"Daniel 2:41","synthesized":"And just as you saw that the feet and toes were made partly of fired clay and partly of iron, so this will be a divided kingdom, yet some of the strength of iron will be in it—just as you saw the iron mixed with clay.","sources":{"KJV":{"text":"And whereas thou sawest the feet and toes, part of potters’ clay, and part of iron, the kingdom shall be divided; but there shall be in it of the strength of the iron, forasmuch as thou sawest the iron mixed with miry clay."},"BSB":{"text":"And just as you saw that the feet and toes were made partly of fired clay and partly of iron, so this will be a divided kingdom, yet some of the strength of iron will be in it—just as you saw the iron mixed with clay."}},"definableWords":["saw","made","kingdom"],"peopleInVerse":[]},"42":{"text":"And as the toes of the feet were part of iron, and part of clay, so the kingdom shall be partly strong, and partly broken.","ref":"Daniel 2:42","synthesized":"And as the toes of the feet were partly iron and partly clay, so this kingdom will be partly strong and partly brittle.","sources":{"KJV":{"text":"And as the toes of the feet were part of iron, and part of clay, so the kingdom shall be partly strong, and partly broken."},"BSB":{"text":"And as the toes of the feet were partly iron and partly clay, so this kingdom will be partly strong and partly brittle."}},"definableWords":["kingdom","strong"],"peopleInVerse":[]},"43":{"text":"And whereas thou sawest iron mixed with miry clay, they shall mingle themselves with the seed of men: but they shall not cleave one to another, even as iron is not mixed with clay.","ref":"Daniel 2:43","synthesized":"As you saw the iron mixed with clay, so the peoples will mix with one another, but will not hold together any more than iron mixes with clay.","sources":{"KJV":{"text":"And whereas thou sawest iron mixed with miry clay, they shall mingle themselves with the seed of men: but they shall not cleave one to another, even as iron is not mixed with clay."},"BSB":{"text":"As you saw the iron mixed with clay, so the peoples will mix with one another, but will not hold together any more than iron mixes with clay."}},"definableWords":["saw","one"],"peopleInVerse":[]},"44":{"text":"And in the days of these kings shall the God of heaven set up a kingdom, which shall never be destroyed: and the kingdom shall not be left to other people, but it shall break in pieces and consume all these kingdoms, and it shall stand for ever.","ref":"Daniel 2:44","synthesized":"In the days of those kings, the God of heaven will set up a kingdom that will never be destroyed, nor will it be left to another people. It will shatter all these kingdoms and bring them to an end, but will itself stand forever.","sources":{"KJV":{"text":"And in the days of these kings shall the God of heaven set up a kingdom, which shall never be destroyed: and the kingdom shall not be left to other people, but it shall break in pieces and consume all these kingdoms, and it shall stand for ever."},"BSB":{"text":"In the days of those kings, the God of heaven will set up a kingdom that will never be destroyed, nor will it be left to another people. It will shatter all these kingdoms and bring them to an end, but will itself stand forever."}},"definableWords":["days","kings","God","heaven","kingdom","people","stand"],"peopleInVerse":[]},"45":{"text":"Forasmuch as thou sawest that the stone was cut out of the mountain without hands, and that it brake in pieces the iron, the brass, the clay, the silver, and the gold; the great God hath made known to the king what shall come to pass hereafter: and the dream is certain, and the interpretation thereof sure.","ref":"Daniel 2:45","synthesized":"And just as you saw a stone being cut out of the mountain without human hands, and it shattered the iron, bronze, clay, silver, and gold, so the great God has told the king what will happen in the future.  The dream is true, and its interpretation is trustworthy.”","sources":{"KJV":{"text":"Forasmuch as thou sawest that the stone was cut out of the mountain without hands, and that it brake in pieces the iron, the brass, the clay, the silver, and the gold; the great God hath made known to the king what shall come to pass hereafter: and the dream is certain, and the interpretation thereof sure."},"BSB":{"text":"And just as you saw a stone being cut out of the mountain without human hands, and it shattered the iron, bronze, clay, silver, and gold, so the great God has told the king what will happen in the future.  The dream is true, and its interpretation is trustworthy.”"}},"definableWords":["saw","stone","great","God","king"],"peopleInVerse":[]},"46":{"text":"Then the king Nebuchadnezzar fell upon his face, and worshipped Daniel, and commanded that they should offer an oblation and sweet odours unto him.","ref":"Daniel 2:46","synthesized":"At this, King Nebuchadnezzar fell on his face, paid homage to Daniel, and ordered that an offering of incense be presented to him.","sources":{"KJV":{"text":"Then the king Nebuchadnezzar fell upon his face, and worshipped Daniel, and commanded that they should offer an oblation and sweet odours unto him."},"BSB":{"text":"At this, King Nebuchadnezzar fell on his face, paid homage to Daniel, and ordered that an offering of incense be presented to him."}},"definableWords":["King","offering","incense"],"peopleInVerse":["Nebuchadnezzar","Daniel"]},"47":{"text":"The king answered unto Daniel, and said, Of a truth it is, that your God is a God of gods, and a Lord of kings, and a revealer of secrets, seeing thou couldest reveal this secret.","ref":"Daniel 2:47","synthesized":"The king said to Daniel, “Your God is truly the God of gods and Lord of kings, the Revealer of Mysteries, since you were able to reveal this mystery.”","sources":{"KJV":{"text":"The king answered unto Daniel, and said, Of a truth it is, that your God is a God of gods, and a Lord of kings, and a revealer of secrets, seeing thou couldest reveal this secret."},"BSB":{"text":"The king said to Daniel, “Your God is truly the God of gods and Lord of kings, the Revealer of Mysteries, since you were able to reveal this mystery.”"}},"definableWords":["king","God","Lord","kings"],"peopleInVerse":["Daniel"]},"48":{"text":"Then the king made Daniel a great man, and gave him many great gifts, and made him ruler over the whole province of Babylon, and chief of the governors over all the wise men of Babylon.","ref":"Daniel 2:48","synthesized":"Then the king promoted Daniel and gave him many generous gifts. He made him ruler over the entire province of Babylon and chief administrator over all the wise men of Babylon.","sources":{"KJV":{"text":"Then the king made Daniel a great man, and gave him many great gifts, and made him ruler over the whole province of Babylon, and chief of the governors over all the wise men of Babylon."},"BSB":{"text":"Then the king promoted Daniel and gave him many generous gifts. He made him ruler over the entire province of Babylon and chief administrator over all the wise men of Babylon."}},"definableWords":["king","made","ruler","Babylon","men"],"peopleInVerse":["Daniel"]},"49":{"text":"Then Daniel requested of the king, and he set Shadrach, Meshach, and Abednego, over the affairs of the province of Babylon: but Daniel sat in the gate of the king.","ref":"Daniel 2:49","synthesized":"And at Daniel’s request, the king appointed Shadrach, Meshach, and Abednego to manage the province of Babylon, while Daniel remained in the king’s court.","sources":{"KJV":{"text":"Then Daniel requested of the king, and he set Shadrach, Meshach, and Abednego, over the affairs of the province of Babylon: but Daniel sat in the gate of the king."},"BSB":{"text":"And at Daniel’s request, the king appointed Shadrach, Meshach, and Abednego to manage the province of Babylon, while Daniel remained in the king’s court."}},"definableWords":["king","Babylon","King"],"peopleInVerse":["Daniel"]}}},"3":{"chapter":"3","title":"THE FIERY FURNACE","verses":{"1":{"text":"Nebuchadnezzar the king made an image of gold, whose height was threescore cubits, and the breadth thereof six cubits: he set it up in the plain of Dura, in the province of Babylon.","ref":"Daniel 3:1","synthesized":"King Nebuchadnezzar made a golden statue sixty cubits high and six cubits wide, and he set it up on the plain of Dura in the province of Babylon.","sources":{"KJV":{"text":"Nebuchadnezzar the king made an image of gold, whose height was threescore cubits, and the breadth thereof six cubits: he set it up in the plain of Dura, in the province of Babylon."},"BSB":{"text":"King Nebuchadnezzar made a golden statue sixty cubits high and six cubits wide, and he set it up on the plain of Dura in the province of Babylon."}},"definableWords":["King","made","Babylon"],"peopleInVerse":["Nebuchadnezzar"],"kingdomLens":"Shadrach, Meshach, and Abednego refuse to bow to Nebuchadnezzar's gold image. They tell the king: 'Our God whom we serve is able to deliver us... BUT IF NOT, be it known unto thee, O king, that we will not serve thy gods' (Dan 3:17-18). Three Hebrews — 'but if not' faith. Thrown in. A fourth figure appears in the fire 'like the Son of God.' They walk out without even the smell of smoke.","cultural":{"title":"The fiery furnace — but if not","detail":"Christian tradition reads the fourth man as a pre-incarnation appearance of Christ — the same Christ who promises us in Isaiah 43:2 'when thou walkest through the fire, thou shalt not be burned.' The 'but if not' faith is the model: trust without bargain, obey without guarantee of rescue.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"Then Nebuchadnezzar the king sent to gather together the princes, the governors, and the captains, the judges, the treasurers, the counsellors, the sheriffs, and all the rulers of the provinces, to come to the dedication of the image which Nebuchadnezzar the king had set up.","ref":"Daniel 3:2","synthesized":"Then King Nebuchadnezzar sent word to assemble the satraps, prefects, governors, advisers, treasurers, judges, magistrates, and all the other officials of the provinces to attend the dedication of the statue he had set up.","sources":{"KJV":{"text":"Then Nebuchadnezzar the king sent to gather together the princes, the governors, and the captains, the judges, the treasurers, the counsellors, the sheriffs, and all the rulers of the provinces, to come to the dedication of the image which Nebuchadnezzar the king had set up."},"BSB":{"text":"Then King Nebuchadnezzar sent word to assemble the satraps, prefects, governors, advisers, treasurers, judges, magistrates, and all the other officials of the provinces to attend the dedication of the statue he had set up."}},"definableWords":["King","word"],"peopleInVerse":["Nebuchadnezzar"]},"3":{"text":"Then the princes, the governors, and captains, the judges, the treasurers, the counsellors, the sheriffs, and all the rulers of the provinces, were gathered together unto the dedication of the image that Nebuchadnezzar the king had set up; and they stood before the image that Nebuchadnezzar had set up.","ref":"Daniel 3:3","synthesized":"So the satraps, prefects, governors, advisers, treasurers, judges, magistrates, and all the rulers of the provinces assembled for the dedication of the statue that King Nebuchadnezzar had set up, and they stood before it.","sources":{"KJV":{"text":"Then the princes, the governors, and captains, the judges, the treasurers, the counsellors, the sheriffs, and all the rulers of the provinces, were gathered together unto the dedication of the image that Nebuchadnezzar the king had set up; and they stood before the image that Nebuchadnezzar had set up."},"BSB":{"text":"So the satraps, prefects, governors, advisers, treasurers, judges, magistrates, and all the rulers of the provinces assembled for the dedication of the statue that King Nebuchadnezzar had set up, and they stood before it."}},"definableWords":["King"],"peopleInVerse":["Nebuchadnezzar"]},"4":{"text":"Then an herald cried aloud, To you it is commanded, O people, nations, and languages,","ref":"Daniel 3:4","synthesized":"Then the herald loudly proclaimed, “O people of every nation and language, this is what you are commanded:","sources":{"KJV":{"text":"Then an herald cried aloud, To you it is commanded, O people, nations, and languages,"},"BSB":{"text":"Then the herald loudly proclaimed, “O people of every nation and language, this is what you are commanded:"}},"definableWords":["people","nation"],"peopleInVerse":[]},"5":{"text":"That at what time ye hear the sound of the cornet, flute, harp, sackbut, psaltery, dulcimer, and all kinds of musick, ye fall down and worship the golden image that Nebuchadnezzar the king hath set up:","ref":"Daniel 3:5","synthesized":"As soon as you hear the sound of the horn, flute, zither, lyre, harp, pipes, and all kinds of music, you must fall down and worship the golden statue that King Nebuchadnezzar has set up.","sources":{"KJV":{"text":"That at what time ye hear the sound of the cornet, flute, harp, sackbut, psaltery, dulcimer, and all kinds of musick, ye fall down and worship the golden image that Nebuchadnezzar the king hath set up:"},"BSB":{"text":"As soon as you hear the sound of the horn, flute, zither, lyre, harp, pipes, and all kinds of music, you must fall down and worship the golden statue that King Nebuchadnezzar has set up."}},"definableWords":["hear","worship","King"],"peopleInVerse":["Nebuchadnezzar"]},"6":{"text":"And whoso falleth not down and worshippeth shall the same hour be cast into the midst of a burning fiery furnace.","ref":"Daniel 3:6","synthesized":"And whoever does not fall down and worship will immediately be thrown into the blazing fiery furnace.”","sources":{"KJV":{"text":"And whoso falleth not down and worshippeth shall the same hour be cast into the midst of a burning fiery furnace."},"BSB":{"text":"And whoever does not fall down and worship will immediately be thrown into the blazing fiery furnace.”"}},"definableWords":["worship"],"peopleInVerse":[]},"7":{"text":"Therefore at that time, when all the people heard the sound of the cornet, flute, harp, sackbut, psaltery, and all kinds of musick, all the people, the nations, and the languages, fell down and worshipped the golden image that Nebuchadnezzar the king had set up.","ref":"Daniel 3:7","synthesized":"Therefore, as soon as all the people heard the sound of the horn, flute, zither, lyre, harp, and all kinds of music, the people of every nation and language would fall down and worship the golden statue that King Nebuchadnezzar had set up.","sources":{"KJV":{"text":"Therefore at that time, when all the people heard the sound of the cornet, flute, harp, sackbut, psaltery, and all kinds of musick, all the people, the nations, and the languages, fell down and worshipped the golden image that Nebuchadnezzar the king had set up."},"BSB":{"text":"Therefore, as soon as all the people heard the sound of the horn, flute, zither, lyre, harp, and all kinds of music, the people of every nation and language would fall down and worship the golden statue that King Nebuchadnezzar had set up."}},"definableWords":["people","nation","worship","King"],"peopleInVerse":["Nebuchadnezzar"]},"8":{"text":"Wherefore at that time certain Chaldeans came near, and accused the Jews.","ref":"Daniel 3:8","synthesized":"At this time some astrologers came forward and maliciously accused the Jews,","sources":{"KJV":{"text":"Wherefore at that time certain Chaldeans came near, and accused the Jews."},"BSB":{"text":"At this time some astrologers came forward and maliciously accused the Jews,"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"They spake and said to the king Nebuchadnezzar, O king, live for ever.","ref":"Daniel 3:9","synthesized":"saying to King Nebuchadnezzar, “O king, may you live forever!","sources":{"KJV":{"text":"They spake and said to the king Nebuchadnezzar, O king, live for ever."},"BSB":{"text":"saying to King Nebuchadnezzar, “O king, may you live forever!"}},"definableWords":["King","king","live"],"peopleInVerse":["Nebuchadnezzar"]},"10":{"text":"Thou, O king, hast made a decree, that every man that shall hear the sound of the cornet, flute, harp, sackbut, psaltery, and dulcimer, and all kinds of musick, shall fall down and worship the golden image:","ref":"Daniel 3:10","synthesized":"You, O king, have issued a decree that everyone who hears the sound of the horn, flute, zither, lyre, harp, pipes, and all kinds of music must fall down and worship the golden statue,","sources":{"KJV":{"text":"Thou, O king, hast made a decree, that every man that shall hear the sound of the cornet, flute, harp, sackbut, psaltery, and dulcimer, and all kinds of musick, shall fall down and worship the golden image:"},"BSB":{"text":"You, O king, have issued a decree that everyone who hears the sound of the horn, flute, zither, lyre, harp, pipes, and all kinds of music must fall down and worship the golden statue,"}},"definableWords":["king","worship"],"peopleInVerse":[]},"11":{"text":"And whoso falleth not down and worshippeth, that he should be cast into the midst of a burning fiery furnace.","ref":"Daniel 3:11","synthesized":"and that whoever does not fall down and worship will be thrown into the blazing fiery furnace.","sources":{"KJV":{"text":"And whoso falleth not down and worshippeth, that he should be cast into the midst of a burning fiery furnace."},"BSB":{"text":"and that whoever does not fall down and worship will be thrown into the blazing fiery furnace."}},"definableWords":["worship"],"peopleInVerse":[]},"12":{"text":"There are certain Jews whom thou hast set over the affairs of the province of Babylon, Shadrach, Meshach, and Abednego; these men, O king, have not regarded thee: they serve not thy gods, nor worship the golden image which thou hast set up.","ref":"Daniel 3:12","synthesized":"But there are some Jews you have appointed to manage the province of Babylon—Shadrach, Meshach, and Abednego—who have ignored you, O king, and have refused to serve your gods or worship the golden statue you have set up.”","sources":{"KJV":{"text":"There are certain Jews whom thou hast set over the affairs of the province of Babylon, Shadrach, Meshach, and Abednego; these men, O king, have not regarded thee: they serve not thy gods, nor worship the golden image which thou hast set up."},"BSB":{"text":"But there are some Jews you have appointed to manage the province of Babylon—Shadrach, Meshach, and Abednego—who have ignored you, O king, and have refused to serve your gods or worship the golden statue you have set up.”"}},"definableWords":["Babylon","king","or","worship"],"peopleInVerse":[]},"13":{"text":"Then Nebuchadnezzar in his rage and fury commanded to bring Shadrach, Meshach, and Abednego. Then they brought these men before the king.","ref":"Daniel 3:13","synthesized":"Then Nebuchadnezzar, furious with rage, summoned Shadrach, Meshach, and Abednego. So these men were brought before the king,","sources":{"KJV":{"text":"Then Nebuchadnezzar in his rage and fury commanded to bring Shadrach, Meshach, and Abednego. Then they brought these men before the king."},"BSB":{"text":"Then Nebuchadnezzar, furious with rage, summoned Shadrach, Meshach, and Abednego. So these men were brought before the king,"}},"definableWords":["men","king"],"peopleInVerse":["Nebuchadnezzar"]},"14":{"text":"Nebuchadnezzar spake and said unto them, Is it true, O Shadrach, Meshach, and Abednego, do not ye serve my gods, nor worship the golden image which I have set up?","ref":"Daniel 3:14","synthesized":"and Nebuchadnezzar said to them, “Shadrach, Meshach, and Abednego, is it true that you do not serve my gods or worship the golden statue I have set up?","sources":{"KJV":{"text":"Nebuchadnezzar spake and said unto them, Is it true, O Shadrach, Meshach, and Abednego, do not ye serve my gods, nor worship the golden image which I have set up?"},"BSB":{"text":"and Nebuchadnezzar said to them, “Shadrach, Meshach, and Abednego, is it true that you do not serve my gods or worship the golden statue I have set up?"}},"definableWords":["or","worship"],"peopleInVerse":["Nebuchadnezzar"]},"15":{"text":"Now if ye be ready that at what time ye hear the sound of the cornet, flute, harp, sackbut, psaltery, and dulcimer, and all kinds of musick, ye fall down and worship the image which I have made; well: but if ye worship not, ye shall be cast the same hour into the midst of a burning fiery furnace; and who is that God that shall deliver you out of my hands?","ref":"Daniel 3:15","synthesized":"Now, if you are ready, as soon as you hear the sound of the horn, flute, zither, lyre, harp, pipes, and all kinds of music, you must fall down and worship the statue I have made. But if you refuse to worship, you will be thrown at once into the blazing fiery furnace. Then what god will be able to deliver you from my hands?”","sources":{"KJV":{"text":"Now if ye be ready that at what time ye hear the sound of the cornet, flute, harp, sackbut, psaltery, and dulcimer, and all kinds of musick, ye fall down and worship the image which I have made; well: but if ye worship not, ye shall be cast the same hour into the midst of a burning fiery furnace; and who is that God that shall deliver you out of my hands?"},"BSB":{"text":"Now, if you are ready, as soon as you hear the sound of the horn, flute, zither, lyre, harp, pipes, and all kinds of music, you must fall down and worship the statue I have made. But if you refuse to worship, you will be thrown at once into the blazing fiery furnace. Then what god will be able to deliver you from my hands?”"}},"definableWords":["hear","worship","made","God","deliver"],"peopleInVerse":[]},"16":{"text":"Shadrach, Meshach, and Abednego, answered and said to the king, O Nebuchadnezzar, we are not careful to answer thee in this matter.","ref":"Daniel 3:16","synthesized":"Shadrach, Meshach, and Abednego replied to the king, “O Nebuchadnezzar, we have no need to answer you in this matter.","sources":{"KJV":{"text":"Shadrach, Meshach, and Abednego, answered and said to the king, O Nebuchadnezzar, we are not careful to answer thee in this matter."},"BSB":{"text":"Shadrach, Meshach, and Abednego replied to the king, “O Nebuchadnezzar, we have no need to answer you in this matter."}},"definableWords":["king"],"peopleInVerse":["Nebuchadnezzar"]},"17":{"text":"If it be so, our God whom we serve is able to deliver us from the burning fiery furnace, and he will deliver us out of thine hand, O king.","ref":"Daniel 3:17","synthesized":"If the God whom we serve exists, then He is able to deliver us from the blazing fiery furnace and from your hand, O king.","sources":{"KJV":{"text":"If it be so, our God whom we serve is able to deliver us from the burning fiery furnace, and he will deliver us out of thine hand, O king."},"BSB":{"text":"If the God whom we serve exists, then He is able to deliver us from the blazing fiery furnace and from your hand, O king."}},"definableWords":["God","deliver","king"],"peopleInVerse":[]},"18":{"text":"But if not, be it known unto thee, O king, that we will not serve thy gods, nor worship the golden image which thou hast set up.","ref":"Daniel 3:18","synthesized":"But even if He does not, let it be known to you, O king, that we will not serve your gods or worship the golden statue you have set up.”","sources":{"KJV":{"text":"But if not, be it known unto thee, O king, that we will not serve thy gods, nor worship the golden image which thou hast set up."},"BSB":{"text":"But even if He does not, let it be known to you, O king, that we will not serve your gods or worship the golden statue you have set up.”"}},"definableWords":["king","or","worship"],"peopleInVerse":[]},"19":{"text":"Then was Nebuchadnezzar full of fury, and the form of his visage was changed against Shadrach, Meshach, and Abednego: therefore he spake, and commanded that they should heat the furnace one seven times more than it was wont to be heated.","ref":"Daniel 3:19","synthesized":"At this, Nebuchadnezzar was filled with rage, and the expression on his face changed toward Shadrach, Meshach, and Abednego. He gave orders to heat the furnace seven times hotter than usual,","sources":{"KJV":{"text":"Then was Nebuchadnezzar full of fury, and the form of his visage was changed against Shadrach, Meshach, and Abednego: therefore he spake, and commanded that they should heat the furnace one seven times more than it was wont to be heated."},"BSB":{"text":"At this, Nebuchadnezzar was filled with rage, and the expression on his face changed toward Shadrach, Meshach, and Abednego. He gave orders to heat the furnace seven times hotter than usual,"}},"definableWords":[],"peopleInVerse":["Nebuchadnezzar"]},"20":{"text":"And he commanded the most mighty men that were in his army to bind Shadrach, Meshach, and Abednego, and to cast them into the burning fiery furnace.","ref":"Daniel 3:20","synthesized":"and he commanded some mighty men of valor in his army to tie up Shadrach, Meshach, and Abednego and throw them into the blazing fiery furnace.","sources":{"KJV":{"text":"And he commanded the most mighty men that were in his army to bind Shadrach, Meshach, and Abednego, and to cast them into the burning fiery furnace."},"BSB":{"text":"and he commanded some mighty men of valor in his army to tie up Shadrach, Meshach, and Abednego and throw them into the blazing fiery furnace."}},"definableWords":["mighty","men"],"peopleInVerse":[]},"21":{"text":"Then these men were bound in their coats, their hosen, and their hats, and their other garments, and were cast into the midst of the burning fiery furnace.","ref":"Daniel 3:21","synthesized":"So they were tied up, wearing robes, trousers, turbans, and other clothes, and they were thrown into the blazing fiery furnace.","sources":{"KJV":{"text":"Then these men were bound in their coats, their hosen, and their hats, and their other garments, and were cast into the midst of the burning fiery furnace."},"BSB":{"text":"So they were tied up, wearing robes, trousers, turbans, and other clothes, and they were thrown into the blazing fiery furnace."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Therefore because the king’s commandment was urgent, and the furnace exceeding hot, the flame of the fire slew those men that took up Shadrach, Meshach, and Abednego.","ref":"Daniel 3:22","synthesized":"The king’s command was so urgent and the furnace so hot that the fiery flames killed the men who carried up Shadrach, Meshach, and Abednego.","sources":{"KJV":{"text":"Therefore because the king’s commandment was urgent, and the furnace exceeding hot, the flame of the fire slew those men that took up Shadrach, Meshach, and Abednego."},"BSB":{"text":"The king’s command was so urgent and the furnace so hot that the fiery flames killed the men who carried up Shadrach, Meshach, and Abednego."}},"definableWords":["king","men"],"peopleInVerse":[]},"23":{"text":"And these three men, Shadrach, Meshach, and Abednego, fell down bound into the midst of the burning fiery furnace.","ref":"Daniel 3:23","synthesized":"And these three men, Shadrach, Meshach, and Abednego, firmly bound, fell into the blazing fiery furnace.","sources":{"KJV":{"text":"And these three men, Shadrach, Meshach, and Abednego, fell down bound into the midst of the burning fiery furnace."},"BSB":{"text":"And these three men, Shadrach, Meshach, and Abednego, firmly bound, fell into the blazing fiery furnace."}},"definableWords":["men"],"peopleInVerse":[]},"24":{"text":"Then Nebuchadnezzar the king was astonied, and rose up in haste, and spake, and said unto his counsellors, Did not we cast three men bound into the midst of the fire? They answered and said unto the king, True, O king.","ref":"Daniel 3:24","synthesized":"Suddenly King Nebuchadnezzar jumped up in amazement and asked his advisers, “Did we not throw three men, firmly bound, into the fire?”  “Certainly, O king,” they replied.","sources":{"KJV":{"text":"Then Nebuchadnezzar the king was astonied, and rose up in haste, and spake, and said unto his counsellors, Did not we cast three men bound into the midst of the fire? They answered and said unto the king, True, O king."},"BSB":{"text":"Suddenly King Nebuchadnezzar jumped up in amazement and asked his advisers, “Did we not throw three men, firmly bound, into the fire?”  “Certainly, O king,” they replied."}},"definableWords":["King","men","king"],"peopleInVerse":["Nebuchadnezzar"]},"25":{"text":"He answered and said, Lo, I see four men loose, walking in the midst of the fire, and they have no hurt; and the form of the fourth is like the Son of God.","ref":"Daniel 3:25","synthesized":"“Look!” he exclaimed. “I see four men, unbound and unharmed, walking around in the fire—and the fourth looks like a son of the gods!”","sources":{"KJV":{"text":"He answered and said, Lo, I see four men loose, walking in the midst of the fire, and they have no hurt; and the form of the fourth is like the Son of God."},"BSB":{"text":"“Look!” he exclaimed. “I see four men, unbound and unharmed, walking around in the fire—and the fourth looks like a son of the gods!”"}},"definableWords":["see","men","son"],"peopleInVerse":[]},"26":{"text":"Then Nebuchadnezzar came near to the mouth of the burning fiery furnace, and spake, and said, Shadrach, Meshach, and Abednego, ye servants of the most high God, come forth, and come hither. Then Shadrach, Meshach, and Abednego, came forth of the midst of the fire.","ref":"Daniel 3:26","synthesized":"Then Nebuchadnezzar approached the door of the blazing fiery furnace and called out, “Shadrach, Meshach, and Abednego, servants of the Most High God, come out!”  So Shadrach, Meshach, and Abednego came out of the fire,","sources":{"KJV":{"text":"Then Nebuchadnezzar came near to the mouth of the burning fiery furnace, and spake, and said, Shadrach, Meshach, and Abednego, ye servants of the most high God, come forth, and come hither. Then Shadrach, Meshach, and Abednego, came forth of the midst of the fire."},"BSB":{"text":"Then Nebuchadnezzar approached the door of the blazing fiery furnace and called out, “Shadrach, Meshach, and Abednego, servants of the Most High God, come out!”  So Shadrach, Meshach, and Abednego came out of the fire,"}},"definableWords":["servants","God"],"peopleInVerse":["Nebuchadnezzar"]},"27":{"text":"And the princes, governors, and captains, and the king’s counsellors, being gathered together, saw these men, upon whose bodies the fire had no power, nor was an hair of their head singed, neither were their coats changed, nor the smell of fire had passed on them.","ref":"Daniel 3:27","synthesized":"and when the satraps, prefects, governors, and royal advisers had gathered around, they saw that the fire had no effect on the bodies of these men. Not a hair of their heads was singed, their robes were unaffected, and there was no smell of fire on them.","sources":{"KJV":{"text":"And the princes, governors, and captains, and the king’s counsellors, being gathered together, saw these men, upon whose bodies the fire had no power, nor was an hair of their head singed, neither were their coats changed, nor the smell of fire had passed on them."},"BSB":{"text":"and when the satraps, prefects, governors, and royal advisers had gathered around, they saw that the fire had no effect on the bodies of these men. Not a hair of their heads was singed, their robes were unaffected, and there was no smell of fire on them."}},"definableWords":["saw","men"],"peopleInVerse":[]},"28":{"text":"Then Nebuchadnezzar spake, and said, Blessed be the God of Shadrach, Meshach, and Abednego, who hath sent his angel, and delivered his servants that trusted in him, and have changed the king’s word, and yielded their bodies, that they might not serve nor worship any god, except their own God.","ref":"Daniel 3:28","synthesized":"Nebuchadnezzar declared, “Blessed be the God of Shadrach, Meshach, and Abednego, who has sent His angel and delivered His servants who trusted in Him. They violated the king’s command and risked their lives rather than serve or worship any god except their own God.","sources":{"KJV":{"text":"Then Nebuchadnezzar spake, and said, Blessed be the God of Shadrach, Meshach, and Abednego, who hath sent his angel, and delivered his servants that trusted in him, and have changed the king’s word, and yielded their bodies, that they might not serve nor worship any god, except their own God."},"BSB":{"text":"Nebuchadnezzar declared, “Blessed be the God of Shadrach, Meshach, and Abednego, who has sent His angel and delivered His servants who trusted in Him. They violated the king’s command and risked their lives rather than serve or worship any god except their own God."}},"definableWords":["blessed","God","angel","servants","king","or","worship"],"peopleInVerse":["Nebuchadnezzar"]},"29":{"text":"Therefore I make a decree, That every people, nation, and language, which speak any thing amiss against the God of Shadrach, Meshach, and Abednego, shall be cut in pieces, and their houses shall be made a dunghill: because there is no other God that can deliver after this sort.","ref":"Daniel 3:29","synthesized":"Therefore I decree that the people of any nation or language who say anything offensive against the God of Shadrach, Meshach, and Abednego will be cut into pieces and their houses reduced to rubble. For there is no other god who can deliver in this way.”","sources":{"KJV":{"text":"Therefore I make a decree, That every people, nation, and language, which speak any thing amiss against the God of Shadrach, Meshach, and Abednego, shall be cut in pieces, and their houses shall be made a dunghill: because there is no other God that can deliver after this sort."},"BSB":{"text":"Therefore I decree that the people of any nation or language who say anything offensive against the God of Shadrach, Meshach, and Abednego will be cut into pieces and their houses reduced to rubble. For there is no other god who can deliver in this way.”"}},"definableWords":["people","nation","or","God","deliver","way"],"peopleInVerse":[]},"30":{"text":"Then the king promoted Shadrach, Meshach, and Abednego, in the province of Babylon.","ref":"Daniel 3:30","synthesized":"Then the king promoted Shadrach, Meshach, and Abednego in the province of Babylon.","sources":{"KJV":{"text":"Then the king promoted Shadrach, Meshach, and Abednego, in the province of Babylon."},"BSB":{"text":"Then the king promoted Shadrach, Meshach, and Abednego in the province of Babylon."}},"definableWords":["king","Babylon"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"NEBUCHADNEZZAR'S MADNESS","verses":{"1":{"text":"Nebuchadnezzar the king, unto all people, nations, and languages, that dwell in all the earth; Peace be multiplied unto you.","ref":"Daniel 4:1","synthesized":"King Nebuchadnezzar,  To the people of every nation and language who dwell in all the earth:  May your prosperity be multiplied.","sources":{"KJV":{"text":"Nebuchadnezzar the king, unto all people, nations, and languages, that dwell in all the earth; Peace be multiplied unto you."},"BSB":{"text":"King Nebuchadnezzar,  To the people of every nation and language who dwell in all the earth:  May your prosperity be multiplied."}},"definableWords":["King","people","nation","earth"],"peopleInVerse":["Nebuchadnezzar"]},"2":{"text":"I thought it good to shew the signs and wonders that the high God hath wrought toward me.","ref":"Daniel 4:2","synthesized":"I am pleased to declare the signs and wonders that the Most High God has performed for me.","sources":{"KJV":{"text":"I thought it good to shew the signs and wonders that the high God hath wrought toward me."},"BSB":{"text":"I am pleased to declare the signs and wonders that the Most High God has performed for me."}},"definableWords":["God"],"peopleInVerse":[]},"3":{"text":"How great are his signs! and how mighty are his wonders! his kingdom is an everlasting kingdom, and his dominion is from generation to generation.","ref":"Daniel 4:3","synthesized":"How great are His signs, how mighty His wonders! His kingdom is an eternal kingdom; His dominion endures from generation to generation.","sources":{"KJV":{"text":"How great are his signs! and how mighty are his wonders! his kingdom is an everlasting kingdom, and his dominion is from generation to generation."},"BSB":{"text":"How great are His signs, how mighty His wonders! His kingdom is an eternal kingdom; His dominion endures from generation to generation."}},"definableWords":["great","mighty","kingdom","eternal","dominion"],"peopleInVerse":[]},"4":{"text":"I Nebuchadnezzar was at rest in mine house, and flourishing in my palace:","ref":"Daniel 4:4","synthesized":"I, Nebuchadnezzar, was at ease in my house and flourishing in my palace.","sources":{"KJV":{"text":"I Nebuchadnezzar was at rest in mine house, and flourishing in my palace:"},"BSB":{"text":"I, Nebuchadnezzar, was at ease in my house and flourishing in my palace."}},"definableWords":["house"],"peopleInVerse":["Nebuchadnezzar"]},"5":{"text":"I saw a dream which made me afraid, and the thoughts upon my bed and the visions of my head troubled me.","ref":"Daniel 4:5","synthesized":"I had a dream, and it frightened me; while in my bed, the images and visions in my mind alarmed me.","sources":{"KJV":{"text":"I saw a dream which made me afraid, and the thoughts upon my bed and the visions of my head troubled me."},"BSB":{"text":"I had a dream, and it frightened me; while in my bed, the images and visions in my mind alarmed me."}},"definableWords":["mind"],"peopleInVerse":[]},"6":{"text":"Therefore made I a decree to bring in all the wise men of Babylon before me, that they might make known unto me the interpretation of the dream.","ref":"Daniel 4:6","synthesized":"So I issued a decree that all the wise men of Babylon be brought before me to interpret the dream for me.","sources":{"KJV":{"text":"Therefore made I a decree to bring in all the wise men of Babylon before me, that they might make known unto me the interpretation of the dream."},"BSB":{"text":"So I issued a decree that all the wise men of Babylon be brought before me to interpret the dream for me."}},"definableWords":["men","Babylon"],"peopleInVerse":[]},"7":{"text":"Then came in the magicians, the astrologers, the Chaldeans, and the soothsayers: and I told the dream before them; but they did not make known unto me the interpretation thereof.","ref":"Daniel 4:7","synthesized":"When the magicians, enchanters, astrologers, and diviners came in, I told them the dream, and they could not interpret it for me.","sources":{"KJV":{"text":"Then came in the magicians, the astrologers, the Chaldeans, and the soothsayers: and I told the dream before them; but they did not make known unto me the interpretation thereof."},"BSB":{"text":"When the magicians, enchanters, astrologers, and diviners came in, I told them the dream, and they could not interpret it for me."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"But at the last Daniel came in before me, whose name was Belteshazzar, according to the name of my God, and in whom is the spirit of the holy gods: and before him I told the dream, saying,","ref":"Daniel 4:8","synthesized":"But at last, into my presence came Daniel (whose name is Belteshazzar after the name of my god, and in whom is the spirit of the holy gods). And I told him the dream:","sources":{"KJV":{"text":"But at the last Daniel came in before me, whose name was Belteshazzar, according to the name of my God, and in whom is the spirit of the holy gods: and before him I told the dream, saying,"},"BSB":{"text":"But at last, into my presence came Daniel (whose name is Belteshazzar after the name of my god, and in whom is the spirit of the holy gods). And I told him the dream:"}},"definableWords":["name","God","spirit","holy"],"peopleInVerse":["Daniel"]},"9":{"text":"O Belteshazzar, master of the magicians, because I know that the spirit of the holy gods is in thee, and no secret troubleth thee, tell me the visions of my dream that I have seen, and the interpretation thereof.","ref":"Daniel 4:9","synthesized":"“O Belteshazzar, chief of the magicians, I know that the spirit of the holy gods is in you and that no mystery baffles you. So explain to me the visions I saw in my dream, and their interpretation.","sources":{"KJV":{"text":"O Belteshazzar, master of the magicians, because I know that the spirit of the holy gods is in thee, and no secret troubleth thee, tell me the visions of my dream that I have seen, and the interpretation thereof."},"BSB":{"text":"“O Belteshazzar, chief of the magicians, I know that the spirit of the holy gods is in you and that no mystery baffles you. So explain to me the visions I saw in my dream, and their interpretation."}},"definableWords":["spirit","holy","saw"],"peopleInVerse":[]},"10":{"text":"Thus were the visions of mine head in my bed; I saw, and behold a tree in the midst of the earth, and the height thereof was great.","ref":"Daniel 4:10","synthesized":"In these visions of my mind as I was lying in bed, I saw this come to pass:  There was a tree in the midst of the land, and its height was great.","sources":{"KJV":{"text":"Thus were the visions of mine head in my bed; I saw, and behold a tree in the midst of the earth, and the height thereof was great."},"BSB":{"text":"In these visions of my mind as I was lying in bed, I saw this come to pass:  There was a tree in the midst of the land, and its height was great."}},"definableWords":["mind","saw","tree","land","great"],"peopleInVerse":[]},"11":{"text":"The tree grew, and was strong, and the height thereof reached unto heaven, and the sight thereof to the end of all the earth:","ref":"Daniel 4:11","synthesized":"The tree grew large and strong; its top reached the sky, and it was visible to the ends of the earth.","sources":{"KJV":{"text":"The tree grew, and was strong, and the height thereof reached unto heaven, and the sight thereof to the end of all the earth:"},"BSB":{"text":"The tree grew large and strong; its top reached the sky, and it was visible to the ends of the earth."}},"definableWords":["tree","strong","earth"],"peopleInVerse":[]},"12":{"text":"The leaves thereof were fair, and the fruit thereof much, and in it was meat for all: the beasts of the field had shadow under it, and the fowls of the heaven dwelt in the boughs thereof, and all flesh was fed of it.","ref":"Daniel 4:12","synthesized":"Its leaves were beautiful, its fruit was abundant, and upon it was food for all. Under it the beasts of the field found shelter, in its branches the birds of the air nested, and from it every creature was fed.","sources":{"KJV":{"text":"The leaves thereof were fair, and the fruit thereof much, and in it was meat for all: the beasts of the field had shadow under it, and the fowls of the heaven dwelt in the boughs thereof, and all flesh was fed of it."},"BSB":{"text":"Its leaves were beautiful, its fruit was abundant, and upon it was food for all. Under it the beasts of the field found shelter, in its branches the birds of the air nested, and from it every creature was fed."}},"definableWords":["field","birds"],"peopleInVerse":[]},"13":{"text":"I saw in the visions of my head upon my bed, and, behold, a watcher and an holy one came down from heaven;","ref":"Daniel 4:13","synthesized":"As I lay on my bed, I also saw in the visions of my mind a watcher, a holy one, coming down from heaven.","sources":{"KJV":{"text":"I saw in the visions of my head upon my bed, and, behold, a watcher and an holy one came down from heaven;"},"BSB":{"text":"As I lay on my bed, I also saw in the visions of my mind a watcher, a holy one, coming down from heaven."}},"definableWords":["saw","mind","holy","one","heaven"],"peopleInVerse":[]},"14":{"text":"He cried aloud, and said thus, Hew down the tree, and cut off his branches, shake off his leaves, and scatter his fruit: let the beasts get away from under it, and the fowls from his branches:","ref":"Daniel 4:14","synthesized":"He called out in a loud voice:  ‘Cut down the tree and chop off its branches; strip off its leaves and scatter its fruit. Let the beasts flee from under it, and the birds from its branches.","sources":{"KJV":{"text":"He cried aloud, and said thus, Hew down the tree, and cut off his branches, shake off his leaves, and scatter his fruit: let the beasts get away from under it, and the fowls from his branches:"},"BSB":{"text":"He called out in a loud voice:  ‘Cut down the tree and chop off its branches; strip off its leaves and scatter its fruit. Let the beasts flee from under it, and the birds from its branches."}},"definableWords":["voice","tree","birds"],"peopleInVerse":[]},"15":{"text":"Nevertheless leave the stump of his roots in the earth, even with a band of iron and brass, in the tender grass of the field; and let it be wet with the dew of heaven, and let his portion be with the beasts in the grass of the earth:","ref":"Daniel 4:15","synthesized":"But leave the stump with its roots in the ground, and a band of iron and bronze around it, in the tender grass of the field.   Let him be drenched with the dew of heaven and graze with the beasts on the grass of the earth.","sources":{"KJV":{"text":"Nevertheless leave the stump of his roots in the earth, even with a band of iron and brass, in the tender grass of the field; and let it be wet with the dew of heaven, and let his portion be with the beasts in the grass of the earth:"},"BSB":{"text":"But leave the stump with its roots in the ground, and a band of iron and bronze around it, in the tender grass of the field.   Let him be drenched with the dew of heaven and graze with the beasts on the grass of the earth."}},"definableWords":["ground","field","heaven","earth"],"peopleInVerse":[]},"16":{"text":"Let his heart be changed from man’s, and let a beast’s heart be given unto him; and let seven times pass over him.","ref":"Daniel 4:16","synthesized":"Let his mind be changed from that of a man, and let him be given the mind of a beast till seven times pass him by.","sources":{"KJV":{"text":"Let his heart be changed from man’s, and let a beast’s heart be given unto him; and let seven times pass over him."},"BSB":{"text":"Let his mind be changed from that of a man, and let him be given the mind of a beast till seven times pass him by."}},"definableWords":["mind","man","till"],"peopleInVerse":[]},"17":{"text":"This matter is by the decree of the watchers, and the demand by the word of the holy ones: to the intent that the living may know that the most High ruleth in the kingdom of men, and giveth it to whomsoever he will, and setteth up over it the basest of men.","ref":"Daniel 4:17","synthesized":"This decision is the decree of the watchers, the verdict declared by the holy ones, so that the living will know that the Most High rules over the kingdom of mankind and gives it to whom He wishes, setting over it the lowliest of men.’","sources":{"KJV":{"text":"This matter is by the decree of the watchers, and the demand by the word of the holy ones: to the intent that the living may know that the most High ruleth in the kingdom of men, and giveth it to whomsoever he will, and setteth up over it the basest of men."},"BSB":{"text":"This decision is the decree of the watchers, the verdict declared by the holy ones, so that the living will know that the Most High rules over the kingdom of mankind and gives it to whom He wishes, setting over it the lowliest of men.’"}},"definableWords":["holy","living","kingdom","men"],"peopleInVerse":[]},"18":{"text":"This dream I king Nebuchadnezzar have seen. Now thou, O Belteshazzar, declare the interpretation thereof, forasmuch as all the wise men of my kingdom are not able to make known unto me the interpretation: but thou art able; for the spirit of the holy gods is in thee.","ref":"Daniel 4:18","synthesized":"This is the dream that I, King Nebuchadnezzar, saw. Now, Belteshazzar, tell me the interpretation, because none of the wise men of my kingdom can interpret it for me. But you are able, because the spirit of the holy gods is in you.”","sources":{"KJV":{"text":"This dream I king Nebuchadnezzar have seen. Now thou, O Belteshazzar, declare the interpretation thereof, forasmuch as all the wise men of my kingdom are not able to make known unto me the interpretation: but thou art able; for the spirit of the holy gods is in thee."},"BSB":{"text":"This is the dream that I, King Nebuchadnezzar, saw. Now, Belteshazzar, tell me the interpretation, because none of the wise men of my kingdom can interpret it for me. But you are able, because the spirit of the holy gods is in you.”"}},"definableWords":["King","saw","men","kingdom","spirit","holy"],"peopleInVerse":["Nebuchadnezzar"]},"19":{"text":"Then Daniel, whose name was Belteshazzar, was astonied for one hour, and his thoughts troubled him. The king spake, and said, Belteshazzar, let not the dream, or the interpretation thereof, trouble thee. Belteshazzar answered and said, My lord, the dream be to them that hate thee, and the interpretation thereof to thine enemies.","ref":"Daniel 4:19","synthesized":"For a time, Daniel, who was also known as Belteshazzar, was perplexed, and his thoughts alarmed him.  So the king said, “Belteshazzar, do not let the dream or its interpretation alarm you.”  “My lord,” replied Belteshazzar, “may the dream apply to those who hate you, and its interpretation to your enemies!","sources":{"KJV":{"text":"Then Daniel, whose name was Belteshazzar, was astonied for one hour, and his thoughts troubled him. The king spake, and said, Belteshazzar, let not the dream, or the interpretation thereof, trouble thee. Belteshazzar answered and said, My lord, the dream be to them that hate thee, and the interpretation thereof to thine enemies."},"BSB":{"text":"For a time, Daniel, who was also known as Belteshazzar, was perplexed, and his thoughts alarmed him.  So the king said, “Belteshazzar, do not let the dream or its interpretation alarm you.”  “My lord,” replied Belteshazzar, “may the dream apply to those who hate you, and its interpretation to your enemies!"}},"definableWords":["king","or","Lord"],"peopleInVerse":["Daniel"]},"20":{"text":"The tree that thou sawest, which grew, and was strong, whose height reached unto the heaven, and the sight thereof to all the earth;","ref":"Daniel 4:20","synthesized":"The tree you saw that grew large and strong, whose top reached the sky and was visible to all the earth,","sources":{"KJV":{"text":"The tree that thou sawest, which grew, and was strong, whose height reached unto the heaven, and the sight thereof to all the earth;"},"BSB":{"text":"The tree you saw that grew large and strong, whose top reached the sky and was visible to all the earth,"}},"definableWords":["tree","saw","strong","earth"],"peopleInVerse":[]},"21":{"text":"Whose leaves were fair, and the fruit thereof much, and in it was meat for all; under which the beasts of the field dwelt, and upon whose branches the fowls of the heaven had their habitation:","ref":"Daniel 4:21","synthesized":"whose foliage was beautiful and whose fruit was abundant, providing food for all, under which the beasts of the field lived, and in whose branches the birds of the air nested—","sources":{"KJV":{"text":"Whose leaves were fair, and the fruit thereof much, and in it was meat for all; under which the beasts of the field dwelt, and upon whose branches the fowls of the heaven had their habitation:"},"BSB":{"text":"whose foliage was beautiful and whose fruit was abundant, providing food for all, under which the beasts of the field lived, and in whose branches the birds of the air nested—"}},"definableWords":["field","birds"],"peopleInVerse":[]},"22":{"text":"It is thou, O king, that art grown and become strong: for thy greatness is grown, and reacheth unto heaven, and thy dominion to the end of the earth.","ref":"Daniel 4:22","synthesized":"you, O king, are that tree! For you have become great and strong; your greatness has grown to reach the sky, and your dominion extends to the ends of the earth.","sources":{"KJV":{"text":"It is thou, O king, that art grown and become strong: for thy greatness is grown, and reacheth unto heaven, and thy dominion to the end of the earth."},"BSB":{"text":"you, O king, are that tree! For you have become great and strong; your greatness has grown to reach the sky, and your dominion extends to the ends of the earth."}},"definableWords":["king","tree","great","strong","dominion","earth"],"peopleInVerse":[]},"23":{"text":"And whereas the king saw a watcher and an holy one coming down from heaven, and saying, Hew the tree down, and destroy it; yet leave the stump of the roots thereof in the earth, even with a band of iron and brass, in the tender grass of the field; and let it be wet with the dew of heaven, and let his portion be with the beasts of the field, till seven times pass over him;","ref":"Daniel 4:23","synthesized":"And you, O king, saw a watcher, a holy one, coming down from heaven and saying:  ‘Cut down the tree and destroy it, but leave the stump with its roots in the ground, and a band of iron and bronze around it, in the tender grass of the field.   Let him be drenched with the dew of heaven, and graze with the beasts of the field till seven times pass him by.’","sources":{"KJV":{"text":"And whereas the king saw a watcher and an holy one coming down from heaven, and saying, Hew the tree down, and destroy it; yet leave the stump of the roots thereof in the earth, even with a band of iron and brass, in the tender grass of the field; and let it be wet with the dew of heaven, and let his portion be with the beasts of the field, till seven times pass over him;"},"BSB":{"text":"And you, O king, saw a watcher, a holy one, coming down from heaven and saying:  ‘Cut down the tree and destroy it, but leave the stump with its roots in the ground, and a band of iron and bronze around it, in the tender grass of the field.   Let him be drenched with the dew of heaven, and graze with the beasts of the field till seven times pass him by.’"}},"definableWords":["king","saw","holy","one","heaven","tree","ground","field","till"],"peopleInVerse":[]},"24":{"text":"This is the interpretation, O king, and this is the decree of the most High, which is come upon my lord the king:","ref":"Daniel 4:24","synthesized":"This is the interpretation, O king, and this is the decree that the Most High has issued against my lord the king:","sources":{"KJV":{"text":"This is the interpretation, O king, and this is the decree of the most High, which is come upon my lord the king:"},"BSB":{"text":"This is the interpretation, O king, and this is the decree that the Most High has issued against my lord the king:"}},"definableWords":["king","Lord","King"],"peopleInVerse":[]},"25":{"text":"That they shall drive thee from men, and thy dwelling shall be with the beasts of the field, and they shall make thee to eat grass as oxen, and they shall wet thee with the dew of heaven, and seven times shall pass over thee, till thou know that the most High ruleth in the kingdom of men, and giveth it to whomsoever he will.","ref":"Daniel 4:25","synthesized":"You will be driven away from mankind, and your dwelling will be with the beasts of the field. You will feed on grass like an ox and be drenched with the dew of heaven, and seven times shall pass you by, until you acknowledge that the Most High rules over the kingdom of mankind and gives it to whom He wishes.","sources":{"KJV":{"text":"That they shall drive thee from men, and thy dwelling shall be with the beasts of the field, and they shall make thee to eat grass as oxen, and they shall wet thee with the dew of heaven, and seven times shall pass over thee, till thou know that the most High ruleth in the kingdom of men, and giveth it to whomsoever he will."},"BSB":{"text":"You will be driven away from mankind, and your dwelling will be with the beasts of the field. You will feed on grass like an ox and be drenched with the dew of heaven, and seven times shall pass you by, until you acknowledge that the Most High rules over the kingdom of mankind and gives it to whom He wishes."}},"definableWords":["field","heaven","kingdom"],"peopleInVerse":[]},"26":{"text":"And whereas they commanded to leave the stump of the tree roots; thy kingdom shall be sure unto thee, after that thou shalt have known that the heavens do rule.","ref":"Daniel 4:26","synthesized":"As for the command to leave the stump of the tree with its roots, your kingdom will be restored to you as soon as you acknowledge that Heaven rules.","sources":{"KJV":{"text":"And whereas they commanded to leave the stump of the tree roots; thy kingdom shall be sure unto thee, after that thou shalt have known that the heavens do rule."},"BSB":{"text":"As for the command to leave the stump of the tree with its roots, your kingdom will be restored to you as soon as you acknowledge that Heaven rules."}},"definableWords":["tree","kingdom","heaven"],"peopleInVerse":[]},"27":{"text":"Wherefore, O king, let my counsel be acceptable unto thee, and break off thy sins by righteousness, and thine iniquities by shewing mercy to the poor; if it may be a lengthening of thy tranquillity.","ref":"Daniel 4:27","synthesized":"Therefore, may my advice be pleasing to you, O king. Break away from your sins by doing what is right, and from your iniquities by showing mercy to the oppressed. Perhaps there will be an extension of your prosperity.”","sources":{"KJV":{"text":"Wherefore, O king, let my counsel be acceptable unto thee, and break off thy sins by righteousness, and thine iniquities by shewing mercy to the poor; if it may be a lengthening of thy tranquillity."},"BSB":{"text":"Therefore, may my advice be pleasing to you, O king. Break away from your sins by doing what is right, and from your iniquities by showing mercy to the oppressed. Perhaps there will be an extension of your prosperity.”"}},"definableWords":["king","mercy"],"peopleInVerse":[]},"28":{"text":"All this came upon the king Nebuchadnezzar.","ref":"Daniel 4:28","synthesized":"All this happened to King Nebuchadnezzar.","sources":{"KJV":{"text":"All this came upon the king Nebuchadnezzar."},"BSB":{"text":"All this happened to King Nebuchadnezzar."}},"definableWords":["King"],"peopleInVerse":["Nebuchadnezzar"]},"29":{"text":"At the end of twelve months he walked in the palace of the kingdom of Babylon.","ref":"Daniel 4:29","synthesized":"Twelve months later, as he was walking on the roof of the royal palace of Babylon,","sources":{"KJV":{"text":"At the end of twelve months he walked in the palace of the kingdom of Babylon."},"BSB":{"text":"Twelve months later, as he was walking on the roof of the royal palace of Babylon,"}},"definableWords":["Babylon"],"peopleInVerse":[]},"30":{"text":"The king spake, and said, Is not this great Babylon, that I have built for the house of the kingdom by the might of my power, and for the honour of my majesty?","ref":"Daniel 4:30","synthesized":"the king exclaimed, “Is this not Babylon the Great, which I myself have built by the might of my power as a royal residence and for the glory of my majesty?”","sources":{"KJV":{"text":"The king spake, and said, Is not this great Babylon, that I have built for the house of the kingdom by the might of my power, and for the honour of my majesty?"},"BSB":{"text":"the king exclaimed, “Is this not Babylon the Great, which I myself have built by the might of my power as a royal residence and for the glory of my majesty?”"}},"definableWords":["king","Babylon","great","glory"],"peopleInVerse":[]},"31":{"text":"While the word was in the king’s mouth, there fell a voice from heaven, saying, O king Nebuchadnezzar, to thee it is spoken; The kingdom is departed from thee.","ref":"Daniel 4:31","synthesized":"While the words were still in the king’s mouth, a voice came from heaven: “It is decreed to you, King Nebuchadnezzar, that the kingdom has departed from you.","sources":{"KJV":{"text":"While the word was in the king’s mouth, there fell a voice from heaven, saying, O king Nebuchadnezzar, to thee it is spoken; The kingdom is departed from thee."},"BSB":{"text":"While the words were still in the king’s mouth, a voice came from heaven: “It is decreed to you, King Nebuchadnezzar, that the kingdom has departed from you."}},"definableWords":["king","voice","heaven","King","kingdom"],"peopleInVerse":["Nebuchadnezzar"]},"32":{"text":"And they shall drive thee from men, and thy dwelling shall be with the beasts of the field: they shall make thee to eat grass as oxen, and seven times shall pass over thee, until thou know that the most High ruleth in the kingdom of men, and giveth it to whomsoever he will.","ref":"Daniel 4:32","synthesized":"You will be driven away from mankind to live with the beasts of the field, and you will feed on grass like an ox. And seven times will pass you by, until you acknowledge that the Most High rules over the kingdom of mankind and gives it to whom He wishes.”","sources":{"KJV":{"text":"And they shall drive thee from men, and thy dwelling shall be with the beasts of the field: they shall make thee to eat grass as oxen, and seven times shall pass over thee, until thou know that the most High ruleth in the kingdom of men, and giveth it to whomsoever he will."},"BSB":{"text":"You will be driven away from mankind to live with the beasts of the field, and you will feed on grass like an ox. And seven times will pass you by, until you acknowledge that the Most High rules over the kingdom of mankind and gives it to whom He wishes.”"}},"definableWords":["live","field","kingdom"],"peopleInVerse":[]},"33":{"text":"The same hour was the thing fulfilled upon Nebuchadnezzar: and he was driven from men, and did eat grass as oxen, and his body was wet with the dew of heaven, till his hairs were grown like eagles’ feathers, and his nails like birds’ claws.","ref":"Daniel 4:33","synthesized":"At that moment the sentence against Nebuchadnezzar was fulfilled. He was driven away from mankind. He ate grass like an ox, and his body was drenched with the dew of heaven, until his hair grew like the feathers of an eagle and his nails like the claws of a bird.","sources":{"KJV":{"text":"The same hour was the thing fulfilled upon Nebuchadnezzar: and he was driven from men, and did eat grass as oxen, and his body was wet with the dew of heaven, till his hairs were grown like eagles’ feathers, and his nails like birds’ claws."},"BSB":{"text":"At that moment the sentence against Nebuchadnezzar was fulfilled. He was driven away from mankind. He ate grass like an ox, and his body was drenched with the dew of heaven, until his hair grew like the feathers of an eagle and his nails like the claws of a bird."}},"definableWords":["heaven","bird"],"peopleInVerse":["Nebuchadnezzar"]},"34":{"text":"And at the end of the days I Nebuchadnezzar lifted up mine eyes unto heaven, and mine understanding returned unto me, and I blessed the most High, and I praised and honoured him that liveth for ever, whose dominion is an everlasting dominion, and his kingdom is from generation to generation:","ref":"Daniel 4:34","synthesized":"But at the end of those days I, Nebuchadnezzar, looked up to heaven, and my sanity was restored to me. Then I praised the Most High, and I honored and glorified Him who lives forever:  “For His dominion is an everlasting dominion, and His kingdom endures from generation to generation.","sources":{"KJV":{"text":"And at the end of the days I Nebuchadnezzar lifted up mine eyes unto heaven, and mine understanding returned unto me, and I blessed the most High, and I praised and honoured him that liveth for ever, whose dominion is an everlasting dominion, and his kingdom is from generation to generation:"},"BSB":{"text":"But at the end of those days I, Nebuchadnezzar, looked up to heaven, and my sanity was restored to me. Then I praised the Most High, and I honored and glorified Him who lives forever:  “For His dominion is an everlasting dominion, and His kingdom endures from generation to generation."}},"definableWords":["days","heaven","dominion","everlasting","kingdom"],"peopleInVerse":["Nebuchadnezzar"]},"35":{"text":"And all the inhabitants of the earth are reputed as nothing: and he doeth according to his will in the army of heaven, and among the inhabitants of the earth: and none can stay his hand, or say unto him, What doest thou?","ref":"Daniel 4:35","synthesized":"All the peoples of the earth are counted as nothing, and He does as He pleases with the army of heaven and the peoples of the earth. There is no one who can restrain His hand or say to Him, ‘What have You done?’”","sources":{"KJV":{"text":"And all the inhabitants of the earth are reputed as nothing: and he doeth according to his will in the army of heaven, and among the inhabitants of the earth: and none can stay his hand, or say unto him, What doest thou?"},"BSB":{"text":"All the peoples of the earth are counted as nothing, and He does as He pleases with the army of heaven and the peoples of the earth. There is no one who can restrain His hand or say to Him, ‘What have You done?’”"}},"definableWords":["earth","heaven","one","or"],"peopleInVerse":[]},"36":{"text":"At the same time my reason returned unto me; and for the glory of my kingdom, mine honour and brightness returned unto me; and my counsellors and my lords sought unto me; and I was established in my kingdom, and excellent majesty was added unto me.","ref":"Daniel 4:36","synthesized":"At the same time my sanity was restored, my honor and splendor returned to me for the glory of my kingdom. My advisers and nobles sought me out, and I was restored to my throne, and surpassing greatness was added to me.","sources":{"KJV":{"text":"At the same time my reason returned unto me; and for the glory of my kingdom, mine honour and brightness returned unto me; and my counsellors and my lords sought unto me; and I was established in my kingdom, and excellent majesty was added unto me."},"BSB":{"text":"At the same time my sanity was restored, my honor and splendor returned to me for the glory of my kingdom. My advisers and nobles sought me out, and I was restored to my throne, and surpassing greatness was added to me."}},"definableWords":["glory","kingdom","throne"],"peopleInVerse":[]},"37":{"text":"Now I Nebuchadnezzar praise and extol and honour the King of heaven, all whose works are truth, and his ways judgment: and those that walk in pride he is able to abase.","ref":"Daniel 4:37","synthesized":"Now I, Nebuchadnezzar, praise and exalt and glorify the King of heaven, for all His works are true and all His ways are just. And He is able to humble those who walk in pride.","sources":{"KJV":{"text":"Now I Nebuchadnezzar praise and extol and honour the King of heaven, all whose works are truth, and his ways judgment: and those that walk in pride he is able to abase."},"BSB":{"text":"Now I, Nebuchadnezzar, praise and exalt and glorify the King of heaven, for all His works are true and all His ways are just. And He is able to humble those who walk in pride."}},"definableWords":["praise","King","heaven","works","walk"],"peopleInVerse":["Nebuchadnezzar"]}}},"5":{"chapter":"5","title":"THE WRITING ON THE WALL","verses":{"1":{"text":"Belshazzar the king made a great feast to a thousand of his lords, and drank wine before the thousand.","ref":"Daniel 5:1","synthesized":"Later, King Belshazzar held a great feast for a thousand of his nobles, and he drank wine with them.","sources":{"KJV":{"text":"Belshazzar the king made a great feast to a thousand of his lords, and drank wine before the thousand."},"BSB":{"text":"Later, King Belshazzar held a great feast for a thousand of his nobles, and he drank wine with them."}},"definableWords":["King","great"],"peopleInVerse":[]},"2":{"text":"Belshazzar, whiles he tasted the wine, commanded to bring the golden and silver vessels which his father Nebuchadnezzar had taken out of the temple which was in Jerusalem; that the king, and his princes, his wives, and his concubines, might drink therein.","ref":"Daniel 5:2","synthesized":"Under the influence of the wine, Belshazzar gave orders to bring in the gold and silver vessels that Nebuchadnezzar his father had taken from the temple in Jerusalem, so that the king could drink from them, along with his nobles, his wives, and his concubines.","sources":{"KJV":{"text":"Belshazzar, whiles he tasted the wine, commanded to bring the golden and silver vessels which his father Nebuchadnezzar had taken out of the temple which was in Jerusalem; that the king, and his princes, his wives, and his concubines, might drink therein."},"BSB":{"text":"Under the influence of the wine, Belshazzar gave orders to bring in the gold and silver vessels that Nebuchadnezzar his father had taken from the temple in Jerusalem, so that the king could drink from them, along with his nobles, his wives, and his concubines."}},"definableWords":["father","temple","Jerusalem","king"],"peopleInVerse":["Nebuchadnezzar"]},"3":{"text":"Then they brought the golden vessels that were taken out of the temple of the house of God which was at Jerusalem; and the king, and his princes, his wives, and his concubines, drank in them.","ref":"Daniel 5:3","synthesized":"Thus they brought in the gold vessels that had been taken from the temple, the house of God in Jerusalem, and the king drank from them, along with his nobles, his wives, and his concubines.","sources":{"KJV":{"text":"Then they brought the golden vessels that were taken out of the temple of the house of God which was at Jerusalem; and the king, and his princes, his wives, and his concubines, drank in them."},"BSB":{"text":"Thus they brought in the gold vessels that had been taken from the temple, the house of God in Jerusalem, and the king drank from them, along with his nobles, his wives, and his concubines."}},"definableWords":["temple","house","God","Jerusalem","king"],"peopleInVerse":[]},"4":{"text":"They drank wine, and praised the gods of gold, and of silver, of brass, of iron, of wood, and of stone.","ref":"Daniel 5:4","synthesized":"As they drank the wine, they praised their gods of gold and silver, bronze and iron, wood and stone.","sources":{"KJV":{"text":"They drank wine, and praised the gods of gold, and of silver, of brass, of iron, of wood, and of stone."},"BSB":{"text":"As they drank the wine, they praised their gods of gold and silver, bronze and iron, wood and stone."}},"definableWords":["stone"],"peopleInVerse":[]},"5":{"text":"In the same hour came forth fingers of a man’s hand, and wrote over against the candlestick upon the plaister of the wall of the king’s palace: and the king saw the part of the hand that wrote.","ref":"Daniel 5:5","synthesized":"At that moment the fingers of a human hand appeared and wrote on the plaster of the wall, near the lampstand in the royal palace. As the king watched the hand that was writing,","sources":{"KJV":{"text":"In the same hour came forth fingers of a man’s hand, and wrote over against the candlestick upon the plaister of the wall of the king’s palace: and the king saw the part of the hand that wrote."},"BSB":{"text":"At that moment the fingers of a human hand appeared and wrote on the plaster of the wall, near the lampstand in the royal palace. As the king watched the hand that was writing,"}},"definableWords":["king"],"peopleInVerse":[]},"6":{"text":"Then the king’s countenance was changed, and his thoughts troubled him, so that the joints of his loins were loosed, and his knees smote one against another.","ref":"Daniel 5:6","synthesized":"his face grew pale and his thoughts so alarmed him that his hips gave way and his knees knocked together.","sources":{"KJV":{"text":"Then the king’s countenance was changed, and his thoughts troubled him, so that the joints of his loins were loosed, and his knees smote one against another."},"BSB":{"text":"his face grew pale and his thoughts so alarmed him that his hips gave way and his knees knocked together."}},"definableWords":["way"],"peopleInVerse":[]},"7":{"text":"The king cried aloud to bring in the astrologers, the Chaldeans, and the soothsayers. And the king spake, and said to the wise men of Babylon, Whosoever shall read this writing, and shew me the interpretation thereof, shall be clothed with scarlet, and have a chain of gold about his neck, and shall be the third ruler in the kingdom.","ref":"Daniel 5:7","synthesized":"The king called out for the enchanters, astrologers, and diviners to be brought in, and he said to these wise men of Babylon, “Whoever reads this inscription and tells me its interpretation will be clothed in purple and have a gold chain placed around his neck, and he will be made the third highest ruler in the kingdom.”","sources":{"KJV":{"text":"The king cried aloud to bring in the astrologers, the Chaldeans, and the soothsayers. And the king spake, and said to the wise men of Babylon, Whosoever shall read this writing, and shew me the interpretation thereof, shall be clothed with scarlet, and have a chain of gold about his neck, and shall be the third ruler in the kingdom."},"BSB":{"text":"The king called out for the enchanters, astrologers, and diviners to be brought in, and he said to these wise men of Babylon, “Whoever reads this inscription and tells me its interpretation will be clothed in purple and have a gold chain placed around his neck, and he will be made the third highest ruler in the kingdom.”"}},"definableWords":["king","men","Babylon","made","ruler","kingdom"],"peopleInVerse":[]},"8":{"text":"Then came in all the king’s wise men: but they could not read the writing, nor make known to the king the interpretation thereof.","ref":"Daniel 5:8","synthesized":"So all the king’s wise men came in, but they could not read the inscription or interpret it for him.","sources":{"KJV":{"text":"Then came in all the king’s wise men: but they could not read the writing, nor make known to the king the interpretation thereof."},"BSB":{"text":"So all the king’s wise men came in, but they could not read the inscription or interpret it for him."}},"definableWords":["king","men","or"],"peopleInVerse":[]},"9":{"text":"Then was king Belshazzar greatly troubled, and his countenance was changed in him, and his lords were astonied.","ref":"Daniel 5:9","synthesized":"Then King Belshazzar became even more terrified, his face grew even more pale, and his nobles were bewildered.","sources":{"KJV":{"text":"Then was king Belshazzar greatly troubled, and his countenance was changed in him, and his lords were astonied."},"BSB":{"text":"Then King Belshazzar became even more terrified, his face grew even more pale, and his nobles were bewildered."}},"definableWords":["King"],"peopleInVerse":[]},"10":{"text":"Now the queen by reason of the words of the king and his lords came into the banquet house: and the queen spake and said, O king, live for ever: let not thy thoughts trouble thee, nor let thy countenance be changed:","ref":"Daniel 5:10","synthesized":"Hearing the outcry of the king and his nobles, the queen entered the banquet hall. “O king, may you live forever!” she said. “Do not let your thoughts terrify you, or your face grow pale.","sources":{"KJV":{"text":"Now the queen by reason of the words of the king and his lords came into the banquet house: and the queen spake and said, O king, live for ever: let not thy thoughts trouble thee, nor let thy countenance be changed:"},"BSB":{"text":"Hearing the outcry of the king and his nobles, the queen entered the banquet hall. “O king, may you live forever!” she said. “Do not let your thoughts terrify you, or your face grow pale."}},"definableWords":["king","King","live","or"],"peopleInVerse":[]},"11":{"text":"There is a man in thy kingdom, in whom is the spirit of the holy gods; and in the days of thy father light and understanding and wisdom, like the wisdom of the gods, was found in him; whom the king Nebuchadnezzar thy father, the king, I say, thy father, made master of the magicians, astrologers, Chaldeans, and soothsayers;","ref":"Daniel 5:11","synthesized":"There is a man in your kingdom who has the spirit of the holy gods in him. In the days of your father he was found to have insight, intelligence, and wisdom like that of the gods.  Your father, King Nebuchadnezzar, appointed him chief of the magicians, enchanters, astrologers, and diviners. Your own father, the king,","sources":{"KJV":{"text":"There is a man in thy kingdom, in whom is the spirit of the holy gods; and in the days of thy father light and understanding and wisdom, like the wisdom of the gods, was found in him; whom the king Nebuchadnezzar thy father, the king, I say, thy father, made master of the magicians, astrologers, Chaldeans, and soothsayers;"},"BSB":{"text":"There is a man in your kingdom who has the spirit of the holy gods in him. In the days of your father he was found to have insight, intelligence, and wisdom like that of the gods.  Your father, King Nebuchadnezzar, appointed him chief of the magicians, enchanters, astrologers, and diviners. Your own father, the king,"}},"definableWords":["man","kingdom","spirit","holy","days","father","wisdom","Father","King","king"],"peopleInVerse":["Nebuchadnezzar"]},"12":{"text":"Forasmuch as an excellent spirit, and knowledge, and understanding, interpreting of dreams, and shewing of hard sentences, and dissolving of doubts, were found in the same Daniel, whom the king named Belteshazzar: now let Daniel be called, and he will shew the interpretation.","ref":"Daniel 5:12","synthesized":"did this because Daniel, the one he named Belteshazzar, was found to have an extraordinary spirit, as well as knowledge, understanding, and the ability to interpret dreams, explain riddles, and solve difficult problems. Summon Daniel, therefore, and he will give you the interpretation.”","sources":{"KJV":{"text":"Forasmuch as an excellent spirit, and knowledge, and understanding, interpreting of dreams, and shewing of hard sentences, and dissolving of doubts, were found in the same Daniel, whom the king named Belteshazzar: now let Daniel be called, and he will shew the interpretation."},"BSB":{"text":"did this because Daniel, the one he named Belteshazzar, was found to have an extraordinary spirit, as well as knowledge, understanding, and the ability to interpret dreams, explain riddles, and solve difficult problems. Summon Daniel, therefore, and he will give you the interpretation.”"}},"definableWords":["one","spirit","knowledge"],"peopleInVerse":["Daniel"]},"13":{"text":"Then was Daniel brought in before the king. And the king spake and said unto Daniel, Art thou that Daniel, which art of the children of the captivity of Judah, whom the king my father brought out of Jewry?","ref":"Daniel 5:13","synthesized":"So Daniel was brought before the king, who asked him, “Are you Daniel, one of the exiles my father the king brought from Judah?","sources":{"KJV":{"text":"Then was Daniel brought in before the king. And the king spake and said unto Daniel, Art thou that Daniel, which art of the children of the captivity of Judah, whom the king my father brought out of Jewry?"},"BSB":{"text":"So Daniel was brought before the king, who asked him, “Are you Daniel, one of the exiles my father the king brought from Judah?"}},"definableWords":["king","one","father","King","Judah"],"peopleInVerse":["Daniel"]},"14":{"text":"I have even heard of thee, that the spirit of the gods is in thee, and that light and understanding and excellent wisdom is found in thee.","ref":"Daniel 5:14","synthesized":"I have heard that the spirit of the gods is in you, and that you have insight, intelligence, and extraordinary wisdom.","sources":{"KJV":{"text":"I have even heard of thee, that the spirit of the gods is in thee, and that light and understanding and excellent wisdom is found in thee."},"BSB":{"text":"I have heard that the spirit of the gods is in you, and that you have insight, intelligence, and extraordinary wisdom."}},"definableWords":["spirit","wisdom"],"peopleInVerse":[]},"15":{"text":"And now the wise men, the astrologers, have been brought in before me, that they should read this writing, and make known unto me the interpretation thereof: but they could not shew the interpretation of the thing:","ref":"Daniel 5:15","synthesized":"Now the wise men and enchanters were brought before me to read this inscription and interpret it for me, but they could not give its interpretation.","sources":{"KJV":{"text":"And now the wise men, the astrologers, have been brought in before me, that they should read this writing, and make known unto me the interpretation thereof: but they could not shew the interpretation of the thing:"},"BSB":{"text":"Now the wise men and enchanters were brought before me to read this inscription and interpret it for me, but they could not give its interpretation."}},"definableWords":["men"],"peopleInVerse":[]},"16":{"text":"And I have heard of thee, that thou canst make interpretations, and dissolve doubts: now if thou canst read the writing, and make known to me the interpretation thereof, thou shalt be clothed with scarlet, and have a chain of gold about thy neck, and shalt be the third ruler in the kingdom.","ref":"Daniel 5:16","synthesized":"But I have heard about you, that you are able to give interpretations and solve difficult problems. Therefore, if you can read this inscription and give me its interpretation, you will be clothed in purple and have a gold chain placed around your neck, and you will be made the third highest ruler in the kingdom.”","sources":{"KJV":{"text":"And I have heard of thee, that thou canst make interpretations, and dissolve doubts: now if thou canst read the writing, and make known to me the interpretation thereof, thou shalt be clothed with scarlet, and have a chain of gold about thy neck, and shalt be the third ruler in the kingdom."},"BSB":{"text":"But I have heard about you, that you are able to give interpretations and solve difficult problems. Therefore, if you can read this inscription and give me its interpretation, you will be clothed in purple and have a gold chain placed around your neck, and you will be made the third highest ruler in the kingdom.”"}},"definableWords":["made","ruler","kingdom"],"peopleInVerse":[]},"17":{"text":"Then Daniel answered and said before the king, Let thy gifts be to thyself, and give thy rewards to another; yet I will read the writing unto the king, and make known to him the interpretation.","ref":"Daniel 5:17","synthesized":"In response, Daniel said to the king, “You may keep your gifts for yourself and give your rewards to someone else. Nevertheless, I will read the inscription for the king and interpret it for him.","sources":{"KJV":{"text":"Then Daniel answered and said before the king, Let thy gifts be to thyself, and give thy rewards to another; yet I will read the writing unto the king, and make known to him the interpretation."},"BSB":{"text":"In response, Daniel said to the king, “You may keep your gifts for yourself and give your rewards to someone else. Nevertheless, I will read the inscription for the king and interpret it for him."}},"definableWords":["king","keep","King"],"peopleInVerse":["Daniel"]},"18":{"text":"O thou king, the most high God gave Nebuchadnezzar thy father a kingdom, and majesty, and glory, and honour:","ref":"Daniel 5:18","synthesized":"As for you, O king, the Most High God gave your father Nebuchadnezzar sovereignty and greatness, glory and honor.","sources":{"KJV":{"text":"O thou king, the most high God gave Nebuchadnezzar thy father a kingdom, and majesty, and glory, and honour:"},"BSB":{"text":"As for you, O king, the Most High God gave your father Nebuchadnezzar sovereignty and greatness, glory and honor."}},"definableWords":["king","God","father","glory"],"peopleInVerse":["Nebuchadnezzar"]},"19":{"text":"And for the majesty that he gave him, all people, nations, and languages, trembled and feared before him: whom he would he slew; and whom he would he kept alive; and whom he would he set up; and whom he would he put down.","ref":"Daniel 5:19","synthesized":"Because of the greatness that He bestowed on him, the people of every nation and language trembled in fear before him. He killed whom he wished and kept alive whom he wished; he exalted whom he wished and humbled whom he wished.","sources":{"KJV":{"text":"And for the majesty that he gave him, all people, nations, and languages, trembled and feared before him: whom he would he slew; and whom he would he kept alive; and whom he would he set up; and whom he would he put down."},"BSB":{"text":"Because of the greatness that He bestowed on him, the people of every nation and language trembled in fear before him. He killed whom he wished and kept alive whom he wished; he exalted whom he wished and humbled whom he wished."}},"definableWords":["people","nation","fear"],"peopleInVerse":[]},"20":{"text":"But when his heart was lifted up, and his mind hardened in pride, he was deposed from his kingly throne, and they took his glory from him:","ref":"Daniel 5:20","synthesized":"But when his heart became arrogant and his spirit was hardened with pride, he was deposed from his royal throne, and his glory was taken from him.","sources":{"KJV":{"text":"But when his heart was lifted up, and his mind hardened in pride, he was deposed from his kingly throne, and they took his glory from him:"},"BSB":{"text":"But when his heart became arrogant and his spirit was hardened with pride, he was deposed from his royal throne, and his glory was taken from him."}},"definableWords":["heart","spirit","throne","glory"],"peopleInVerse":[]},"21":{"text":"And he was driven from the sons of men; and his heart was made like the beasts, and his dwelling was with the wild asses: they fed him with grass like oxen, and his body was wet with the dew of heaven; till he knew that the most high God ruled in the kingdom of men, and that he appointeth over it whomsoever he will.","ref":"Daniel 5:21","synthesized":"He was driven away from mankind, and his mind was like that of a beast. He lived with the wild donkeys and ate grass like an ox, and his body was drenched with the dew of heaven until he acknowledged that the Most High God rules over the kingdom of mankind, setting over it whom He wishes.","sources":{"KJV":{"text":"And he was driven from the sons of men; and his heart was made like the beasts, and his dwelling was with the wild asses: they fed him with grass like oxen, and his body was wet with the dew of heaven; till he knew that the most high God ruled in the kingdom of men, and that he appointeth over it whomsoever he will."},"BSB":{"text":"He was driven away from mankind, and his mind was like that of a beast. He lived with the wild donkeys and ate grass like an ox, and his body was drenched with the dew of heaven until he acknowledged that the Most High God rules over the kingdom of mankind, setting over it whom He wishes."}},"definableWords":["mind","heaven","God","kingdom"],"peopleInVerse":[]},"22":{"text":"And thou his son, O Belshazzar, hast not humbled thine heart, though thou knewest all this;","ref":"Daniel 5:22","synthesized":"But you his son, O Belshazzar, have not humbled your heart, even though you knew all this.","sources":{"KJV":{"text":"And thou his son, O Belshazzar, hast not humbled thine heart, though thou knewest all this;"},"BSB":{"text":"But you his son, O Belshazzar, have not humbled your heart, even though you knew all this."}},"definableWords":["son","heart"],"peopleInVerse":[]},"23":{"text":"But hast lifted up thyself against the Lord of heaven; and they have brought the vessels of his house before thee, and thou, and thy lords, thy wives, and thy concubines, have drunk wine in them; and thou hast praised the gods of silver, and gold, of brass, iron, wood, and stone, which see not, nor hear, nor know: and the God in whose hand thy breath is, and whose are all thy ways, hast thou not glorified:","ref":"Daniel 5:23","synthesized":"Instead, you have exalted yourself against the Lord of heaven. The vessels from His house were brought to you, and as you drank wine from them with your nobles, wives, and concubines, you praised your gods of silver and gold, bronze and iron, wood and stone, which cannot see or hear or understand. But you have failed to glorify the God who holds in His hand your very breath and all your ways.","sources":{"KJV":{"text":"But hast lifted up thyself against the Lord of heaven; and they have brought the vessels of his house before thee, and thou, and thy lords, thy wives, and thy concubines, have drunk wine in them; and thou hast praised the gods of silver, and gold, of brass, iron, wood, and stone, which see not, nor hear, nor know: and the God in whose hand thy breath is, and whose are all thy ways, hast thou not glorified:"},"BSB":{"text":"Instead, you have exalted yourself against the Lord of heaven. The vessels from His house were brought to you, and as you drank wine from them with your nobles, wives, and concubines, you praised your gods of silver and gold, bronze and iron, wood and stone, which cannot see or hear or understand. But you have failed to glorify the God who holds in His hand your very breath and all your ways."}},"definableWords":["Lord","heaven","house","stone","see","or","hear","God","breath"],"peopleInVerse":[]},"24":{"text":"Then was the part of the hand sent from him; and this writing was written.","ref":"Daniel 5:24","synthesized":"Therefore He sent the hand that wrote the inscription.","sources":{"KJV":{"text":"Then was the part of the hand sent from him; and this writing was written."},"BSB":{"text":"Therefore He sent the hand that wrote the inscription."}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"And this is the writing that was written, MENE, MENE, TEKEL, UPHARSIN.","ref":"Daniel 5:25","synthesized":"Now this is the inscription that was written:  MENE, MENE, TEKEL, PARSIN.","sources":{"KJV":{"text":"And this is the writing that was written, MENE, MENE, TEKEL, UPHARSIN."},"BSB":{"text":"Now this is the inscription that was written:  MENE, MENE, TEKEL, PARSIN."}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"This is the interpretation of the thing: MENE; God hath numbered thy kingdom, and finished it.","ref":"Daniel 5:26","synthesized":"And this is the interpretation of the message:  MENE means that God has numbered the days of your reign and brought it to an end.","sources":{"KJV":{"text":"This is the interpretation of the thing: MENE; God hath numbered thy kingdom, and finished it."},"BSB":{"text":"And this is the interpretation of the message:  MENE means that God has numbered the days of your reign and brought it to an end."}},"definableWords":["God","days","reign"],"peopleInVerse":[]},"27":{"text":"TEKEL; Thou art weighed in the balances, and art found wanting.","ref":"Daniel 5:27","synthesized":"TEKEL means that you have been weighed on the scales and found deficient.","sources":{"KJV":{"text":"TEKEL; Thou art weighed in the balances, and art found wanting."},"BSB":{"text":"TEKEL means that you have been weighed on the scales and found deficient."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"PERES; Thy kingdom is divided, and given to the Medes and Persians.","ref":"Daniel 5:28","synthesized":"PERES means that your kingdom has been divided and given over to the Medes and Persians.”","sources":{"KJV":{"text":"PERES; Thy kingdom is divided, and given to the Medes and Persians."},"BSB":{"text":"PERES means that your kingdom has been divided and given over to the Medes and Persians.”"}},"definableWords":["kingdom"],"peopleInVerse":[]},"29":{"text":"Then commanded Belshazzar, and they clothed Daniel with scarlet, and put a chain of gold about his neck, and made a proclamation concerning him, that he should be the third ruler in the kingdom.","ref":"Daniel 5:29","synthesized":"Then Belshazzar gave the command, and they clothed Daniel in purple, placed a gold chain around his neck, and proclaimed him the third highest ruler in the kingdom.","sources":{"KJV":{"text":"Then commanded Belshazzar, and they clothed Daniel with scarlet, and put a chain of gold about his neck, and made a proclamation concerning him, that he should be the third ruler in the kingdom."},"BSB":{"text":"Then Belshazzar gave the command, and they clothed Daniel in purple, placed a gold chain around his neck, and proclaimed him the third highest ruler in the kingdom."}},"definableWords":["ruler","kingdom"],"peopleInVerse":["Daniel"]},"30":{"text":"In that night was Belshazzar the king of the Chaldeans slain.","ref":"Daniel 5:30","synthesized":"That very night Belshazzar king of the Chaldeans was slain,","sources":{"KJV":{"text":"In that night was Belshazzar the king of the Chaldeans slain."},"BSB":{"text":"That very night Belshazzar king of the Chaldeans was slain,"}},"definableWords":["night","king"],"peopleInVerse":[]},"31":{"text":"And Darius the Median took the kingdom, being about threescore and two years old.","ref":"Daniel 5:31","synthesized":"and Darius the Mede received the kingdom at the age of sixty-two.","sources":{"KJV":{"text":"And Darius the Median took the kingdom, being about threescore and two years old."},"BSB":{"text":"and Darius the Mede received the kingdom at the age of sixty-two."}},"definableWords":["kingdom"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"DANIEL IN THE LIONS' DEN","verses":{"1":{"text":"It pleased Darius to set over the kingdom an hundred and twenty princes, which should be over the whole kingdom;","ref":"Daniel 6:1","synthesized":"Now it pleased Darius to appoint 120 satraps to rule throughout the kingdom,","sources":{"KJV":{"text":"It pleased Darius to set over the kingdom an hundred and twenty princes, which should be over the whole kingdom;"},"BSB":{"text":"Now it pleased Darius to appoint 120 satraps to rule throughout the kingdom,"}},"definableWords":["rule","kingdom"],"peopleInVerse":[],"kingdomLens":"Officials trick King Darius into signing a 30-day decree: no prayer to any god but the king. Daniel continues to pray three times a day at his open window — facing Jerusalem, as always. He's thrown into the lions' den. God shuts the lions' mouths. The king pulls him out in the morning. The accusers are thrown in instead — and devoured before they hit the bottom.","cultural":{"title":"Daniel in the lions' den","detail":"Daniel was probably over 80 years old at this point. A lifetime of consistent prayer prepared him for the moment. Daniel 6:10 is precise: he prayed 'as he did aforetime' — no panic prayer, just normal faithful prayer that happened to be illegal.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"And over these three presidents; of whom Daniel was first: that the princes might give accounts unto them, and the king should have no damage.","ref":"Daniel 6:2","synthesized":"and over them three administrators, including Daniel, to whom these satraps were accountable so that the king would not suffer loss.","sources":{"KJV":{"text":"And over these three presidents; of whom Daniel was first: that the princes might give accounts unto them, and the king should have no damage."},"BSB":{"text":"and over them three administrators, including Daniel, to whom these satraps were accountable so that the king would not suffer loss."}},"definableWords":["king"],"peopleInVerse":["Daniel"]},"3":{"text":"Then this Daniel was preferred above the presidents and princes, because an excellent spirit was in him; and the king thought to set him over the whole realm.","ref":"Daniel 6:3","synthesized":"Soon, by his extraordinary spirit, Daniel distinguished himself among the administrators and satraps. So the king planned to set him over the whole kingdom.","sources":{"KJV":{"text":"Then this Daniel was preferred above the presidents and princes, because an excellent spirit was in him; and the king thought to set him over the whole realm."},"BSB":{"text":"Soon, by his extraordinary spirit, Daniel distinguished himself among the administrators and satraps. So the king planned to set him over the whole kingdom."}},"definableWords":["spirit","king","kingdom"],"peopleInVerse":["Daniel"]},"4":{"text":"Then the presidents and princes sought to find occasion against Daniel concerning the kingdom; but they could find none occasion nor fault; forasmuch as he was faithful, neither was there any error or fault found in him.","ref":"Daniel 6:4","synthesized":"Thus the administrators and satraps sought a charge against Daniel concerning the kingdom, but they could find no charge or corruption, because he was trustworthy, and no negligence or corruption was found in him.","sources":{"KJV":{"text":"Then the presidents and princes sought to find occasion against Daniel concerning the kingdom; but they could find none occasion nor fault; forasmuch as he was faithful, neither was there any error or fault found in him."},"BSB":{"text":"Thus the administrators and satraps sought a charge against Daniel concerning the kingdom, but they could find no charge or corruption, because he was trustworthy, and no negligence or corruption was found in him."}},"definableWords":["charge","kingdom","or"],"peopleInVerse":["Daniel"]},"5":{"text":"Then said these men, We shall not find any occasion against this Daniel, except we find it against him concerning the law of his God.","ref":"Daniel 6:5","synthesized":"Finally these men said, “We will never find any charge against this Daniel, unless we find something against him concerning the law of his God.”","sources":{"KJV":{"text":"Then said these men, We shall not find any occasion against this Daniel, except we find it against him concerning the law of his God."},"BSB":{"text":"Finally these men said, “We will never find any charge against this Daniel, unless we find something against him concerning the law of his God.”"}},"definableWords":["men","charge","law","God"],"peopleInVerse":["Daniel"]},"6":{"text":"Then these presidents and princes assembled together to the king, and said thus unto him, King Darius, live for ever.","ref":"Daniel 6:6","synthesized":"So the administrators and satraps went together to the king and said, “O King Darius, may you live forever!","sources":{"KJV":{"text":"Then these presidents and princes assembled together to the king, and said thus unto him, King Darius, live for ever."},"BSB":{"text":"So the administrators and satraps went together to the king and said, “O King Darius, may you live forever!"}},"definableWords":["king","King","live"],"peopleInVerse":[]},"7":{"text":"All the presidents of the kingdom, the governors, and the princes, the counsellors, and the captains, have consulted together to establish a royal statute, and to make a firm decree, that whosoever shall ask a petition of any God or man for thirty days, save of thee, O king, he shall be cast into the den of lions.","ref":"Daniel 6:7","synthesized":"All the royal administrators, prefects, satraps, advisers, and governors have agreed that the king should establish an ordinance and enforce a decree that for thirty days anyone who petitions any god or man except you, O king, will be thrown into the den of lions.","sources":{"KJV":{"text":"All the presidents of the kingdom, the governors, and the princes, the counsellors, and the captains, have consulted together to establish a royal statute, and to make a firm decree, that whosoever shall ask a petition of any God or man for thirty days, save of thee, O king, he shall be cast into the den of lions."},"BSB":{"text":"All the royal administrators, prefects, satraps, advisers, and governors have agreed that the king should establish an ordinance and enforce a decree that for thirty days anyone who petitions any god or man except you, O king, will be thrown into the den of lions."}},"definableWords":["king","days","God","or","man","King"],"peopleInVerse":[]},"8":{"text":"Now, O king, establish the decree, and sign the writing, that it be not changed, according to the law of the Medes and Persians, which altereth not.","ref":"Daniel 6:8","synthesized":"Therefore, O king, establish the decree and sign the document so that it cannot be changed—in accordance with the law of the Medes and Persians, which cannot be repealed.”","sources":{"KJV":{"text":"Now, O king, establish the decree, and sign the writing, that it be not changed, according to the law of the Medes and Persians, which altereth not."},"BSB":{"text":"Therefore, O king, establish the decree and sign the document so that it cannot be changed—in accordance with the law of the Medes and Persians, which cannot be repealed.”"}},"definableWords":["king","law"],"peopleInVerse":[]},"9":{"text":"Wherefore king Darius signed the writing and the decree.","ref":"Daniel 6:9","synthesized":"Therefore King Darius signed the written decree.","sources":{"KJV":{"text":"Wherefore king Darius signed the writing and the decree."},"BSB":{"text":"Therefore King Darius signed the written decree."}},"definableWords":["King"],"peopleInVerse":[]},"10":{"text":"Now when Daniel knew that the writing was signed, he went into his house; and his windows being open in his chamber toward Jerusalem, he kneeled upon his knees three times a day, and prayed, and gave thanks before his God, as he did aforetime.","ref":"Daniel 6:10","synthesized":"Now when Daniel learned that the document had been signed, he went into his house, where the windows of his upper room opened toward Jerusalem, and three times a day he got down on his knees, prayed, and gave thanks to his God, just as he had done before.","sources":{"KJV":{"text":"Now when Daniel knew that the writing was signed, he went into his house; and his windows being open in his chamber toward Jerusalem, he kneeled upon his knees three times a day, and prayed, and gave thanks before his God, as he did aforetime."},"BSB":{"text":"Now when Daniel learned that the document had been signed, he went into his house, where the windows of his upper room opened toward Jerusalem, and three times a day he got down on his knees, prayed, and gave thanks to his God, just as he had done before."}},"definableWords":["house","Jerusalem","day","God"],"peopleInVerse":["Daniel"]},"11":{"text":"Then these men assembled, and found Daniel praying and making supplication before his God.","ref":"Daniel 6:11","synthesized":"Then these men went as a group and found Daniel petitioning and imploring his God.","sources":{"KJV":{"text":"Then these men assembled, and found Daniel praying and making supplication before his God."},"BSB":{"text":"Then these men went as a group and found Daniel petitioning and imploring his God."}},"definableWords":["men","God"],"peopleInVerse":["Daniel"]},"12":{"text":"Then they came near, and spake before the king concerning the king’s decree; Hast thou not signed a decree, that every man that shall ask a petition of any God or man within thirty days, save of thee, O king, shall be cast into the den of lions? The king answered and said, The thing is true, according to the law of the Medes and Persians, which altereth not.","ref":"Daniel 6:12","synthesized":"So they approached the king and asked about his royal decree: “Did you not sign a decree that for thirty days any man who petitions any god or man except you, O king, will be thrown into the den of lions?”  The king replied, “According to the law of the Medes and Persians the order stands, and it cannot be repealed.”","sources":{"KJV":{"text":"Then they came near, and spake before the king concerning the king’s decree; Hast thou not signed a decree, that every man that shall ask a petition of any God or man within thirty days, save of thee, O king, shall be cast into the den of lions? The king answered and said, The thing is true, according to the law of the Medes and Persians, which altereth not."},"BSB":{"text":"So they approached the king and asked about his royal decree: “Did you not sign a decree that for thirty days any man who petitions any god or man except you, O king, will be thrown into the den of lions?”  The king replied, “According to the law of the Medes and Persians the order stands, and it cannot be repealed.”"}},"definableWords":["king","days","man","God","or","King","law"],"peopleInVerse":[]},"13":{"text":"Then answered they and said before the king, That Daniel, which is of the children of the captivity of Judah, regardeth not thee, O king, nor the decree that thou hast signed, but maketh his petition three times a day.","ref":"Daniel 6:13","synthesized":"Then they told the king, “Daniel, one of the exiles from Judah, shows no regard for you, O king, or for the decree that you have signed. He still makes his petition three times a day.”","sources":{"KJV":{"text":"Then answered they and said before the king, That Daniel, which is of the children of the captivity of Judah, regardeth not thee, O king, nor the decree that thou hast signed, but maketh his petition three times a day."},"BSB":{"text":"Then they told the king, “Daniel, one of the exiles from Judah, shows no regard for you, O king, or for the decree that you have signed. He still makes his petition three times a day.”"}},"definableWords":["king","one","Judah","King","or","day"],"peopleInVerse":["Daniel"]},"14":{"text":"Then the king, when he heard these words, was sore displeased with himself, and set his heart on Daniel to deliver him: and he laboured till the going down of the sun to deliver him.","ref":"Daniel 6:14","synthesized":"As soon as the king heard this, he was deeply distressed and set his mind on delivering Daniel, and he labored until sundown to rescue him.","sources":{"KJV":{"text":"Then the king, when he heard these words, was sore displeased with himself, and set his heart on Daniel to deliver him: and he laboured till the going down of the sun to deliver him."},"BSB":{"text":"As soon as the king heard this, he was deeply distressed and set his mind on delivering Daniel, and he labored until sundown to rescue him."}},"definableWords":["king","mind"],"peopleInVerse":["Daniel"]},"15":{"text":"Then these men assembled unto the king, and said unto the king, Know, O king, that the law of the Medes and Persians is, That no decree nor statute which the king establisheth may be changed.","ref":"Daniel 6:15","synthesized":"Then the men approached the king together and said to him, “Remember, O king, that by the law of the Medes and Persians no decree or ordinance established by the king can be changed.”","sources":{"KJV":{"text":"Then these men assembled unto the king, and said unto the king, Know, O king, that the law of the Medes and Persians is, That no decree nor statute which the king establisheth may be changed."},"BSB":{"text":"Then the men approached the king together and said to him, “Remember, O king, that by the law of the Medes and Persians no decree or ordinance established by the king can be changed.”"}},"definableWords":["men","king","remember","King","law","or"],"peopleInVerse":[]},"16":{"text":"Then the king commanded, and they brought Daniel, and cast him into the den of lions. Now the king spake and said unto Daniel, Thy God whom thou servest continually, he will deliver thee.","ref":"Daniel 6:16","synthesized":"So the king gave the order, and they brought Daniel and threw him into the den of lions.  The king said to Daniel, “May your God, whom you serve continually, deliver you!”","sources":{"KJV":{"text":"Then the king commanded, and they brought Daniel, and cast him into the den of lions. Now the king spake and said unto Daniel, Thy God whom thou servest continually, he will deliver thee."},"BSB":{"text":"So the king gave the order, and they brought Daniel and threw him into the den of lions.  The king said to Daniel, “May your God, whom you serve continually, deliver you!”"}},"definableWords":["king","King","God","deliver"],"peopleInVerse":["Daniel"]},"17":{"text":"And a stone was brought, and laid upon the mouth of the den; and the king sealed it with his own signet, and with the signet of his lords; that the purpose might not be changed concerning Daniel.","ref":"Daniel 6:17","synthesized":"A stone was brought and placed over the mouth of the den, and the king sealed it with his own signet ring and with the rings of his nobles, so that nothing concerning Daniel could be changed.","sources":{"KJV":{"text":"And a stone was brought, and laid upon the mouth of the den; and the king sealed it with his own signet, and with the signet of his lords; that the purpose might not be changed concerning Daniel."},"BSB":{"text":"A stone was brought and placed over the mouth of the den, and the king sealed it with his own signet ring and with the rings of his nobles, so that nothing concerning Daniel could be changed."}},"definableWords":["stone","king"],"peopleInVerse":["Daniel"]},"18":{"text":"Then the king went to his palace, and passed the night fasting: neither were instruments of musick brought before him: and his sleep went from him.","ref":"Daniel 6:18","synthesized":"Then the king went to his palace and spent the night fasting. No entertainment was brought before him, and sleep fled from him.","sources":{"KJV":{"text":"Then the king went to his palace, and passed the night fasting: neither were instruments of musick brought before him: and his sleep went from him."},"BSB":{"text":"Then the king went to his palace and spent the night fasting. No entertainment was brought before him, and sleep fled from him."}},"definableWords":["king","night"],"peopleInVerse":[]},"19":{"text":"Then the king arose very early in the morning, and went in haste unto the den of lions.","ref":"Daniel 6:19","synthesized":"At the first light of dawn, the king got up and hurried to the den of lions.","sources":{"KJV":{"text":"Then the king arose very early in the morning, and went in haste unto the den of lions."},"BSB":{"text":"At the first light of dawn, the king got up and hurried to the den of lions."}},"definableWords":["light","king"],"peopleInVerse":[]},"20":{"text":"And when he came to the den, he cried with a lamentable voice unto Daniel: and the king spake and said to Daniel, O Daniel, servant of the living God, is thy God, whom thou servest continually, able to deliver thee from the lions?","ref":"Daniel 6:20","synthesized":"When he reached the den, he cried out in a voice of anguish, “O Daniel, servant of the living God, has your God, whom you serve continually, been able to deliver you from the lions?”","sources":{"KJV":{"text":"And when he came to the den, he cried with a lamentable voice unto Daniel: and the king spake and said to Daniel, O Daniel, servant of the living God, is thy God, whom thou servest continually, able to deliver thee from the lions?"},"BSB":{"text":"When he reached the den, he cried out in a voice of anguish, “O Daniel, servant of the living God, has your God, whom you serve continually, been able to deliver you from the lions?”"}},"definableWords":["voice","servant","living","God","deliver"],"peopleInVerse":["Daniel"]},"21":{"text":"Then said Daniel unto the king, O king, live for ever.","ref":"Daniel 6:21","synthesized":"Then Daniel replied, “O king, may you live forever!","sources":{"KJV":{"text":"Then said Daniel unto the king, O king, live for ever."},"BSB":{"text":"Then Daniel replied, “O king, may you live forever!"}},"definableWords":["king","live"],"peopleInVerse":["Daniel"]},"22":{"text":"My God hath sent his angel, and hath shut the lions’ mouths, that they have not hurt me: forasmuch as before him innocency was found in me; and also before thee, O king, have I done no hurt.","ref":"Daniel 6:22","synthesized":"My God sent His angel and shut the mouths of the lions. They have not hurt me, for I was found innocent in His sight, and I have done no wrong against you, O king.”","sources":{"KJV":{"text":"My God hath sent his angel, and hath shut the lions’ mouths, that they have not hurt me: forasmuch as before him innocency was found in me; and also before thee, O king, have I done no hurt."},"BSB":{"text":"My God sent His angel and shut the mouths of the lions. They have not hurt me, for I was found innocent in His sight, and I have done no wrong against you, O king.”"}},"definableWords":["God","angel","king"],"peopleInVerse":[]},"23":{"text":"Then was the king exceeding glad for him, and commanded that they should take Daniel up out of the den. So Daniel was taken up out of the den, and no manner of hurt was found upon him, because he believed in his God.","ref":"Daniel 6:23","synthesized":"The king was overjoyed and gave orders to lift Daniel out of the den, and when Daniel was lifted out of the den, no wounds whatsoever were found on him, because he had trusted in his God.","sources":{"KJV":{"text":"Then was the king exceeding glad for him, and commanded that they should take Daniel up out of the den. So Daniel was taken up out of the den, and no manner of hurt was found upon him, because he believed in his God."},"BSB":{"text":"The king was overjoyed and gave orders to lift Daniel out of the den, and when Daniel was lifted out of the den, no wounds whatsoever were found on him, because he had trusted in his God."}},"definableWords":["king","God"],"peopleInVerse":["Daniel"]},"24":{"text":"And the king commanded, and they brought those men which had accused Daniel, and they cast them into the den of lions, them, their children, and their wives; and the lions had the mastery of them, and brake all their bones in pieces or ever they came at the bottom of the den.","ref":"Daniel 6:24","synthesized":"At the command of the king, the men who had falsely accused Daniel were brought and thrown into the den of lions—they and their children and wives. And before they had reached the bottom of the den, the lions overpowered them and crushed all their bones.","sources":{"KJV":{"text":"And the king commanded, and they brought those men which had accused Daniel, and they cast them into the den of lions, them, their children, and their wives; and the lions had the mastery of them, and brake all their bones in pieces or ever they came at the bottom of the den."},"BSB":{"text":"At the command of the king, the men who had falsely accused Daniel were brought and thrown into the den of lions—they and their children and wives. And before they had reached the bottom of the den, the lions overpowered them and crushed all their bones."}},"definableWords":["king","men","bones"],"peopleInVerse":["Daniel"]},"25":{"text":"Then king Darius wrote unto all people, nations, and languages, that dwell in all the earth; Peace be multiplied unto you.","ref":"Daniel 6:25","synthesized":"Then King Darius wrote to the people of every nation and language throughout the land: “May your prosperity abound.","sources":{"KJV":{"text":"Then king Darius wrote unto all people, nations, and languages, that dwell in all the earth; Peace be multiplied unto you."},"BSB":{"text":"Then King Darius wrote to the people of every nation and language throughout the land: “May your prosperity abound."}},"definableWords":["King","people","nation","land"],"peopleInVerse":[]},"26":{"text":"I make a decree, That in every dominion of my kingdom men tremble and fear before the God of Daniel: for he is the living God, and stedfast for ever, and his kingdom that which shall not be destroyed, and his dominion shall be even unto the end.","ref":"Daniel 6:26","synthesized":"I hereby decree that in every part of my kingdom, men are to tremble in fear before the God of Daniel:  For He is the living God, and He endures forever; His kingdom will never be destroyed, and His dominion will never end.","sources":{"KJV":{"text":"I make a decree, That in every dominion of my kingdom men tremble and fear before the God of Daniel: for he is the living God, and stedfast for ever, and his kingdom that which shall not be destroyed, and his dominion shall be even unto the end."},"BSB":{"text":"I hereby decree that in every part of my kingdom, men are to tremble in fear before the God of Daniel:  For He is the living God, and He endures forever; His kingdom will never be destroyed, and His dominion will never end."}},"definableWords":["kingdom","men","fear","God","living","dominion"],"peopleInVerse":["Daniel"]},"27":{"text":"He delivereth and rescueth, and he worketh signs and wonders in heaven and in earth, who hath delivered Daniel from the power of the lions.","ref":"Daniel 6:27","synthesized":"He delivers and rescues; He performs signs and wonders in the heavens and on the earth, for He has rescued Daniel from the power of the lions.”","sources":{"KJV":{"text":"He delivereth and rescueth, and he worketh signs and wonders in heaven and in earth, who hath delivered Daniel from the power of the lions."},"BSB":{"text":"He delivers and rescues; He performs signs and wonders in the heavens and on the earth, for He has rescued Daniel from the power of the lions.”"}},"definableWords":["heavens","earth"],"peopleInVerse":["Daniel"]},"28":{"text":"So this Daniel prospered in the reign of Darius, and in the reign of Cyrus the Persian.","ref":"Daniel 6:28","synthesized":"So Daniel prospered during the reign of Darius and the reign of Cyrus the Persian.","sources":{"KJV":{"text":"So this Daniel prospered in the reign of Darius, and in the reign of Cyrus the Persian."},"BSB":{"text":"So Daniel prospered during the reign of Darius and the reign of Cyrus the Persian."}},"definableWords":["reign"],"peopleInVerse":["Daniel","Cyrus"]}}},"7":{"chapter":"7","title":"THE SON OF MAN","verses":{"1":{"text":"In the first year of Belshazzar king of Babylon Daniel had a dream and visions of his head upon his bed: then he wrote the dream, and told the sum of the matters.","ref":"Daniel 7:1","synthesized":"In the first year of the reign of Belshazzar over Babylon, Daniel had a dream, and visions passed through his mind as he lay on his bed. He wrote down the dream, and this is the summary of his account.","sources":{"KJV":{"text":"In the first year of Belshazzar king of Babylon Daniel had a dream and visions of his head upon his bed: then he wrote the dream, and told the sum of the matters."},"BSB":{"text":"In the first year of the reign of Belshazzar over Babylon, Daniel had a dream, and visions passed through his mind as he lay on his bed. He wrote down the dream, and this is the summary of his account."}},"definableWords":["year","reign","Babylon","mind"],"peopleInVerse":["Daniel"],"kingdomLens":"Daniel sees four beasts representing four kingdoms (Babylon, Persia, Greece, Rome). Then 'one like the Son of man came with the clouds of heaven, and came to the Ancient of days... And there was given him dominion, and glory, and a kingdom, that all people, nations, and languages, should serve him' (Dan 7:13-14). This is the most-claimed self-title of Jesus — 'the Son of Man.' At his trial (Matt 26:64), Jesus quotes this verse directly to the high priest. They tear their robes for blasphemy.","cultural":{"title":"The Son of Man comes on the clouds","detail":"'Son of Man' in Aramaic (bar enash) sounded ordinary — 'a human being.' But coming WITH THE CLOUDS to the Ancient of Days is divine territory. Jesus chose the title precisely because it both veiled and revealed his identity.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"Daniel spake and said, I saw in my vision by night, and, behold, the four winds of the heaven strove upon the great sea.","ref":"Daniel 7:2","synthesized":"Daniel declared: “In my vision in the night I looked, and suddenly the four winds of heaven were churning up the great sea.","sources":{"KJV":{"text":"Daniel spake and said, I saw in my vision by night, and, behold, the four winds of the heaven strove upon the great sea."},"BSB":{"text":"Daniel declared: “In my vision in the night I looked, and suddenly the four winds of heaven were churning up the great sea."}},"definableWords":["night","heaven","great","sea"],"peopleInVerse":["Daniel"]},"3":{"text":"And four great beasts came up from the sea, diverse one from another.","ref":"Daniel 7:3","synthesized":"Then four great beasts came up out of the sea, each one different from the others:","sources":{"KJV":{"text":"And four great beasts came up from the sea, diverse one from another."},"BSB":{"text":"Then four great beasts came up out of the sea, each one different from the others:"}},"definableWords":["great","sea","one"],"peopleInVerse":[]},"4":{"text":"The first was like a lion, and had eagle’s wings: I beheld till the wings thereof were plucked, and it was lifted up from the earth, and made stand upon the feet as a man, and a man’s heart was given to it.","ref":"Daniel 7:4","synthesized":"The first beast was like a lion, and it had the wings of an eagle. I watched until its wings were torn off and it was lifted up from the ground and made to stand on two feet like a man, and given the mind of a man.","sources":{"KJV":{"text":"The first was like a lion, and had eagle’s wings: I beheld till the wings thereof were plucked, and it was lifted up from the earth, and made stand upon the feet as a man, and a man’s heart was given to it."},"BSB":{"text":"The first beast was like a lion, and it had the wings of an eagle. I watched until its wings were torn off and it was lifted up from the ground and made to stand on two feet like a man, and given the mind of a man."}},"definableWords":["lion","ground","made","stand","man","mind"],"peopleInVerse":[]},"5":{"text":"And behold another beast, a second, like to a bear, and it raised up itself on one side, and it had three ribs in the mouth of it between the teeth of it: and they said thus unto it, Arise, devour much flesh.","ref":"Daniel 7:5","synthesized":"Suddenly another beast appeared, which looked like a bear. It was raised up on one of its sides, and it had three ribs in its mouth between its teeth. So it was told, ‘Get up and gorge yourself on flesh!’","sources":{"KJV":{"text":"And behold another beast, a second, like to a bear, and it raised up itself on one side, and it had three ribs in the mouth of it between the teeth of it: and they said thus unto it, Arise, devour much flesh."},"BSB":{"text":"Suddenly another beast appeared, which looked like a bear. It was raised up on one of its sides, and it had three ribs in its mouth between its teeth. So it was told, ‘Get up and gorge yourself on flesh!’"}},"definableWords":["one","flesh"],"peopleInVerse":[]},"6":{"text":"After this I beheld, and lo another, like a leopard, which had upon the back of it four wings of a fowl; the beast had also four heads; and dominion was given to it.","ref":"Daniel 7:6","synthesized":"Next, as I watched, another beast appeared. It was like a leopard, and on its back it had four wings like those of a bird. The beast also had four heads, and it was given authority to rule.","sources":{"KJV":{"text":"After this I beheld, and lo another, like a leopard, which had upon the back of it four wings of a fowl; the beast had also four heads; and dominion was given to it."},"BSB":{"text":"Next, as I watched, another beast appeared. It was like a leopard, and on its back it had four wings like those of a bird. The beast also had four heads, and it was given authority to rule."}},"definableWords":["bird","rule"],"peopleInVerse":[]},"7":{"text":"After this I saw in the night visions, and behold a fourth beast, dreadful and terrible, and strong exceedingly; and it had great iron teeth: it devoured and brake in pieces, and stamped the residue with the feet of it: and it was diverse from all the beasts that were before it; and it had ten horns.","ref":"Daniel 7:7","synthesized":"After this, as I watched in my vision in the night, suddenly a fourth beast appeared, and it was terrifying—dreadful and extremely strong—with large iron teeth. It devoured and crushed; then it trampled underfoot whatever was left. It was different from all the beasts before it, and it had ten horns.","sources":{"KJV":{"text":"After this I saw in the night visions, and behold a fourth beast, dreadful and terrible, and strong exceedingly; and it had great iron teeth: it devoured and brake in pieces, and stamped the residue with the feet of it: and it was diverse from all the beasts that were before it; and it had ten horns."},"BSB":{"text":"After this, as I watched in my vision in the night, suddenly a fourth beast appeared, and it was terrifying—dreadful and extremely strong—with large iron teeth. It devoured and crushed; then it trampled underfoot whatever was left. It was different from all the beasts before it, and it had ten horns."}},"definableWords":["night","strong"],"peopleInVerse":[]},"8":{"text":"I considered the horns, and, behold, there came up among them another little horn, before whom there were three of the first horns plucked up by the roots: and, behold, in this horn were eyes like the eyes of man, and a mouth speaking great things.","ref":"Daniel 7:8","synthesized":"While I was contemplating the horns, suddenly another horn, a little one, came up among them, and three of the first horns were uprooted before it. This horn had eyes like those of a man and a mouth that spoke words of arrogance.","sources":{"KJV":{"text":"I considered the horns, and, behold, there came up among them another little horn, before whom there were three of the first horns plucked up by the roots: and, behold, in this horn were eyes like the eyes of man, and a mouth speaking great things."},"BSB":{"text":"While I was contemplating the horns, suddenly another horn, a little one, came up among them, and three of the first horns were uprooted before it. This horn had eyes like those of a man and a mouth that spoke words of arrogance."}},"definableWords":["one","man"],"peopleInVerse":[]},"9":{"text":"I beheld till the thrones were cast down, and the Ancient of days did sit, whose garment was white as snow, and the hair of his head like the pure wool: his throne was like the fiery flame, and his wheels as burning fire.","ref":"Daniel 7:9","synthesized":"As I continued to watch,  thrones were set in place, and the Ancient of Days took His seat. His clothing was white as snow, and the hair of His head was like pure wool. His throne was flaming with fire, and its wheels were all ablaze.","sources":{"KJV":{"text":"I beheld till the thrones were cast down, and the Ancient of days did sit, whose garment was white as snow, and the hair of his head like the pure wool: his throne was like the fiery flame, and his wheels as burning fire."},"BSB":{"text":"As I continued to watch,  thrones were set in place, and the Ancient of Days took His seat. His clothing was white as snow, and the hair of His head was like pure wool. His throne was flaming with fire, and its wheels were all ablaze."}},"definableWords":["days","throne"],"peopleInVerse":[]},"10":{"text":"A fiery stream issued and came forth from before him: thousand thousands ministered unto him, and ten thousand times ten thousand stood before him: the judgment was set, and the books were opened.","ref":"Daniel 7:10","synthesized":"A river of fire was flowing, coming out from His presence. Thousands upon thousands attended Him, and myriads upon myriads stood before Him. The court was convened, and the books were opened.","sources":{"KJV":{"text":"A fiery stream issued and came forth from before him: thousand thousands ministered unto him, and ten thousand times ten thousand stood before him: the judgment was set, and the books were opened."},"BSB":{"text":"A river of fire was flowing, coming out from His presence. Thousands upon thousands attended Him, and myriads upon myriads stood before Him. The court was convened, and the books were opened."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"I beheld then because of the voice of the great words which the horn spake: I beheld even till the beast was slain, and his body destroyed, and given to the burning flame.","ref":"Daniel 7:11","synthesized":"Then I kept watching because of the arrogant words the horn was speaking. As I continued to watch, the beast was slain, and its body was destroyed and thrown into the blazing fire.","sources":{"KJV":{"text":"I beheld then because of the voice of the great words which the horn spake: I beheld even till the beast was slain, and his body destroyed, and given to the burning flame."},"BSB":{"text":"Then I kept watching because of the arrogant words the horn was speaking. As I continued to watch, the beast was slain, and its body was destroyed and thrown into the blazing fire."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"As concerning the rest of the beasts, they had their dominion taken away: yet their lives were prolonged for a season and time.","ref":"Daniel 7:12","synthesized":"As for the rest of the beasts, their dominion was removed, but they were granted an extension of life for a season and a time.","sources":{"KJV":{"text":"As concerning the rest of the beasts, they had their dominion taken away: yet their lives were prolonged for a season and time."},"BSB":{"text":"As for the rest of the beasts, their dominion was removed, but they were granted an extension of life for a season and a time."}},"definableWords":["rest","dominion","life"],"peopleInVerse":[]},"13":{"text":"I saw in the night visions, and, behold, one like the Son of man came with the clouds of heaven, and came to the Ancient of days, and they brought him near before him.","ref":"Daniel 7:13","synthesized":"In my vision in the night I continued to watch,  and I saw One like the Son of Man coming with the clouds of heaven. He approached the Ancient of Days and was led into His presence.","sources":{"KJV":{"text":"I saw in the night visions, and, behold, one like the Son of man came with the clouds of heaven, and came to the Ancient of days, and they brought him near before him."},"BSB":{"text":"In my vision in the night I continued to watch,  and I saw One like the Son of Man coming with the clouds of heaven. He approached the Ancient of Days and was led into His presence."}},"definableWords":["night","saw","one","Son","man","heaven","days"],"peopleInVerse":[]},"14":{"text":"And there was given him dominion, and glory, and a kingdom, that all people, nations, and languages, should serve him: his dominion is an everlasting dominion, which shall not pass away, and his kingdom that which shall not be destroyed.","ref":"Daniel 7:14","synthesized":"And He was given dominion, glory, and kingship, that the people of every nation and language should serve Him. His dominion is an everlasting dominion that will not pass away, and His kingdom is one that will never be destroyed.","sources":{"KJV":{"text":"And there was given him dominion, and glory, and a kingdom, that all people, nations, and languages, should serve him: his dominion is an everlasting dominion, which shall not pass away, and his kingdom that which shall not be destroyed."},"BSB":{"text":"And He was given dominion, glory, and kingship, that the people of every nation and language should serve Him. His dominion is an everlasting dominion that will not pass away, and His kingdom is one that will never be destroyed."}},"definableWords":["dominion","glory","people","nation","everlasting","kingdom","one"],"peopleInVerse":[]},"15":{"text":"I Daniel was grieved in my spirit in the midst of my body, and the visions of my head troubled me.","ref":"Daniel 7:15","synthesized":"I, Daniel, was grieved in my spirit, and the visions in my mind alarmed me.","sources":{"KJV":{"text":"I Daniel was grieved in my spirit in the midst of my body, and the visions of my head troubled me."},"BSB":{"text":"I, Daniel, was grieved in my spirit, and the visions in my mind alarmed me."}},"definableWords":["spirit","mind"],"peopleInVerse":["Daniel"]},"16":{"text":"I came near unto one of them that stood by, and asked him the truth of all this. So he told me, and made me know the interpretation of the things.","ref":"Daniel 7:16","synthesized":"I approached one of those who were standing there, and I asked him the true meaning of all this.  So he told me the interpretation of these things:","sources":{"KJV":{"text":"I came near unto one of them that stood by, and asked him the truth of all this. So he told me, and made me know the interpretation of the things."},"BSB":{"text":"I approached one of those who were standing there, and I asked him the true meaning of all this.  So he told me the interpretation of these things:"}},"definableWords":["one"],"peopleInVerse":[]},"17":{"text":"These great beasts, which are four, are four kings, which shall arise out of the earth.","ref":"Daniel 7:17","synthesized":"‘These four great beasts are four kings who will arise from the earth.","sources":{"KJV":{"text":"These great beasts, which are four, are four kings, which shall arise out of the earth."},"BSB":{"text":"‘These four great beasts are four kings who will arise from the earth."}},"definableWords":["great","kings","earth"],"peopleInVerse":[]},"18":{"text":"But the saints of the most High shall take the kingdom, and possess the kingdom for ever, even for ever and ever.","ref":"Daniel 7:18","synthesized":"But the saints of the Most High will receive the kingdom and possess it forever—yes, forever and ever.’","sources":{"KJV":{"text":"But the saints of the most High shall take the kingdom, and possess the kingdom for ever, even for ever and ever."},"BSB":{"text":"But the saints of the Most High will receive the kingdom and possess it forever—yes, forever and ever.’"}},"definableWords":["kingdom"],"peopleInVerse":[]},"19":{"text":"Then I would know the truth of the fourth beast, which was diverse from all the others, exceeding dreadful, whose teeth were of iron, and his nails of brass; which devoured, brake in pieces, and stamped the residue with his feet;","ref":"Daniel 7:19","synthesized":"Then I wanted to know the true meaning of the fourth beast, which was different from all the others—extremely terrifying—devouring and crushing with iron teeth and bronze claws, then trampling underfoot whatever was left.","sources":{"KJV":{"text":"Then I would know the truth of the fourth beast, which was diverse from all the others, exceeding dreadful, whose teeth were of iron, and his nails of brass; which devoured, brake in pieces, and stamped the residue with his feet;"},"BSB":{"text":"Then I wanted to know the true meaning of the fourth beast, which was different from all the others—extremely terrifying—devouring and crushing with iron teeth and bronze claws, then trampling underfoot whatever was left."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"And of the ten horns that were in his head, and of the other which came up, and before whom three fell; even of that horn that had eyes, and a mouth that spake very great things, whose look was more stout than his fellows.","ref":"Daniel 7:20","synthesized":"I also wanted to know about the ten horns on its head and the other horn that came up, before which three of them fell—the horn whose appearance was more imposing than the others, with eyes and with a mouth that spoke words of arrogance.","sources":{"KJV":{"text":"And of the ten horns that were in his head, and of the other which came up, and before whom three fell; even of that horn that had eyes, and a mouth that spake very great things, whose look was more stout than his fellows."},"BSB":{"text":"I also wanted to know about the ten horns on its head and the other horn that came up, before which three of them fell—the horn whose appearance was more imposing than the others, with eyes and with a mouth that spoke words of arrogance."}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"I beheld, and the same horn made war with the saints, and prevailed against them;","ref":"Daniel 7:21","synthesized":"As I watched, this horn was waging war against the saints and prevailing against them,","sources":{"KJV":{"text":"I beheld, and the same horn made war with the saints, and prevailed against them;"},"BSB":{"text":"As I watched, this horn was waging war against the saints and prevailing against them,"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Until the Ancient of days came, and judgment was given to the saints of the most High; and the time came that the saints possessed the kingdom.","ref":"Daniel 7:22","synthesized":"until the Ancient of Days arrived and pronounced judgment in favor of the saints of the Most High, and the time came for them to possess the kingdom.","sources":{"KJV":{"text":"Until the Ancient of days came, and judgment was given to the saints of the most High; and the time came that the saints possessed the kingdom."},"BSB":{"text":"until the Ancient of Days arrived and pronounced judgment in favor of the saints of the Most High, and the time came for them to possess the kingdom."}},"definableWords":["days","judgment","kingdom"],"peopleInVerse":[]},"23":{"text":"Thus he said, The fourth beast shall be the fourth kingdom upon earth, which shall be diverse from all kingdoms, and shall devour the whole earth, and shall tread it down, and break it in pieces.","ref":"Daniel 7:23","synthesized":"This is what he said: ‘The fourth beast is a fourth kingdom that will appear on the earth, different from all the other kingdoms, and it will devour the whole earth, trample it down, and crush it.","sources":{"KJV":{"text":"Thus he said, The fourth beast shall be the fourth kingdom upon earth, which shall be diverse from all kingdoms, and shall devour the whole earth, and shall tread it down, and break it in pieces."},"BSB":{"text":"This is what he said: ‘The fourth beast is a fourth kingdom that will appear on the earth, different from all the other kingdoms, and it will devour the whole earth, trample it down, and crush it."}},"definableWords":["kingdom","earth"],"peopleInVerse":[]},"24":{"text":"And the ten horns out of this kingdom are ten kings that shall arise: and another shall rise after them; and he shall be diverse from the first, and he shall subdue three kings.","ref":"Daniel 7:24","synthesized":"And the ten horns are ten kings who will rise from this kingdom. After them another king, different from the earlier ones, will rise and subdue three kings.","sources":{"KJV":{"text":"And the ten horns out of this kingdom are ten kings that shall arise: and another shall rise after them; and he shall be diverse from the first, and he shall subdue three kings."},"BSB":{"text":"And the ten horns are ten kings who will rise from this kingdom. After them another king, different from the earlier ones, will rise and subdue three kings."}},"definableWords":["kings","kingdom","king","subdue"],"peopleInVerse":[]},"25":{"text":"And he shall speak great words against the most High, and shall wear out the saints of the most High, and think to change times and laws: and they shall be given into his hand until a time and times and the dividing of time.","ref":"Daniel 7:25","synthesized":"He will speak out against the Most High and oppress the saints of the Most High, intending to change the appointed times and laws; and the saints will be given into his hand for a time, and times, and half a time.","sources":{"KJV":{"text":"And he shall speak great words against the most High, and shall wear out the saints of the most High, and think to change times and laws: and they shall be given into his hand until a time and times and the dividing of time."},"BSB":{"text":"He will speak out against the Most High and oppress the saints of the Most High, intending to change the appointed times and laws; and the saints will be given into his hand for a time, and times, and half a time."}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"But the judgment shall sit, and they shall take away his dominion, to consume and to destroy it unto the end.","ref":"Daniel 7:26","synthesized":"But the court will convene, and his dominion will be taken away and completely destroyed forever.","sources":{"KJV":{"text":"But the judgment shall sit, and they shall take away his dominion, to consume and to destroy it unto the end."},"BSB":{"text":"But the court will convene, and his dominion will be taken away and completely destroyed forever."}},"definableWords":["dominion"],"peopleInVerse":[]},"27":{"text":"And the kingdom and dominion, and the greatness of the kingdom under the whole heaven, shall be given to the people of the saints of the most High, whose kingdom is an everlasting kingdom, and all dominions shall serve and obey him.","ref":"Daniel 7:27","synthesized":"Then the sovereignty, dominion, and greatness of the kingdoms under all of heaven will be given to the people, the saints of the Most High. His kingdom will be an everlasting kingdom, and all rulers will serve and obey Him.’","sources":{"KJV":{"text":"And the kingdom and dominion, and the greatness of the kingdom under the whole heaven, shall be given to the people of the saints of the most High, whose kingdom is an everlasting kingdom, and all dominions shall serve and obey him."},"BSB":{"text":"Then the sovereignty, dominion, and greatness of the kingdoms under all of heaven will be given to the people, the saints of the Most High. His kingdom will be an everlasting kingdom, and all rulers will serve and obey Him.’"}},"definableWords":["dominion","heaven","people","kingdom","everlasting"],"peopleInVerse":[]},"28":{"text":"Hitherto is the end of the matter. As for me Daniel, my cogitations much troubled me, and my countenance changed in me: but I kept the matter in my heart.","ref":"Daniel 7:28","synthesized":"Thus ends the matter. As for me, Daniel, my thoughts troubled me greatly, and my face turned pale. But I kept the matter to myself.”","sources":{"KJV":{"text":"Hitherto is the end of the matter. As for me Daniel, my cogitations much troubled me, and my countenance changed in me: but I kept the matter in my heart."},"BSB":{"text":"Thus ends the matter. As for me, Daniel, my thoughts troubled me greatly, and my face turned pale. But I kept the matter to myself.”"}},"definableWords":[],"peopleInVerse":["Daniel"]}}},"8":{"chapter":"8","title":"THE RAM AND THE GOAT — PERSIA AND GREECE","verses":{"1":{"text":"In the third year of the reign of king Belshazzar a vision appeared unto me, even unto me Daniel, after that which appeared unto me at the first.","ref":"Daniel 8:1","synthesized":"In the third year of the reign of King Belshazzar, a vision appeared to me, Daniel, subsequent to the one that had appeared to me earlier.","sources":{"KJV":{"text":"In the third year of the reign of king Belshazzar a vision appeared unto me, even unto me Daniel, after that which appeared unto me at the first."},"BSB":{"text":"In the third year of the reign of King Belshazzar, a vision appeared to me, Daniel, subsequent to the one that had appeared to me earlier."}},"definableWords":["year","reign","King","one"],"peopleInVerse":["Daniel"]},"2":{"text":"And I saw in a vision; and it came to pass, when I saw, that I was at Shushan in the palace, which is in the province of Elam; and I saw in a vision, and I was by the river of Ulai.","ref":"Daniel 8:2","synthesized":"And in the vision I saw myself in the citadel of Susa, in the province of Elam. I saw in the vision that I was beside the Ulai Canal.","sources":{"KJV":{"text":"And I saw in a vision; and it came to pass, when I saw, that I was at Shushan in the palace, which is in the province of Elam; and I saw in a vision, and I was by the river of Ulai."},"BSB":{"text":"And in the vision I saw myself in the citadel of Susa, in the province of Elam. I saw in the vision that I was beside the Ulai Canal."}},"definableWords":["saw"],"peopleInVerse":[]},"3":{"text":"Then I lifted up mine eyes, and saw, and, behold, there stood before the river a ram which had two horns: and the two horns were high; but one was higher than the other, and the higher came up last.","ref":"Daniel 8:3","synthesized":"Then I lifted up my eyes and saw a ram with two horns standing beside the canal. The horns were long, but one was longer than the other, and the longer one grew up later.","sources":{"KJV":{"text":"Then I lifted up mine eyes, and saw, and, behold, there stood before the river a ram which had two horns: and the two horns were high; but one was higher than the other, and the higher came up last."},"BSB":{"text":"Then I lifted up my eyes and saw a ram with two horns standing beside the canal. The horns were long, but one was longer than the other, and the longer one grew up later."}},"definableWords":["saw","one"],"peopleInVerse":[]},"4":{"text":"I saw the ram pushing westward, and northward, and southward; so that no beasts might stand before him, neither was there any that could deliver out of his hand; but he did according to his will, and became great.","ref":"Daniel 8:4","synthesized":"I saw the ram charging toward the west and the north and the south. No animal could stand against him, and there was no deliverance from his power. He did as he pleased and became great.","sources":{"KJV":{"text":"I saw the ram pushing westward, and northward, and southward; so that no beasts might stand before him, neither was there any that could deliver out of his hand; but he did according to his will, and became great."},"BSB":{"text":"I saw the ram charging toward the west and the north and the south. No animal could stand against him, and there was no deliverance from his power. He did as he pleased and became great."}},"definableWords":["saw","stand","great"],"peopleInVerse":[]},"5":{"text":"And as I was considering, behold, an he goat came from the west on the face of the whole earth, and touched not the ground: and the goat had a notable horn between his eyes.","ref":"Daniel 8:5","synthesized":"As I was contemplating all this, suddenly a goat with a prominent horn between his eyes came out of the west, crossing the surface of the entire earth without touching the ground.","sources":{"KJV":{"text":"And as I was considering, behold, an he goat came from the west on the face of the whole earth, and touched not the ground: and the goat had a notable horn between his eyes."},"BSB":{"text":"As I was contemplating all this, suddenly a goat with a prominent horn between his eyes came out of the west, crossing the surface of the entire earth without touching the ground."}},"definableWords":["earth","ground"],"peopleInVerse":[]},"6":{"text":"And he came to the ram that had two horns, which I had seen standing before the river, and ran unto him in the fury of his power.","ref":"Daniel 8:6","synthesized":"He came toward the two-horned ram I had seen standing beside the canal and rushed at him with furious power.","sources":{"KJV":{"text":"And he came to the ram that had two horns, which I had seen standing before the river, and ran unto him in the fury of his power."},"BSB":{"text":"He came toward the two-horned ram I had seen standing beside the canal and rushed at him with furious power."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"And I saw him come close unto the ram, and he was moved with choler against him, and smote the ram, and brake his two horns: and there was no power in the ram to stand before him, but he cast him down to the ground, and stamped upon him: and there was none that could deliver the ram out of his hand.","ref":"Daniel 8:7","synthesized":"I saw him approach the ram in a rage against him, and he struck the ram and shattered his two horns. The ram was powerless to stand against him, and the goat threw him to the ground and trampled him, and no one could deliver the ram from his power.","sources":{"KJV":{"text":"And I saw him come close unto the ram, and he was moved with choler against him, and smote the ram, and brake his two horns: and there was no power in the ram to stand before him, but he cast him down to the ground, and stamped upon him: and there was none that could deliver the ram out of his hand."},"BSB":{"text":"I saw him approach the ram in a rage against him, and he struck the ram and shattered his two horns. The ram was powerless to stand against him, and the goat threw him to the ground and trampled him, and no one could deliver the ram from his power."}},"definableWords":["saw","stand","ground","one","deliver"],"peopleInVerse":[]},"8":{"text":"Therefore the he goat waxed very great: and when he was strong, the great horn was broken; and for it came up four notable ones toward the four winds of heaven.","ref":"Daniel 8:8","synthesized":"Thus the goat became very great, but at the height of his power, his large horn was broken off, and four prominent horns came up in its place, pointing toward the four winds of heaven.","sources":{"KJV":{"text":"Therefore the he goat waxed very great: and when he was strong, the great horn was broken; and for it came up four notable ones toward the four winds of heaven."},"BSB":{"text":"Thus the goat became very great, but at the height of his power, his large horn was broken off, and four prominent horns came up in its place, pointing toward the four winds of heaven."}},"definableWords":["great","heaven"],"peopleInVerse":[]},"9":{"text":"And out of one of them came forth a little horn, which waxed exceeding great, toward the south, and toward the east, and toward the pleasant land.","ref":"Daniel 8:9","synthesized":"From one of these horns a little horn emerged and grew extensively toward the south and the east and toward the Beautiful Land.","sources":{"KJV":{"text":"And out of one of them came forth a little horn, which waxed exceeding great, toward the south, and toward the east, and toward the pleasant land."},"BSB":{"text":"From one of these horns a little horn emerged and grew extensively toward the south and the east and toward the Beautiful Land."}},"definableWords":["one","land"],"peopleInVerse":[]},"10":{"text":"And it waxed great, even to the host of heaven; and it cast down some of the host and of the stars to the ground, and stamped upon them.","ref":"Daniel 8:10","synthesized":"It grew as high as the host of heaven, and it cast down some of the host and some of the stars to the earth, and trampled them.","sources":{"KJV":{"text":"And it waxed great, even to the host of heaven; and it cast down some of the host and of the stars to the ground, and stamped upon them."},"BSB":{"text":"It grew as high as the host of heaven, and it cast down some of the host and some of the stars to the earth, and trampled them."}},"definableWords":["heaven","earth"],"peopleInVerse":[]},"11":{"text":"Yea, he magnified himself even to the prince of the host, and by him the daily sacrifice was taken away, and the place of his sanctuary was cast down.","ref":"Daniel 8:11","synthesized":"It magnified itself, even to the Prince of the host; it removed His daily sacrifice and overthrew the place of His sanctuary.","sources":{"KJV":{"text":"Yea, he magnified himself even to the prince of the host, and by him the daily sacrifice was taken away, and the place of his sanctuary was cast down."},"BSB":{"text":"It magnified itself, even to the Prince of the host; it removed His daily sacrifice and overthrew the place of His sanctuary."}},"definableWords":["prince","sacrifice"],"peopleInVerse":[]},"12":{"text":"And an host was given him against the daily sacrifice by reason of transgression, and it cast down the truth to the ground; and it practised, and prospered.","ref":"Daniel 8:12","synthesized":"And in the rebellion, the host and the daily sacrifice were given over to the horn, and it flung truth to the ground and prospered in whatever it did.","sources":{"KJV":{"text":"And an host was given him against the daily sacrifice by reason of transgression, and it cast down the truth to the ground; and it practised, and prospered."},"BSB":{"text":"And in the rebellion, the host and the daily sacrifice were given over to the horn, and it flung truth to the ground and prospered in whatever it did."}},"definableWords":["sacrifice","truth","ground"],"peopleInVerse":[]},"13":{"text":"Then I heard one saint speaking, and another saint said unto that certain saint which spake, How long shall be the vision concerning the daily sacrifice, and the transgression of desolation, to give both the sanctuary and the host to be trodden under foot?","ref":"Daniel 8:13","synthesized":"Then I heard a holy one speaking, and another holy one said to him, “How long until the fulfillment of the vision of the daily sacrifice, the rebellion that causes desolation, and the surrender of the sanctuary and of the host to be trampled?”","sources":{"KJV":{"text":"Then I heard one saint speaking, and another saint said unto that certain saint which spake, How long shall be the vision concerning the daily sacrifice, and the transgression of desolation, to give both the sanctuary and the host to be trodden under foot?"},"BSB":{"text":"Then I heard a holy one speaking, and another holy one said to him, “How long until the fulfillment of the vision of the daily sacrifice, the rebellion that causes desolation, and the surrender of the sanctuary and of the host to be trampled?”"}},"definableWords":["holy","one","sacrifice"],"peopleInVerse":[]},"14":{"text":"And he said unto me, Unto two thousand and three hundred days; then shall the sanctuary be cleansed.","ref":"Daniel 8:14","synthesized":"He said to me, “It will take 2,300 evenings and mornings; then the sanctuary will be properly restored.”","sources":{"KJV":{"text":"And he said unto me, Unto two thousand and three hundred days; then shall the sanctuary be cleansed."},"BSB":{"text":"He said to me, “It will take 2,300 evenings and mornings; then the sanctuary will be properly restored.”"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And it came to pass, when I, even I Daniel, had seen the vision, and sought for the meaning, then, behold, there stood before me as the appearance of a man.","ref":"Daniel 8:15","synthesized":"While I, Daniel, was watching the vision and trying to understand it, there stood before me one having the appearance of a man.","sources":{"KJV":{"text":"And it came to pass, when I, even I Daniel, had seen the vision, and sought for the meaning, then, behold, there stood before me as the appearance of a man."},"BSB":{"text":"While I, Daniel, was watching the vision and trying to understand it, there stood before me one having the appearance of a man."}},"definableWords":["one","man"],"peopleInVerse":["Daniel"]},"16":{"text":"And I heard a man’s voice between the banks of Ulai, which called, and said, Gabriel, make this man to understand the vision.","ref":"Daniel 8:16","synthesized":"And I heard the voice of a man calling from between the banks of the Ulai: “Gabriel, explain the vision to this man.”","sources":{"KJV":{"text":"And I heard a man’s voice between the banks of Ulai, which called, and said, Gabriel, make this man to understand the vision."},"BSB":{"text":"And I heard the voice of a man calling from between the banks of the Ulai: “Gabriel, explain the vision to this man.”"}},"definableWords":["voice","man"],"peopleInVerse":[]},"17":{"text":"So he came near where I stood: and when he came, I was afraid, and fell upon my face: but he said unto me, Understand, O son of man: for at the time of the end shall be the vision.","ref":"Daniel 8:17","synthesized":"As he came near to where I stood, I was terrified and fell facedown.  “Son of man,” he said to me, “understand that the vision concerns the time of the end.”","sources":{"KJV":{"text":"So he came near where I stood: and when he came, I was afraid, and fell upon my face: but he said unto me, Understand, O son of man: for at the time of the end shall be the vision."},"BSB":{"text":"As he came near to where I stood, I was terrified and fell facedown.  “Son of man,” he said to me, “understand that the vision concerns the time of the end.”"}},"definableWords":["Son","man"],"peopleInVerse":[]},"18":{"text":"Now as he was speaking with me, I was in a deep sleep on my face toward the ground: but he touched me, and set me upright.","ref":"Daniel 8:18","synthesized":"While he was speaking with me, I fell into a deep sleep, with my face to the ground.  Then he touched me, helped me to my feet,","sources":{"KJV":{"text":"Now as he was speaking with me, I was in a deep sleep on my face toward the ground: but he touched me, and set me upright."},"BSB":{"text":"While he was speaking with me, I fell into a deep sleep, with my face to the ground.  Then he touched me, helped me to my feet,"}},"definableWords":["deep","ground"],"peopleInVerse":[]},"19":{"text":"And he said, Behold, I will make thee know what shall be in the last end of the indignation: for at the time appointed the end shall be.","ref":"Daniel 8:19","synthesized":"and said, “Behold, I will make known to you what will happen in the latter time of wrath, because it concerns the appointed time of the end.","sources":{"KJV":{"text":"And he said, Behold, I will make thee know what shall be in the last end of the indignation: for at the time appointed the end shall be."},"BSB":{"text":"and said, “Behold, I will make known to you what will happen in the latter time of wrath, because it concerns the appointed time of the end."}},"definableWords":["make","wrath"],"peopleInVerse":[]},"20":{"text":"The ram which thou sawest having two horns are the kings of Media and Persia.","ref":"Daniel 8:20","synthesized":"The two-horned ram that you saw represents the kings of Media and Persia.","sources":{"KJV":{"text":"The ram which thou sawest having two horns are the kings of Media and Persia."},"BSB":{"text":"The two-horned ram that you saw represents the kings of Media and Persia."}},"definableWords":["saw","kings"],"peopleInVerse":[]},"21":{"text":"And the rough goat is the king of Grecia: and the great horn that is between his eyes is the first king.","ref":"Daniel 8:21","synthesized":"The shaggy goat represents the king of Greece, and the large horn between his eyes is the first king.","sources":{"KJV":{"text":"And the rough goat is the king of Grecia: and the great horn that is between his eyes is the first king."},"BSB":{"text":"The shaggy goat represents the king of Greece, and the large horn between his eyes is the first king."}},"definableWords":["king","King"],"peopleInVerse":[]},"22":{"text":"Now that being broken, whereas four stood up for it, four kingdoms shall stand up out of the nation, but not in his power.","ref":"Daniel 8:22","synthesized":"The four horns that replaced the broken one represent four kingdoms that will rise from that nation, but will not have the same power.","sources":{"KJV":{"text":"Now that being broken, whereas four stood up for it, four kingdoms shall stand up out of the nation, but not in his power."},"BSB":{"text":"The four horns that replaced the broken one represent four kingdoms that will rise from that nation, but will not have the same power."}},"definableWords":["one","nation"],"peopleInVerse":[]},"23":{"text":"And in the latter time of their kingdom, when the transgressors are come to the full, a king of fierce countenance, and understanding dark sentences, shall stand up.","ref":"Daniel 8:23","synthesized":"In the latter part of their reign, when the rebellion has reached its full measure, an insolent king, skilled in intrigue, will come to the throne.","sources":{"KJV":{"text":"And in the latter time of their kingdom, when the transgressors are come to the full, a king of fierce countenance, and understanding dark sentences, shall stand up."},"BSB":{"text":"In the latter part of their reign, when the rebellion has reached its full measure, an insolent king, skilled in intrigue, will come to the throne."}},"definableWords":["reign","king","throne"],"peopleInVerse":[]},"24":{"text":"And his power shall be mighty, but not by his own power: and he shall destroy wonderfully, and shall prosper, and practise, and shall destroy the mighty and the holy people.","ref":"Daniel 8:24","synthesized":"His power will be great, but it will not be his own. He will cause terrible destruction and succeed in whatever he does. He will destroy the mighty men along with the holy people.","sources":{"KJV":{"text":"And his power shall be mighty, but not by his own power: and he shall destroy wonderfully, and shall prosper, and practise, and shall destroy the mighty and the holy people."},"BSB":{"text":"His power will be great, but it will not be his own. He will cause terrible destruction and succeed in whatever he does. He will destroy the mighty men along with the holy people."}},"definableWords":["great","mighty","men","holy","people"],"peopleInVerse":[]},"25":{"text":"And through his policy also he shall cause craft to prosper in his hand; and he shall magnify himself in his heart, and by peace shall destroy many: he shall also stand up against the Prince of princes; but he shall be broken without hand.","ref":"Daniel 8:25","synthesized":"Through his craft and by his hand, he will cause deceit to prosper, and in his own mind he will make himself great. In a time of peace he will destroy many, and he will even stand against the Prince of princes. Yet he will be broken off, but not by human hands.","sources":{"KJV":{"text":"And through his policy also he shall cause craft to prosper in his hand; and he shall magnify himself in his heart, and by peace shall destroy many: he shall also stand up against the Prince of princes; but he shall be broken without hand."},"BSB":{"text":"Through his craft and by his hand, he will cause deceit to prosper, and in his own mind he will make himself great. In a time of peace he will destroy many, and he will even stand against the Prince of princes. Yet he will be broken off, but not by human hands."}},"definableWords":["mind","make","great","peace","stand","prince"],"peopleInVerse":[]},"26":{"text":"And the vision of the evening and the morning which was told is true: wherefore shut thou up the vision; for it shall be for many days.","ref":"Daniel 8:26","synthesized":"The vision of the evenings and the mornings that has been spoken is true. Now you must seal up the vision, for it concerns the distant future.”","sources":{"KJV":{"text":"And the vision of the evening and the morning which was told is true: wherefore shut thou up the vision; for it shall be for many days."},"BSB":{"text":"The vision of the evenings and the mornings that has been spoken is true. Now you must seal up the vision, for it concerns the distant future.”"}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"And I Daniel fainted, and was sick certain days; afterward I rose up, and did the king’s business; and I was astonished at the vision, but none understood it.","ref":"Daniel 8:27","synthesized":"I, Daniel, was exhausted and lay ill for days. Then I got up and went about the king’s business. I was confounded by the vision; it was beyond understanding.","sources":{"KJV":{"text":"And I Daniel fainted, and was sick certain days; afterward I rose up, and did the king’s business; and I was astonished at the vision, but none understood it."},"BSB":{"text":"I, Daniel, was exhausted and lay ill for days. Then I got up and went about the king’s business. I was confounded by the vision; it was beyond understanding."}},"definableWords":["days","king"],"peopleInVerse":["Daniel"]}}},"9":{"chapter":"9","title":"DANIEL'S PRAYER AND 70 WEEKS","verses":{"1":{"text":"In the first year of Darius the son of Ahasuerus, of the seed of the Medes, which was made king over the realm of the Chaldeans;","ref":"Daniel 9:1","synthesized":"In the first year of Darius son of Xerxes, a Mede by descent, who was made ruler over the kingdom of the Chaldeans—","sources":{"KJV":{"text":"In the first year of Darius the son of Ahasuerus, of the seed of the Medes, which was made king over the realm of the Chaldeans;"},"BSB":{"text":"In the first year of Darius son of Xerxes, a Mede by descent, who was made ruler over the kingdom of the Chaldeans—"}},"definableWords":["year","son","made","ruler","kingdom"],"peopleInVerse":[]},"2":{"text":"In the first year of his reign I Daniel understood by books the number of the years, whereof the word of the LORD came to Jeremiah the prophet, that he would accomplish seventy years in the desolations of Jerusalem.","ref":"Daniel 9:2","synthesized":"in the first year of his reign, I, Daniel, understood from the sacred books, according to the word of the LORD to Jeremiah the prophet, that the desolation of Jerusalem would last seventy years.","sources":{"KJV":{"text":"In the first year of his reign I Daniel understood by books the number of the years, whereof the word of the LORD came to Jeremiah the prophet, that he would accomplish seventy years in the desolations of Jerusalem."},"BSB":{"text":"in the first year of his reign, I, Daniel, understood from the sacred books, according to the word of the LORD to Jeremiah the prophet, that the desolation of Jerusalem would last seventy years."}},"definableWords":["year","reign","word","LORD","prophet","Jerusalem","years"],"peopleInVerse":["Daniel","Jeremiah"]},"3":{"text":"And I set my face unto the Lord God, to seek by prayer and supplications, with fasting, and sackcloth, and ashes:","ref":"Daniel 9:3","synthesized":"So I turned my attention to the Lord God to seek Him by prayer and petition, with fasting, sackcloth, and ashes.","sources":{"KJV":{"text":"And I set my face unto the Lord God, to seek by prayer and supplications, with fasting, and sackcloth, and ashes:"},"BSB":{"text":"So I turned my attention to the Lord God to seek Him by prayer and petition, with fasting, sackcloth, and ashes."}},"definableWords":["Lord","God","seek","prayer"],"peopleInVerse":[]},"4":{"text":"And I prayed unto the LORD my God, and made my confession, and said, O Lord, the great and dreadful God, keeping the covenant and mercy to them that love him, and to them that keep his commandments;","ref":"Daniel 9:4","synthesized":"And I prayed to the LORD my God and confessed, “O, Lord, the great and awesome God, who keeps His covenant of loving devotion to those who love Him and keep His commandments,","sources":{"KJV":{"text":"And I prayed unto the LORD my God, and made my confession, and said, O Lord, the great and dreadful God, keeping the covenant and mercy to them that love him, and to them that keep his commandments;"},"BSB":{"text":"And I prayed to the LORD my God and confessed, “O, Lord, the great and awesome God, who keeps His covenant of loving devotion to those who love Him and keep His commandments,"}},"definableWords":["LORD","God","Lord","great","covenant","love","keep"],"peopleInVerse":[]},"5":{"text":"We have sinned, and have committed iniquity, and have done wickedly, and have rebelled, even by departing from thy precepts and from thy judgments:","ref":"Daniel 9:5","synthesized":"we have sinned and done wrong. We have acted wickedly and rebelled. We have turned away from Your commandments and ordinances.","sources":{"KJV":{"text":"We have sinned, and have committed iniquity, and have done wickedly, and have rebelled, even by departing from thy precepts and from thy judgments:"},"BSB":{"text":"we have sinned and done wrong. We have acted wickedly and rebelled. We have turned away from Your commandments and ordinances."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Neither have we hearkened unto thy servants the prophets, which spake in thy name to our kings, our princes, and our fathers, and to all the people of the land.","ref":"Daniel 9:6","synthesized":"We have not listened to Your servants the prophets, who spoke in Your name to our kings, leaders, and fathers, and to all the people of the land.","sources":{"KJV":{"text":"Neither have we hearkened unto thy servants the prophets, which spake in thy name to our kings, our princes, and our fathers, and to all the people of the land."},"BSB":{"text":"We have not listened to Your servants the prophets, who spoke in Your name to our kings, leaders, and fathers, and to all the people of the land."}},"definableWords":["servants","name","kings","fathers","people","land"],"peopleInVerse":[]},"7":{"text":"O LORD, righteousness belongeth unto thee, but unto us confusion of faces, as at this day; to the men of Judah, and to the inhabitants of Jerusalem, and unto all Israel, that are near, and that are far off, through all the countries whither thou hast driven them, because of their trespass that they have trespassed against thee.","ref":"Daniel 9:7","synthesized":"To You, O Lord, belongs righteousness, but this day we are covered with shame—the men of Judah, the people of Jerusalem, and all Israel near and far, in all the countries to which You have driven us because of our unfaithfulness to You.","sources":{"KJV":{"text":"O LORD, righteousness belongeth unto thee, but unto us confusion of faces, as at this day; to the men of Judah, and to the inhabitants of Jerusalem, and unto all Israel, that are near, and that are far off, through all the countries whither thou hast driven them, because of their trespass that they have trespassed against thee."},"BSB":{"text":"To You, O Lord, belongs righteousness, but this day we are covered with shame—the men of Judah, the people of Jerusalem, and all Israel near and far, in all the countries to which You have driven us because of our unfaithfulness to You."}},"definableWords":["Lord","righteousness","day","men","Judah","people","Jerusalem","Israel"],"peopleInVerse":[]},"8":{"text":"O Lord, to us belongeth confusion of face, to our kings, to our princes, and to our fathers, because we have sinned against thee.","ref":"Daniel 9:8","synthesized":"O LORD, we are covered with shame—our kings, our leaders, and our fathers—because we have sinned against You.","sources":{"KJV":{"text":"O Lord, to us belongeth confusion of face, to our kings, to our princes, and to our fathers, because we have sinned against thee."},"BSB":{"text":"O LORD, we are covered with shame—our kings, our leaders, and our fathers—because we have sinned against You."}},"definableWords":["LORD","kings","fathers"],"peopleInVerse":[]},"9":{"text":"To the Lord our God belong mercies and forgivenesses, though we have rebelled against him;","ref":"Daniel 9:9","synthesized":"To the Lord our God belong compassion and forgiveness, even though we have rebelled against Him","sources":{"KJV":{"text":"To the Lord our God belong mercies and forgivenesses, though we have rebelled against him;"},"BSB":{"text":"To the Lord our God belong compassion and forgiveness, even though we have rebelled against Him"}},"definableWords":["Lord","God"],"peopleInVerse":[]},"10":{"text":"Neither have we obeyed the voice of the LORD our God, to walk in his laws, which he set before us by his servants the prophets.","ref":"Daniel 9:10","synthesized":"and have not obeyed the voice of the LORD our God to walk in His laws, which He set before us through His servants the prophets.","sources":{"KJV":{"text":"Neither have we obeyed the voice of the LORD our God, to walk in his laws, which he set before us by his servants the prophets."},"BSB":{"text":"and have not obeyed the voice of the LORD our God to walk in His laws, which He set before us through His servants the prophets."}},"definableWords":["voice","LORD","God","walk","servants"],"peopleInVerse":[]},"11":{"text":"Yea, all Israel have transgressed thy law, even by departing, that they might not obey thy voice; therefore the curse is poured upon us, and the oath that is written in the law of Moses the servant of God, because we have sinned against him.","ref":"Daniel 9:11","synthesized":"All Israel has transgressed Your law and turned away, refusing to obey Your voice; so the oath and the curse written in the Law of Moses the servant of God has been poured out on us, because we have sinned against You.","sources":{"KJV":{"text":"Yea, all Israel have transgressed thy law, even by departing, that they might not obey thy voice; therefore the curse is poured upon us, and the oath that is written in the law of Moses the servant of God, because we have sinned against him."},"BSB":{"text":"All Israel has transgressed Your law and turned away, refusing to obey Your voice; so the oath and the curse written in the Law of Moses the servant of God has been poured out on us, because we have sinned against You."}},"definableWords":["Israel","law","voice","curse","servant","God"],"peopleInVerse":["Moses"]},"12":{"text":"And he hath confirmed his words, which he spake against us, and against our judges that judged us, by bringing upon us a great evil: for under the whole heaven hath not been done as hath been done upon Jerusalem.","ref":"Daniel 9:12","synthesized":"You have carried out the words spoken against us and against our rulers by bringing upon us a great disaster. For under all of heaven, nothing has ever been done like what has been done to Jerusalem.","sources":{"KJV":{"text":"And he hath confirmed his words, which he spake against us, and against our judges that judged us, by bringing upon us a great evil: for under the whole heaven hath not been done as hath been done upon Jerusalem."},"BSB":{"text":"You have carried out the words spoken against us and against our rulers by bringing upon us a great disaster. For under all of heaven, nothing has ever been done like what has been done to Jerusalem."}},"definableWords":["great","heaven","Jerusalem"],"peopleInVerse":[]},"13":{"text":"As it is written in the law of Moses, all this evil is come upon us: yet made we not our prayer before the LORD our God, that we might turn from our iniquities, and understand thy truth.","ref":"Daniel 9:13","synthesized":"Just as it is written in the Law of Moses, all this disaster has come upon us, yet we have not sought the favor of the LORD our God by turning from our iniquities and giving attention to Your truth.","sources":{"KJV":{"text":"As it is written in the law of Moses, all this evil is come upon us: yet made we not our prayer before the LORD our God, that we might turn from our iniquities, and understand thy truth."},"BSB":{"text":"Just as it is written in the Law of Moses, all this disaster has come upon us, yet we have not sought the favor of the LORD our God by turning from our iniquities and giving attention to Your truth."}},"definableWords":["law","LORD","God","truth"],"peopleInVerse":["Moses"]},"14":{"text":"Therefore hath the LORD watched upon the evil, and brought it upon us: for the LORD our God is righteous in all his works which he doeth: for we obeyed not his voice.","ref":"Daniel 9:14","synthesized":"Therefore the LORD has kept the calamity in store and brought it upon us. For the LORD our God is righteous in all He does; yet we have not obeyed His voice.","sources":{"KJV":{"text":"Therefore hath the LORD watched upon the evil, and brought it upon us: for the LORD our God is righteous in all his works which he doeth: for we obeyed not his voice."},"BSB":{"text":"Therefore the LORD has kept the calamity in store and brought it upon us. For the LORD our God is righteous in all He does; yet we have not obeyed His voice."}},"definableWords":["LORD","Lord","God","righteous","voice"],"peopleInVerse":[]},"15":{"text":"And now, O Lord our God, that hast brought thy people forth out of the land of Egypt with a mighty hand, and hast gotten thee renown, as at this day; we have sinned, we have done wickedly.","ref":"Daniel 9:15","synthesized":"Now, O Lord our God, who brought Your people out of the land of Egypt with a mighty hand, and who made for Yourself a name renowned to this day, we have sinned; we have acted wickedly.","sources":{"KJV":{"text":"And now, O Lord our God, that hast brought thy people forth out of the land of Egypt with a mighty hand, and hast gotten thee renown, as at this day; we have sinned, we have done wickedly."},"BSB":{"text":"Now, O Lord our God, who brought Your people out of the land of Egypt with a mighty hand, and who made for Yourself a name renowned to this day, we have sinned; we have acted wickedly."}},"definableWords":["Lord","God","people","land","Egypt","mighty","made","name","day"],"peopleInVerse":[]},"16":{"text":"O LORD, according to all thy righteousness, I beseech thee, let thine anger and thy fury be turned away from thy city Jerusalem, thy holy mountain: because for our sins, and for the iniquities of our fathers, Jerusalem and thy people are become a reproach to all that are about us.","ref":"Daniel 9:16","synthesized":"O Lord, in keeping with all Your righteous acts, I pray that Your anger and wrath may turn away from Your city Jerusalem, Your holy mountain; for because of our sins and the iniquities of our fathers, Jerusalem and Your people are a reproach to all around us.","sources":{"KJV":{"text":"O LORD, according to all thy righteousness, I beseech thee, let thine anger and thy fury be turned away from thy city Jerusalem, thy holy mountain: because for our sins, and for the iniquities of our fathers, Jerusalem and thy people are become a reproach to all that are about us."},"BSB":{"text":"O Lord, in keeping with all Your righteous acts, I pray that Your anger and wrath may turn away from Your city Jerusalem, Your holy mountain; for because of our sins and the iniquities of our fathers, Jerusalem and Your people are a reproach to all around us."}},"definableWords":["Lord","righteous","anger","wrath","Jerusalem","holy","fathers","people"],"peopleInVerse":[]},"17":{"text":"Now therefore, O our God, hear the prayer of thy servant, and his supplications, and cause thy face to shine upon thy sanctuary that is desolate, for the Lord’s sake.","ref":"Daniel 9:17","synthesized":"So now, our God, hear the prayers and petitions of Your servant. For Your sake, O Lord, cause Your face to shine upon Your desolate sanctuary.","sources":{"KJV":{"text":"Now therefore, O our God, hear the prayer of thy servant, and his supplications, and cause thy face to shine upon thy sanctuary that is desolate, for the Lord’s sake."},"BSB":{"text":"So now, our God, hear the prayers and petitions of Your servant. For Your sake, O Lord, cause Your face to shine upon Your desolate sanctuary."}},"definableWords":["God","hear","servant","Lord"],"peopleInVerse":[]},"18":{"text":"O my God, incline thine ear, and hear; open thine eyes, and behold our desolations, and the city which is called by thy name: for we do not present our supplications before thee for our righteousnesses, but for thy great mercies.","ref":"Daniel 9:18","synthesized":"Incline Your ear, O my God, and hear; open Your eyes and see the desolation of the city that bears Your name. For we are not presenting our petitions before You because of our righteous acts, but because of Your great compassion.","sources":{"KJV":{"text":"O my God, incline thine ear, and hear; open thine eyes, and behold our desolations, and the city which is called by thy name: for we do not present our supplications before thee for our righteousnesses, but for thy great mercies."},"BSB":{"text":"Incline Your ear, O my God, and hear; open Your eyes and see the desolation of the city that bears Your name. For we are not presenting our petitions before You because of our righteous acts, but because of Your great compassion."}},"definableWords":["God","hear","see","name","righteous","great"],"peopleInVerse":[]},"19":{"text":"O Lord, hear; O Lord, forgive; O Lord, hearken and do; defer not, for thine own sake, O my God: for thy city and thy people are called by thy name.","ref":"Daniel 9:19","synthesized":"O Lord, listen! O Lord, forgive! O Lord, hear and act! For Your sake, O my God, do not delay, because Your city and Your people bear Your name.”","sources":{"KJV":{"text":"O Lord, hear; O Lord, forgive; O Lord, hearken and do; defer not, for thine own sake, O my God: for thy city and thy people are called by thy name."},"BSB":{"text":"O Lord, listen! O Lord, forgive! O Lord, hear and act! For Your sake, O my God, do not delay, because Your city and Your people bear Your name.”"}},"definableWords":["Lord","forgive","hear","God","people","name"],"peopleInVerse":[]},"20":{"text":"And whiles I was speaking, and praying, and confessing my sin and the sin of my people Israel, and presenting my supplication before the LORD my God for the holy mountain of my God;","ref":"Daniel 9:20","synthesized":"While I was speaking, praying, confessing my sin and that of my people Israel, and presenting my petition before the LORD my God concerning His holy mountain—","sources":{"KJV":{"text":"And whiles I was speaking, and praying, and confessing my sin and the sin of my people Israel, and presenting my supplication before the LORD my God for the holy mountain of my God;"},"BSB":{"text":"While I was speaking, praying, confessing my sin and that of my people Israel, and presenting my petition before the LORD my God concerning His holy mountain—"}},"definableWords":["sin","people","Israel","LORD","God","holy"],"peopleInVerse":[]},"21":{"text":"Yea, whiles I was speaking in prayer, even the man Gabriel, whom I had seen in the vision at the beginning, being caused to fly swiftly, touched me about the time of the evening oblation.","ref":"Daniel 9:21","synthesized":"while I was still praying, Gabriel, the man I had seen in the earlier vision, came to me in swift flight about the time of the evening sacrifice.","sources":{"KJV":{"text":"Yea, whiles I was speaking in prayer, even the man Gabriel, whom I had seen in the vision at the beginning, being caused to fly swiftly, touched me about the time of the evening oblation."},"BSB":{"text":"while I was still praying, Gabriel, the man I had seen in the earlier vision, came to me in swift flight about the time of the evening sacrifice."}},"definableWords":["man","sacrifice"],"peopleInVerse":[]},"22":{"text":"And he informed me, and talked with me, and said, O Daniel, I am now come forth to give thee skill and understanding.","ref":"Daniel 9:22","synthesized":"He instructed me and spoke with me, saying: “O Daniel, I have come now to give you insight and understanding.","sources":{"KJV":{"text":"And he informed me, and talked with me, and said, O Daniel, I am now come forth to give thee skill and understanding."},"BSB":{"text":"He instructed me and spoke with me, saying: “O Daniel, I have come now to give you insight and understanding."}},"definableWords":[],"peopleInVerse":["Daniel"]},"23":{"text":"At the beginning of thy supplications the commandment came forth, and I am come to shew thee; for thou art greatly beloved: therefore understand the matter, and consider the vision.","ref":"Daniel 9:23","synthesized":"At the beginning of your petitions, an answer went out, and I have come to tell you, for you are highly precious. So consider the message and understand the vision:","sources":{"KJV":{"text":"At the beginning of thy supplications the commandment came forth, and I am come to shew thee; for thou art greatly beloved: therefore understand the matter, and consider the vision."},"BSB":{"text":"At the beginning of your petitions, an answer went out, and I have come to tell you, for you are highly precious. So consider the message and understand the vision:"}},"definableWords":["beginning"],"peopleInVerse":[]},"24":{"text":"Seventy weeks are determined upon thy people and upon thy holy city, to finish the transgression, and to make an end of sins, and to make reconciliation for iniquity, and to bring in everlasting righteousness, and to seal up the vision and prophecy, and to anoint the most Holy.","ref":"Daniel 9:24","synthesized":"Seventy weeks are decreed for your people and your holy city to stop their transgression, to put an end to sin, to make atonement for iniquity, to bring in everlasting righteousness, to seal up vision and prophecy, and to anoint the Most Holy Place.","sources":{"KJV":{"text":"Seventy weeks are determined upon thy people and upon thy holy city, to finish the transgression, and to make an end of sins, and to make reconciliation for iniquity, and to bring in everlasting righteousness, and to seal up the vision and prophecy, and to anoint the most Holy."},"BSB":{"text":"Seventy weeks are decreed for your people and your holy city to stop their transgression, to put an end to sin, to make atonement for iniquity, to bring in everlasting righteousness, to seal up vision and prophecy, and to anoint the Most Holy Place."}},"definableWords":["people","holy","transgression","sin","make","atonement","iniquity","everlasting","righteousness","anoint"],"peopleInVerse":[]},"25":{"text":"Know therefore and understand, that from the going forth of the commandment to restore and to build Jerusalem unto the Messiah the Prince shall be seven weeks, and threescore and two weeks: the street shall be built again, and the wall, even in troublous times.","ref":"Daniel 9:25","synthesized":"Know and understand this: From the issuance of the decree to restore and rebuild Jerusalem, until the Messiah, the Prince, there will be seven weeks and sixty-two weeks. It will be rebuilt with streets and a trench, but in times of distress.","sources":{"KJV":{"text":"Know therefore and understand, that from the going forth of the commandment to restore and to build Jerusalem unto the Messiah the Prince shall be seven weeks, and threescore and two weeks: the street shall be built again, and the wall, even in troublous times."},"BSB":{"text":"Know and understand this: From the issuance of the decree to restore and rebuild Jerusalem, until the Messiah, the Prince, there will be seven weeks and sixty-two weeks. It will be rebuilt with streets and a trench, but in times of distress."}},"definableWords":["Jerusalem","Messiah","prince"],"peopleInVerse":[]},"26":{"text":"And after threescore and two weeks shall Messiah be cut off, but not for himself: and the people of the prince that shall come shall destroy the city and the sanctuary; and the end thereof shall be with a flood, and unto the end of the war desolations are determined.","ref":"Daniel 9:26","synthesized":"Then after the sixty-two weeks the Messiah will be cut off and will have nothing.  Then the people of the prince who is to come will destroy the city and the sanctuary. The end will come like a flood, and until the end there will be war; desolations have been decreed.","sources":{"KJV":{"text":"And after threescore and two weeks shall Messiah be cut off, but not for himself: and the people of the prince that shall come shall destroy the city and the sanctuary; and the end thereof shall be with a flood, and unto the end of the war desolations are determined."},"BSB":{"text":"Then after the sixty-two weeks the Messiah will be cut off and will have nothing.  Then the people of the prince who is to come will destroy the city and the sanctuary. The end will come like a flood, and until the end there will be war; desolations have been decreed."}},"definableWords":["Messiah","people","prince","flood"],"peopleInVerse":[]},"27":{"text":"And he shall confirm the covenant with many for one week: and in the midst of the week he shall cause the sacrifice and the oblation to cease, and for the overspreading of abominations he shall make it desolate, even until the consummation, and that determined shall be poured upon the desolate.","ref":"Daniel 9:27","synthesized":"And he will confirm a covenant with many for one week, but in the middle of the week he will put an end to sacrifice and offering. And on the wing of the temple will come the abomination that causes desolation, until the decreed destruction is poured out upon him.”","sources":{"KJV":{"text":"And he shall confirm the covenant with many for one week: and in the midst of the week he shall cause the sacrifice and the oblation to cease, and for the overspreading of abominations he shall make it desolate, even until the consummation, and that determined shall be poured upon the desolate."},"BSB":{"text":"And he will confirm a covenant with many for one week, but in the middle of the week he will put an end to sacrifice and offering. And on the wing of the temple will come the abomination that causes desolation, until the decreed destruction is poured out upon him.”"}},"definableWords":["covenant","one","sacrifice","offering","temple"],"peopleInVerse":[]}}},"10":{"chapter":"10","title":"THE MAN CLOTHED IN LINEN","verses":{"1":{"text":"In the third year of Cyrus king of Persia a thing was revealed unto Daniel, whose name was called Belteshazzar; and the thing was true, but the time appointed was long: and he understood the thing, and had understanding of the vision.","ref":"Daniel 10:1","synthesized":"In the third year of Cyrus king of Persia, a message was revealed to Daniel, who was called Belteshazzar. The message was true, and it concerned a great conflict. And the understanding of the message was given to him in a vision.","sources":{"KJV":{"text":"In the third year of Cyrus king of Persia a thing was revealed unto Daniel, whose name was called Belteshazzar; and the thing was true, but the time appointed was long: and he understood the thing, and had understanding of the vision."},"BSB":{"text":"In the third year of Cyrus king of Persia, a message was revealed to Daniel, who was called Belteshazzar. The message was true, and it concerned a great conflict. And the understanding of the message was given to him in a vision."}},"definableWords":["year","king","great"],"peopleInVerse":["Cyrus","Daniel"]},"2":{"text":"In those days I Daniel was mourning three full weeks.","ref":"Daniel 10:2","synthesized":"In those days I, Daniel, was mourning for three full weeks.","sources":{"KJV":{"text":"In those days I Daniel was mourning three full weeks."},"BSB":{"text":"In those days I, Daniel, was mourning for three full weeks."}},"definableWords":["days"],"peopleInVerse":["Daniel"]},"3":{"text":"I ate no pleasant bread, neither came flesh nor wine in my mouth, neither did I anoint myself at all, till three whole weeks were fulfilled.","ref":"Daniel 10:3","synthesized":"I ate no rich food, no meat or wine entered my mouth, and I did not anoint myself with oil until the three weeks were completed.","sources":{"KJV":{"text":"I ate no pleasant bread, neither came flesh nor wine in my mouth, neither did I anoint myself at all, till three whole weeks were fulfilled."},"BSB":{"text":"I ate no rich food, no meat or wine entered my mouth, and I did not anoint myself with oil until the three weeks were completed."}},"definableWords":["or","anoint"],"peopleInVerse":[]},"4":{"text":"And in the four and twentieth day of the first month, as I was by the side of the great river, which is Hiddekel;","ref":"Daniel 10:4","synthesized":"On the twenty-fourth day of the first month, as I was standing on the bank of the great river, the Tigris,","sources":{"KJV":{"text":"And in the four and twentieth day of the first month, as I was by the side of the great river, which is Hiddekel;"},"BSB":{"text":"On the twenty-fourth day of the first month, as I was standing on the bank of the great river, the Tigris,"}},"definableWords":["day","great"],"peopleInVerse":[]},"5":{"text":"Then I lifted up mine eyes, and looked, and behold a certain man clothed in linen, whose loins were girded with fine gold of Uphaz:","ref":"Daniel 10:5","synthesized":"I lifted up my eyes, and behold, there was a certain man dressed in linen, with a belt of fine gold from Uphaz around his waist.","sources":{"KJV":{"text":"Then I lifted up mine eyes, and looked, and behold a certain man clothed in linen, whose loins were girded with fine gold of Uphaz:"},"BSB":{"text":"I lifted up my eyes, and behold, there was a certain man dressed in linen, with a belt of fine gold from Uphaz around his waist."}},"definableWords":["man"],"peopleInVerse":[]},"6":{"text":"His body also was like the beryl, and his face as the appearance of lightning, and his eyes as lamps of fire, and his arms and his feet like in colour to polished brass, and the voice of his words like the voice of a multitude.","ref":"Daniel 10:6","synthesized":"His body was like beryl, his face like the brilliance of lightning, his eyes like flaming torches, his arms and legs like the gleam of polished bronze, and his voice like the sound of a multitude.","sources":{"KJV":{"text":"His body also was like the beryl, and his face as the appearance of lightning, and his eyes as lamps of fire, and his arms and his feet like in colour to polished brass, and the voice of his words like the voice of a multitude."},"BSB":{"text":"His body was like beryl, his face like the brilliance of lightning, his eyes like flaming torches, his arms and legs like the gleam of polished bronze, and his voice like the sound of a multitude."}},"definableWords":["voice"],"peopleInVerse":[]},"7":{"text":"And I Daniel alone saw the vision: for the men that were with me saw not the vision; but a great quaking fell upon them, so that they fled to hide themselves.","ref":"Daniel 10:7","synthesized":"Only I, Daniel, saw the vision; the men with me did not see it, but a great terror fell upon them, and they ran and hid themselves.","sources":{"KJV":{"text":"And I Daniel alone saw the vision: for the men that were with me saw not the vision; but a great quaking fell upon them, so that they fled to hide themselves."},"BSB":{"text":"Only I, Daniel, saw the vision; the men with me did not see it, but a great terror fell upon them, and they ran and hid themselves."}},"definableWords":["saw","men","see","great"],"peopleInVerse":["Daniel"]},"8":{"text":"Therefore I was left alone, and saw this great vision, and there remained no strength in me: for my comeliness was turned in me into corruption, and I retained no strength.","ref":"Daniel 10:8","synthesized":"So I was left alone, gazing at this great vision. No strength remained in me; my face grew deathly pale, and I was powerless.","sources":{"KJV":{"text":"Therefore I was left alone, and saw this great vision, and there remained no strength in me: for my comeliness was turned in me into corruption, and I retained no strength."},"BSB":{"text":"So I was left alone, gazing at this great vision. No strength remained in me; my face grew deathly pale, and I was powerless."}},"definableWords":["great"],"peopleInVerse":[]},"9":{"text":"Yet heard I the voice of his words: and when I heard the voice of his words, then was I in a deep sleep on my face, and my face toward the ground.","ref":"Daniel 10:9","synthesized":"I heard the sound of his words, and as I listened, I fell into a deep sleep, with my face to the ground.","sources":{"KJV":{"text":"Yet heard I the voice of his words: and when I heard the voice of his words, then was I in a deep sleep on my face, and my face toward the ground."},"BSB":{"text":"I heard the sound of his words, and as I listened, I fell into a deep sleep, with my face to the ground."}},"definableWords":["deep","ground"],"peopleInVerse":[]},"10":{"text":"And, behold, an hand touched me, which set me upon my knees and upon the palms of my hands.","ref":"Daniel 10:10","synthesized":"Suddenly, a hand touched me and set me trembling on my hands and knees.","sources":{"KJV":{"text":"And, behold, an hand touched me, which set me upon my knees and upon the palms of my hands."},"BSB":{"text":"Suddenly, a hand touched me and set me trembling on my hands and knees."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"And he said unto me, O Daniel, a man greatly beloved, understand the words that I speak unto thee, and stand upright: for unto thee am I now sent. And when he had spoken this word unto me, I stood trembling.","ref":"Daniel 10:11","synthesized":"He said to me, “Daniel, you are a man who is highly precious. Consider carefully the words that I am about to say to you. Stand up, for I have now been sent to you.”  And when he had said this to me, I stood up trembling.","sources":{"KJV":{"text":"And he said unto me, O Daniel, a man greatly beloved, understand the words that I speak unto thee, and stand upright: for unto thee am I now sent. And when he had spoken this word unto me, I stood trembling."},"BSB":{"text":"He said to me, “Daniel, you are a man who is highly precious. Consider carefully the words that I am about to say to you. Stand up, for I have now been sent to you.”  And when he had said this to me, I stood up trembling."}},"definableWords":["man","stand"],"peopleInVerse":["Daniel"]},"12":{"text":"Then said he unto me, Fear not, Daniel: for from the first day that thou didst set thine heart to understand, and to chasten thyself before thy God, thy words were heard, and I am come for thy words.","ref":"Daniel 10:12","synthesized":"“Do not be afraid, Daniel,” he said, “for from the first day that you purposed to understand and to humble yourself before your God, your words were heard, and I have come in response to them.","sources":{"KJV":{"text":"Then said he unto me, Fear not, Daniel: for from the first day that thou didst set thine heart to understand, and to chasten thyself before thy God, thy words were heard, and I am come for thy words."},"BSB":{"text":"“Do not be afraid, Daniel,” he said, “for from the first day that you purposed to understand and to humble yourself before your God, your words were heard, and I have come in response to them."}},"definableWords":["day","God"],"peopleInVerse":["Daniel"]},"13":{"text":"But the prince of the kingdom of Persia withstood me one and twenty days: but, lo, Michael, one of the chief princes, came to help me; and I remained there with the kings of Persia.","ref":"Daniel 10:13","synthesized":"However, the prince of the kingdom of Persia opposed me for twenty-one days. Then Michael, one of the chief princes, came to help me, for I had been left there with the kings of Persia.","sources":{"KJV":{"text":"But the prince of the kingdom of Persia withstood me one and twenty days: but, lo, Michael, one of the chief princes, came to help me; and I remained there with the kings of Persia."},"BSB":{"text":"However, the prince of the kingdom of Persia opposed me for twenty-one days. Then Michael, one of the chief princes, came to help me, for I had been left there with the kings of Persia."}},"definableWords":["prince","kingdom","one","days","kings"],"peopleInVerse":[]},"14":{"text":"Now I am come to make thee understand what shall befall thy people in the latter days: for yet the vision is for many days.","ref":"Daniel 10:14","synthesized":"Now I have come to explain to you what will happen to your people in the latter days, for the vision concerns those days.”","sources":{"KJV":{"text":"Now I am come to make thee understand what shall befall thy people in the latter days: for yet the vision is for many days."},"BSB":{"text":"Now I have come to explain to you what will happen to your people in the latter days, for the vision concerns those days.”"}},"definableWords":["people","days"],"peopleInVerse":[]},"15":{"text":"And when he had spoken such words unto me, I set my face toward the ground, and I became dumb.","ref":"Daniel 10:15","synthesized":"While he was speaking these words to me, I set my face toward the ground and became speechless.","sources":{"KJV":{"text":"And when he had spoken such words unto me, I set my face toward the ground, and I became dumb."},"BSB":{"text":"While he was speaking these words to me, I set my face toward the ground and became speechless."}},"definableWords":["ground"],"peopleInVerse":[]},"16":{"text":"And, behold, one like the similitude of the sons of men touched my lips: then I opened my mouth, and spake, and said unto him that stood before me, O my lord, by the vision my sorrows are turned upon me, and I have retained no strength.","ref":"Daniel 10:16","synthesized":"And suddenly one with the likeness of a man touched my lips, and I opened my mouth and said to the one standing before me, “My lord, because of the vision, I am overcome with anguish, and I have no strength.","sources":{"KJV":{"text":"And, behold, one like the similitude of the sons of men touched my lips: then I opened my mouth, and spake, and said unto him that stood before me, O my lord, by the vision my sorrows are turned upon me, and I have retained no strength."},"BSB":{"text":"And suddenly one with the likeness of a man touched my lips, and I opened my mouth and said to the one standing before me, “My lord, because of the vision, I am overcome with anguish, and I have no strength."}},"definableWords":["one","likeness","man","Lord","overcome"],"peopleInVerse":[]},"17":{"text":"For how can the servant of this my lord talk with this my lord? for as for me, straightway there remained no strength in me, neither is there breath left in me.","ref":"Daniel 10:17","synthesized":"How can I, your servant, speak with you, my lord? Now I have no strength, nor is any breath left in me.”","sources":{"KJV":{"text":"For how can the servant of this my lord talk with this my lord? for as for me, straightway there remained no strength in me, neither is there breath left in me."},"BSB":{"text":"How can I, your servant, speak with you, my lord? Now I have no strength, nor is any breath left in me.”"}},"definableWords":["servant","Lord","breath"],"peopleInVerse":[]},"18":{"text":"Then there came again and touched me one like the appearance of a man, and he strengthened me,","ref":"Daniel 10:18","synthesized":"Again the one with the likeness of a man touched me and strengthened me.","sources":{"KJV":{"text":"Then there came again and touched me one like the appearance of a man, and he strengthened me,"},"BSB":{"text":"Again the one with the likeness of a man touched me and strengthened me."}},"definableWords":["one","likeness","man"],"peopleInVerse":[]},"19":{"text":"And said, O man greatly beloved, fear not: peace be unto thee, be strong, yea, be strong. And when he had spoken unto me, I was strengthened, and said, Let my lord speak; for thou hast strengthened me.","ref":"Daniel 10:19","synthesized":"“Do not be afraid, you who are highly precious,” he said. “Peace be with you! Be strong now; be very strong!”  As he spoke with me, I was strengthened and said, “Speak, my lord, for you have strengthened me.”","sources":{"KJV":{"text":"And said, O man greatly beloved, fear not: peace be unto thee, be strong, yea, be strong. And when he had spoken unto me, I was strengthened, and said, Let my lord speak; for thou hast strengthened me."},"BSB":{"text":"“Do not be afraid, you who are highly precious,” he said. “Peace be with you! Be strong now; be very strong!”  As he spoke with me, I was strengthened and said, “Speak, my lord, for you have strengthened me.”"}},"definableWords":["peace","strong","Lord"],"peopleInVerse":[]},"20":{"text":"Then said he, Knowest thou wherefore I come unto thee? and now will I return to fight with the prince of Persia: and when I am gone forth, lo, the prince of Grecia shall come.","ref":"Daniel 10:20","synthesized":"“Do you know why I have come to you?” he said. “I must return at once to fight against the prince of Persia, and when I have gone forth, behold, the prince of Greece will come.","sources":{"KJV":{"text":"Then said he, Knowest thou wherefore I come unto thee? and now will I return to fight with the prince of Persia: and when I am gone forth, lo, the prince of Grecia shall come."},"BSB":{"text":"“Do you know why I have come to you?” he said. “I must return at once to fight against the prince of Persia, and when I have gone forth, behold, the prince of Greece will come."}},"definableWords":["fight","prince"],"peopleInVerse":[]},"21":{"text":"But I will shew thee that which is noted in the scripture of truth: and there is none that holdeth with me in these things, but Michael your prince.","ref":"Daniel 10:21","synthesized":"But first I will tell you what is inscribed in the Book of Truth. Yet no one has the courage to support me against these, except Michael your prince.","sources":{"KJV":{"text":"But I will shew thee that which is noted in the scripture of truth: and there is none that holdeth with me in these things, but Michael your prince."},"BSB":{"text":"But first I will tell you what is inscribed in the Book of Truth. Yet no one has the courage to support me against these, except Michael your prince."}},"definableWords":["truth","one","prince"],"peopleInVerse":[]}}},"11":{"chapter":"11","title":"THE KINGS OF NORTH AND SOUTH","verses":{"1":{"text":"Also I in the first year of Darius the Mede, even I, stood to confirm and to strengthen him.","ref":"Daniel 11:1","synthesized":"“And I, in the first year of Darius the Mede, stood up to strengthen and protect him.","sources":{"KJV":{"text":"Also I in the first year of Darius the Mede, even I, stood to confirm and to strengthen him."},"BSB":{"text":"“And I, in the first year of Darius the Mede, stood up to strengthen and protect him."}},"definableWords":["year"],"peopleInVerse":[]},"2":{"text":"And now will I shew thee the truth. Behold, there shall stand up yet three kings in Persia; and the fourth shall be far richer than they all: and by his strength through his riches he shall stir up all against the realm of Grecia.","ref":"Daniel 11:2","synthesized":"Now then, I will tell you the truth: Three more kings will arise in Persia, and then a fourth, who will be far richer than all the others. By the power of his wealth, he will stir up everyone against the kingdom of Greece.","sources":{"KJV":{"text":"And now will I shew thee the truth. Behold, there shall stand up yet three kings in Persia; and the fourth shall be far richer than they all: and by his strength through his riches he shall stir up all against the realm of Grecia."},"BSB":{"text":"Now then, I will tell you the truth: Three more kings will arise in Persia, and then a fourth, who will be far richer than all the others. By the power of his wealth, he will stir up everyone against the kingdom of Greece."}},"definableWords":["truth","kings","kingdom"],"peopleInVerse":[]},"3":{"text":"And a mighty king shall stand up, that shall rule with great dominion, and do according to his will.","ref":"Daniel 11:3","synthesized":"Then a mighty king will arise, who will rule with great authority and do as he pleases.","sources":{"KJV":{"text":"And a mighty king shall stand up, that shall rule with great dominion, and do according to his will."},"BSB":{"text":"Then a mighty king will arise, who will rule with great authority and do as he pleases."}},"definableWords":["mighty","king","rule","great"],"peopleInVerse":[]},"4":{"text":"And when he shall stand up, his kingdom shall be broken, and shall be divided toward the four winds of heaven; and not to his posterity, nor according to his dominion which he ruled: for his kingdom shall be plucked up, even for others beside those.","ref":"Daniel 11:4","synthesized":"But as soon as he is established, his kingdom will be broken up and parceled out toward the four winds of heaven. It will not go to his descendants, nor will it have the authority with which he ruled, because his kingdom will be uprooted and given to others.","sources":{"KJV":{"text":"And when he shall stand up, his kingdom shall be broken, and shall be divided toward the four winds of heaven; and not to his posterity, nor according to his dominion which he ruled: for his kingdom shall be plucked up, even for others beside those."},"BSB":{"text":"But as soon as he is established, his kingdom will be broken up and parceled out toward the four winds of heaven. It will not go to his descendants, nor will it have the authority with which he ruled, because his kingdom will be uprooted and given to others."}},"definableWords":["kingdom","heaven"],"peopleInVerse":[]},"5":{"text":"And the king of the south shall be strong, and one of his princes; and he shall be strong above him, and have dominion; his dominion shall be a great dominion.","ref":"Daniel 11:5","synthesized":"The king of the South will grow strong, but one of his commanders will grow even stronger and will rule his own kingdom with great authority.","sources":{"KJV":{"text":"And the king of the south shall be strong, and one of his princes; and he shall be strong above him, and have dominion; his dominion shall be a great dominion."},"BSB":{"text":"The king of the South will grow strong, but one of his commanders will grow even stronger and will rule his own kingdom with great authority."}},"definableWords":["king","strong","one","rule","kingdom","great"],"peopleInVerse":[]},"6":{"text":"And in the end of years they shall join themselves together; for the king’s daughter of the south shall come to the king of the north to make an agreement: but she shall not retain the power of the arm; neither shall he stand, nor his arm: but she shall be given up, and they that brought her, and he that begat her, and he that strengthened her in these times.","ref":"Daniel 11:6","synthesized":"After some years they will form an alliance, and the daughter of the king of the South will go to the king of the North to seal the agreement. But his daughter will not retain her position of power, nor will his strength endure. At that time she will be given up, along with her royal escort and her father and the one who supported her.","sources":{"KJV":{"text":"And in the end of years they shall join themselves together; for the king’s daughter of the south shall come to the king of the north to make an agreement: but she shall not retain the power of the arm; neither shall he stand, nor his arm: but she shall be given up, and they that brought her, and he that begat her, and he that strengthened her in these times."},"BSB":{"text":"After some years they will form an alliance, and the daughter of the king of the South will go to the king of the North to seal the agreement. But his daughter will not retain her position of power, nor will his strength endure. At that time she will be given up, along with her royal escort and her father and the one who supported her."}},"definableWords":["years","form","daughter","king","King","father","one"],"peopleInVerse":[]},"7":{"text":"But out of a branch of her roots shall one stand up in his estate, which shall come with an army, and shall enter into the fortress of the king of the north, and shall deal against them, and shall prevail:","ref":"Daniel 11:7","synthesized":"But one from her family line will rise up in his place, come against the army of the king of the North, and enter his fortress, fighting and prevailing.","sources":{"KJV":{"text":"But out of a branch of her roots shall one stand up in his estate, which shall come with an army, and shall enter into the fortress of the king of the north, and shall deal against them, and shall prevail:"},"BSB":{"text":"But one from her family line will rise up in his place, come against the army of the king of the North, and enter his fortress, fighting and prevailing."}},"definableWords":["one","family","king"],"peopleInVerse":[]},"8":{"text":"And shall also carry captives into Egypt their gods, with their princes, and with their precious vessels of silver and of gold; and he shall continue more years than the king of the north.","ref":"Daniel 11:8","synthesized":"He will take even their gods captive to Egypt, with their metal images and their precious vessels of silver and gold. For some years he will stay away from the king of the North,","sources":{"KJV":{"text":"And shall also carry captives into Egypt their gods, with their princes, and with their precious vessels of silver and of gold; and he shall continue more years than the king of the north."},"BSB":{"text":"He will take even their gods captive to Egypt, with their metal images and their precious vessels of silver and gold. For some years he will stay away from the king of the North,"}},"definableWords":["Egypt","years","king"],"peopleInVerse":[]},"9":{"text":"So the king of the south shall come into his kingdom, and shall return into his own land.","ref":"Daniel 11:9","synthesized":"who will invade the realm of the king of the South and then return to his own land.","sources":{"KJV":{"text":"So the king of the south shall come into his kingdom, and shall return into his own land."},"BSB":{"text":"who will invade the realm of the king of the South and then return to his own land."}},"definableWords":["king","land"],"peopleInVerse":[]},"10":{"text":"But his sons shall be stirred up, and shall assemble a multitude of great forces: and one shall certainly come, and overflow, and pass through: then shall he return, and be stirred up, even to his fortress.","ref":"Daniel 11:10","synthesized":"But his sons will stir up strife and assemble a great army, which will advance forcefully, sweeping through like a flood, and will again carry the battle as far as his fortress.","sources":{"KJV":{"text":"But his sons shall be stirred up, and shall assemble a multitude of great forces: and one shall certainly come, and overflow, and pass through: then shall he return, and be stirred up, even to his fortress."},"BSB":{"text":"But his sons will stir up strife and assemble a great army, which will advance forcefully, sweeping through like a flood, and will again carry the battle as far as his fortress."}},"definableWords":["sons","great","flood"],"peopleInVerse":[]},"11":{"text":"And the king of the south shall be moved with choler, and shall come forth and fight with him, even with the king of the north: and he shall set forth a great multitude; but the multitude shall be given into his hand.","ref":"Daniel 11:11","synthesized":"In a rage, the king of the South will march out to fight the king of the North, who will raise a large army, but it will be delivered into the hand of his enemy.","sources":{"KJV":{"text":"And the king of the south shall be moved with choler, and shall come forth and fight with him, even with the king of the north: and he shall set forth a great multitude; but the multitude shall be given into his hand."},"BSB":{"text":"In a rage, the king of the South will march out to fight the king of the North, who will raise a large army, but it will be delivered into the hand of his enemy."}},"definableWords":["king","fight","King"],"peopleInVerse":[]},"12":{"text":"And when he hath taken away the multitude, his heart shall be lifted up; and he shall cast down many ten thousands: but he shall not be strengthened by it.","ref":"Daniel 11:12","synthesized":"When the army is carried off, the king of the South will be proud in heart and will cast down tens of thousands, but he will not triumph.","sources":{"KJV":{"text":"And when he hath taken away the multitude, his heart shall be lifted up; and he shall cast down many ten thousands: but he shall not be strengthened by it."},"BSB":{"text":"When the army is carried off, the king of the South will be proud in heart and will cast down tens of thousands, but he will not triumph."}},"definableWords":["king","heart"],"peopleInVerse":[]},"13":{"text":"For the king of the north shall return, and shall set forth a multitude greater than the former, and shall certainly come after certain years with a great army and with much riches.","ref":"Daniel 11:13","synthesized":"For the king of the North will raise another army, larger than the first, and after some years he will advance with a great army and many supplies.","sources":{"KJV":{"text":"For the king of the north shall return, and shall set forth a multitude greater than the former, and shall certainly come after certain years with a great army and with much riches."},"BSB":{"text":"For the king of the North will raise another army, larger than the first, and after some years he will advance with a great army and many supplies."}},"definableWords":["king","years","great"],"peopleInVerse":[]},"14":{"text":"And in those times there shall many stand up against the king of the south: also the robbers of thy people shall exalt themselves to establish the vision; but they shall fall.","ref":"Daniel 11:14","synthesized":"In those times many will rise up against the king of the South. Violent ones among your own people will exalt themselves in fulfillment of the vision, but they will fail.","sources":{"KJV":{"text":"And in those times there shall many stand up against the king of the south: also the robbers of thy people shall exalt themselves to establish the vision; but they shall fall."},"BSB":{"text":"In those times many will rise up against the king of the South. Violent ones among your own people will exalt themselves in fulfillment of the vision, but they will fail."}},"definableWords":["king","people"],"peopleInVerse":[]},"15":{"text":"So the king of the north shall come, and cast up a mount, and take the most fenced cities: and the arms of the south shall not withstand, neither his chosen people, neither shall there be any strength to withstand.","ref":"Daniel 11:15","synthesized":"Then the king of the North will come, build up a siege ramp, and capture a fortified city. The forces of the South will not stand; even their best troops will not be able to resist.","sources":{"KJV":{"text":"So the king of the north shall come, and cast up a mount, and take the most fenced cities: and the arms of the south shall not withstand, neither his chosen people, neither shall there be any strength to withstand."},"BSB":{"text":"Then the king of the North will come, build up a siege ramp, and capture a fortified city. The forces of the South will not stand; even their best troops will not be able to resist."}},"definableWords":["king","stand"],"peopleInVerse":[]},"16":{"text":"But he that cometh against him shall do according to his own will, and none shall stand before him: and he shall stand in the glorious land, which by his hand shall be consumed.","ref":"Daniel 11:16","synthesized":"The invader will do as he pleases, and no one will stand against him. He will establish himself in the Beautiful Land, with destruction in his hand.","sources":{"KJV":{"text":"But he that cometh against him shall do according to his own will, and none shall stand before him: and he shall stand in the glorious land, which by his hand shall be consumed."},"BSB":{"text":"The invader will do as he pleases, and no one will stand against him. He will establish himself in the Beautiful Land, with destruction in his hand."}},"definableWords":["one","stand","land"],"peopleInVerse":[]},"17":{"text":"He shall also set his face to enter with the strength of his whole kingdom, and upright ones with him; thus shall he do: and he shall give him the daughter of women, corrupting her: but she shall not stand on his side, neither be for him.","ref":"Daniel 11:17","synthesized":"He will resolve to come with the strength of his whole kingdom, and will reach an agreement with the king of the South. He will give him a daughter in marriage in order to overthrow the kingdom, but his plan will not succeed or help him.","sources":{"KJV":{"text":"He shall also set his face to enter with the strength of his whole kingdom, and upright ones with him; thus shall he do: and he shall give him the daughter of women, corrupting her: but she shall not stand on his side, neither be for him."},"BSB":{"text":"He will resolve to come with the strength of his whole kingdom, and will reach an agreement with the king of the South. He will give him a daughter in marriage in order to overthrow the kingdom, but his plan will not succeed or help him."}},"definableWords":["kingdom","king","daughter","or"],"peopleInVerse":[]},"18":{"text":"After this shall he turn his face unto the isles, and shall take many: but a prince for his own behalf shall cause the reproach offered by him to cease; without his own reproach he shall cause it to turn upon him.","ref":"Daniel 11:18","synthesized":"Then he will turn his face to the coastlands and capture many of them. But a commander will put an end to his reproach and will turn it back upon him.","sources":{"KJV":{"text":"After this shall he turn his face unto the isles, and shall take many: but a prince for his own behalf shall cause the reproach offered by him to cease; without his own reproach he shall cause it to turn upon him."},"BSB":{"text":"Then he will turn his face to the coastlands and capture many of them. But a commander will put an end to his reproach and will turn it back upon him."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Then he shall turn his face toward the fort of his own land: but he shall stumble and fall, and not be found.","ref":"Daniel 11:19","synthesized":"After this, he will turn back toward the fortresses of his own land, but he will stumble and fall and be no more.","sources":{"KJV":{"text":"Then he shall turn his face toward the fort of his own land: but he shall stumble and fall, and not be found."},"BSB":{"text":"After this, he will turn back toward the fortresses of his own land, but he will stumble and fall and be no more."}},"definableWords":["land"],"peopleInVerse":[]},"20":{"text":"Then shall stand up in his estate a raiser of taxes in the glory of the kingdom: but within few days he shall be destroyed, neither in anger, nor in battle.","ref":"Daniel 11:20","synthesized":"In his place one will arise who will send out a tax collector for the glory of the kingdom; but within a few days he will be destroyed, though not in anger or in battle.","sources":{"KJV":{"text":"Then shall stand up in his estate a raiser of taxes in the glory of the kingdom: but within few days he shall be destroyed, neither in anger, nor in battle."},"BSB":{"text":"In his place one will arise who will send out a tax collector for the glory of the kingdom; but within a few days he will be destroyed, though not in anger or in battle."}},"definableWords":["one","glory","kingdom","days","anger","or"],"peopleInVerse":[]},"21":{"text":"And in his estate shall stand up a vile person, to whom they shall not give the honour of the kingdom: but he shall come in peaceably, and obtain the kingdom by flatteries.","ref":"Daniel 11:21","synthesized":"In his place a despicable person will arise; royal honors will not be given to him, but he will come in a time of peace and seize the kingdom by intrigue.","sources":{"KJV":{"text":"And in his estate shall stand up a vile person, to whom they shall not give the honour of the kingdom: but he shall come in peaceably, and obtain the kingdom by flatteries."},"BSB":{"text":"In his place a despicable person will arise; royal honors will not be given to him, but he will come in a time of peace and seize the kingdom by intrigue."}},"definableWords":["peace","kingdom"],"peopleInVerse":[]},"22":{"text":"And with the arms of a flood shall they be overflown from before him, and shall be broken; yea, also the prince of the covenant.","ref":"Daniel 11:22","synthesized":"Then a flood of forces will be swept away before him and destroyed, along with a prince of the covenant.","sources":{"KJV":{"text":"And with the arms of a flood shall they be overflown from before him, and shall be broken; yea, also the prince of the covenant."},"BSB":{"text":"Then a flood of forces will be swept away before him and destroyed, along with a prince of the covenant."}},"definableWords":["flood","prince","covenant"],"peopleInVerse":[]},"23":{"text":"And after the league made with him he shall work deceitfully: for he shall come up, and shall become strong with a small people.","ref":"Daniel 11:23","synthesized":"After an alliance is made with him, he will act deceitfully; for he will rise to power with only a few people.","sources":{"KJV":{"text":"And after the league made with him he shall work deceitfully: for he shall come up, and shall become strong with a small people."},"BSB":{"text":"After an alliance is made with him, he will act deceitfully; for he will rise to power with only a few people."}},"definableWords":["made","people"],"peopleInVerse":[]},"24":{"text":"He shall enter peaceably even upon the fattest places of the province; and he shall do that which his fathers have not done, nor his fathers’ fathers; he shall scatter among them the prey, and spoil, and riches: yea, and he shall forecast his devices against the strong holds, even for a time.","ref":"Daniel 11:24","synthesized":"In a time of peace, he will invade the richest provinces and do what his fathers and forefathers never did. He will lavish plunder, loot, and wealth on his followers, and he will plot against the strongholds—but only for a time.","sources":{"KJV":{"text":"He shall enter peaceably even upon the fattest places of the province; and he shall do that which his fathers have not done, nor his fathers’ fathers; he shall scatter among them the prey, and spoil, and riches: yea, and he shall forecast his devices against the strong holds, even for a time."},"BSB":{"text":"In a time of peace, he will invade the richest provinces and do what his fathers and forefathers never did. He will lavish plunder, loot, and wealth on his followers, and he will plot against the strongholds—but only for a time."}},"definableWords":["peace","fathers"],"peopleInVerse":[]},"25":{"text":"And he shall stir up his power and his courage against the king of the south with a great army; and the king of the south shall be stirred up to battle with a very great and mighty army; but he shall not stand: for they shall forecast devices against him.","ref":"Daniel 11:25","synthesized":"And with a large army he will stir up his power and his courage against the king of the South, who will mobilize a very large and powerful army but will not withstand the plots devised against him.","sources":{"KJV":{"text":"And he shall stir up his power and his courage against the king of the south with a great army; and the king of the south shall be stirred up to battle with a very great and mighty army; but he shall not stand: for they shall forecast devices against him."},"BSB":{"text":"And with a large army he will stir up his power and his courage against the king of the South, who will mobilize a very large and powerful army but will not withstand the plots devised against him."}},"definableWords":["king"],"peopleInVerse":[]},"26":{"text":"Yea, they that feed of the portion of his meat shall destroy him, and his army shall overflow: and many shall fall down slain.","ref":"Daniel 11:26","synthesized":"Those who eat from his provisions will seek to destroy him; his army will be swept away, and many will fall slain.","sources":{"KJV":{"text":"Yea, they that feed of the portion of his meat shall destroy him, and his army shall overflow: and many shall fall down slain."},"BSB":{"text":"Those who eat from his provisions will seek to destroy him; his army will be swept away, and many will fall slain."}},"definableWords":["seek"],"peopleInVerse":[]},"27":{"text":"And both these kings’ hearts shall be to do mischief, and they shall speak lies at one table; but it shall not prosper: for yet the end shall be at the time appointed.","ref":"Daniel 11:27","synthesized":"And the two kings, with their hearts bent on evil, will speak lies at the same table, but to no avail, for still the end will come at the appointed time.","sources":{"KJV":{"text":"And both these kings’ hearts shall be to do mischief, and they shall speak lies at one table; but it shall not prosper: for yet the end shall be at the time appointed."},"BSB":{"text":"And the two kings, with their hearts bent on evil, will speak lies at the same table, but to no avail, for still the end will come at the appointed time."}},"definableWords":["kings","evil"],"peopleInVerse":[]},"28":{"text":"Then shall he return into his land with great riches; and his heart shall be against the holy covenant; and he shall do exploits, and return to his own land.","ref":"Daniel 11:28","synthesized":"The king of the North will return to his land with great wealth, but his heart will be set against the holy covenant; so he will do damage and return to his own land.","sources":{"KJV":{"text":"Then shall he return into his land with great riches; and his heart shall be against the holy covenant; and he shall do exploits, and return to his own land."},"BSB":{"text":"The king of the North will return to his land with great wealth, but his heart will be set against the holy covenant; so he will do damage and return to his own land."}},"definableWords":["king","land","great","heart","holy","covenant"],"peopleInVerse":[]},"29":{"text":"At the time appointed he shall return, and come toward the south; but it shall not be as the former, or as the latter.","ref":"Daniel 11:29","synthesized":"At the appointed time he will invade the South again, but this time will not be like the first.","sources":{"KJV":{"text":"At the time appointed he shall return, and come toward the south; but it shall not be as the former, or as the latter."},"BSB":{"text":"At the appointed time he will invade the South again, but this time will not be like the first."}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"For the ships of Chittim shall come against him: therefore he shall be grieved, and return, and have indignation against the holy covenant: so shall he do; he shall even return, and have intelligence with them that forsake the holy covenant.","ref":"Daniel 11:30","synthesized":"Ships of Kittim will come against him, and he will lose heart. Then he will turn back and rage against the holy covenant and do damage. So he will return and show favor to those who forsake the holy covenant.","sources":{"KJV":{"text":"For the ships of Chittim shall come against him: therefore he shall be grieved, and return, and have indignation against the holy covenant: so shall he do; he shall even return, and have intelligence with them that forsake the holy covenant."},"BSB":{"text":"Ships of Kittim will come against him, and he will lose heart. Then he will turn back and rage against the holy covenant and do damage. So he will return and show favor to those who forsake the holy covenant."}},"definableWords":["heart","holy","covenant"],"peopleInVerse":[]},"31":{"text":"And arms shall stand on his part, and they shall pollute the sanctuary of strength, and shall take away the daily sacrifice, and they shall place the abomination that maketh desolate.","ref":"Daniel 11:31","synthesized":"His forces will rise up and desecrate the temple fortress. They will abolish the daily sacrifice and set up the abomination of desolation.","sources":{"KJV":{"text":"And arms shall stand on his part, and they shall pollute the sanctuary of strength, and shall take away the daily sacrifice, and they shall place the abomination that maketh desolate."},"BSB":{"text":"His forces will rise up and desecrate the temple fortress. They will abolish the daily sacrifice and set up the abomination of desolation."}},"definableWords":["temple","sacrifice"],"peopleInVerse":[]},"32":{"text":"And such as do wickedly against the covenant shall he corrupt by flatteries: but the people that do know their God shall be strong, and do exploits.","ref":"Daniel 11:32","synthesized":"With flattery he will corrupt those who violate the covenant, but the people who know their God will firmly resist him.","sources":{"KJV":{"text":"And such as do wickedly against the covenant shall he corrupt by flatteries: but the people that do know their God shall be strong, and do exploits."},"BSB":{"text":"With flattery he will corrupt those who violate the covenant, but the people who know their God will firmly resist him."}},"definableWords":["covenant","people","God"],"peopleInVerse":[]},"33":{"text":"And they that understand among the people shall instruct many: yet they shall fall by the sword, and by flame, by captivity, and by spoil, many days.","ref":"Daniel 11:33","synthesized":"Those with insight will instruct many, though for a time they will fall by sword or flame, or be captured or plundered.","sources":{"KJV":{"text":"And they that understand among the people shall instruct many: yet they shall fall by the sword, and by flame, by captivity, and by spoil, many days."},"BSB":{"text":"Those with insight will instruct many, though for a time they will fall by sword or flame, or be captured or plundered."}},"definableWords":["or"],"peopleInVerse":[]},"34":{"text":"Now when they shall fall, they shall be holpen with a little help: but many shall cleave to them with flatteries.","ref":"Daniel 11:34","synthesized":"Now when they fall, they will be granted a little help, but many will join them insincerely.","sources":{"KJV":{"text":"Now when they shall fall, they shall be holpen with a little help: but many shall cleave to them with flatteries."},"BSB":{"text":"Now when they fall, they will be granted a little help, but many will join them insincerely."}},"definableWords":[],"peopleInVerse":[]},"35":{"text":"And some of them of understanding shall fall, to try them, and to purge, and to make them white, even to the time of the end: because it is yet for a time appointed.","ref":"Daniel 11:35","synthesized":"Some of the wise will fall, so that they may be refined, purified, and made spotless until the time of the end, for it will still come at the appointed time.","sources":{"KJV":{"text":"And some of them of understanding shall fall, to try them, and to purge, and to make them white, even to the time of the end: because it is yet for a time appointed."},"BSB":{"text":"Some of the wise will fall, so that they may be refined, purified, and made spotless until the time of the end, for it will still come at the appointed time."}},"definableWords":["made"],"peopleInVerse":[]},"36":{"text":"And the king shall do according to his will; and he shall exalt himself, and magnify himself above every god, and shall speak marvellous things against the God of gods, and shall prosper till the indignation be accomplished: for that that is determined shall be done.","ref":"Daniel 11:36","synthesized":"Then the king will do as he pleases and will exalt and magnify himself above every god, and he will speak monstrous things against the God of gods. He will be successful until the time of wrath is completed, for what has been decreed must be accomplished.","sources":{"KJV":{"text":"And the king shall do according to his will; and he shall exalt himself, and magnify himself above every god, and shall speak marvellous things against the God of gods, and shall prosper till the indignation be accomplished: for that that is determined shall be done."},"BSB":{"text":"Then the king will do as he pleases and will exalt and magnify himself above every god, and he will speak monstrous things against the God of gods. He will be successful until the time of wrath is completed, for what has been decreed must be accomplished."}},"definableWords":["king","God","wrath"],"peopleInVerse":[]},"37":{"text":"Neither shall he regard the God of his fathers, nor the desire of women, nor regard any god: for he shall magnify himself above all.","ref":"Daniel 11:37","synthesized":"He will show no regard for the gods of his fathers, nor for the one desired by women, nor for any other god, because he will magnify himself above them all.","sources":{"KJV":{"text":"Neither shall he regard the God of his fathers, nor the desire of women, nor regard any god: for he shall magnify himself above all."},"BSB":{"text":"He will show no regard for the gods of his fathers, nor for the one desired by women, nor for any other god, because he will magnify himself above them all."}},"definableWords":["fathers","one","women","God"],"peopleInVerse":[]},"38":{"text":"But in his estate shall he honour the God of forces: and a god whom his fathers knew not shall he honour with gold, and silver, and with precious stones, and pleasant things.","ref":"Daniel 11:38","synthesized":"And in their place, he will honor a god of fortresses—a god his fathers did not know—with gold, silver, precious stones, and riches.","sources":{"KJV":{"text":"But in his estate shall he honour the God of forces: and a god whom his fathers knew not shall he honour with gold, and silver, and with precious stones, and pleasant things."},"BSB":{"text":"And in their place, he will honor a god of fortresses—a god his fathers did not know—with gold, silver, precious stones, and riches."}},"definableWords":["God","fathers"],"peopleInVerse":[]},"39":{"text":"Thus shall he do in the most strong holds with a strange god, whom he shall acknowledge and increase with glory: and he shall cause them to rule over many, and shall divide the land for gain.","ref":"Daniel 11:39","synthesized":"He will attack the strongest fortresses with the help of a foreign god and will greatly honor those who acknowledge him, making them rulers over many and distributing the land for a price.","sources":{"KJV":{"text":"Thus shall he do in the most strong holds with a strange god, whom he shall acknowledge and increase with glory: and he shall cause them to rule over many, and shall divide the land for gain."},"BSB":{"text":"He will attack the strongest fortresses with the help of a foreign god and will greatly honor those who acknowledge him, making them rulers over many and distributing the land for a price."}},"definableWords":["God","land"],"peopleInVerse":[]},"40":{"text":"And at the time of the end shall the king of the south push at him: and the king of the north shall come against him like a whirlwind, with chariots, and with horsemen, and with many ships; and he shall enter into the countries, and shall overflow and pass over.","ref":"Daniel 11:40","synthesized":"At the time of the end, the king of the South will engage him in battle, but the king of the North will storm out against him with chariots, horsemen, and many ships, invading many countries and sweeping through them like a flood.","sources":{"KJV":{"text":"And at the time of the end shall the king of the south push at him: and the king of the north shall come against him like a whirlwind, with chariots, and with horsemen, and with many ships; and he shall enter into the countries, and shall overflow and pass over."},"BSB":{"text":"At the time of the end, the king of the South will engage him in battle, but the king of the North will storm out against him with chariots, horsemen, and many ships, invading many countries and sweeping through them like a flood."}},"definableWords":["king","King","flood"],"peopleInVerse":[]},"41":{"text":"He shall enter also into the glorious land, and many countries shall be overthrown: but these shall escape out of his hand, even Edom, and Moab, and the chief of the children of Ammon.","ref":"Daniel 11:41","synthesized":"He will also invade the Beautiful Land, and many countries will fall. But these will be delivered from his hand: Edom, Moab, and the leaders of the Ammonites.","sources":{"KJV":{"text":"He shall enter also into the glorious land, and many countries shall be overthrown: but these shall escape out of his hand, even Edom, and Moab, and the chief of the children of Ammon."},"BSB":{"text":"He will also invade the Beautiful Land, and many countries will fall. But these will be delivered from his hand: Edom, Moab, and the leaders of the Ammonites."}},"definableWords":["land","Edom"],"peopleInVerse":["Ammonites"]},"42":{"text":"He shall stretch forth his hand also upon the countries: and the land of Egypt shall not escape.","ref":"Daniel 11:42","synthesized":"He will extend his power over many countries, and not even the land of Egypt will escape.","sources":{"KJV":{"text":"He shall stretch forth his hand also upon the countries: and the land of Egypt shall not escape."},"BSB":{"text":"He will extend his power over many countries, and not even the land of Egypt will escape."}},"definableWords":["land","Egypt"],"peopleInVerse":[]},"43":{"text":"But he shall have power over the treasures of gold and of silver, and over all the precious things of Egypt: and the Libyans and the Ethiopians shall be at his steps.","ref":"Daniel 11:43","synthesized":"He will gain control of the treasures of gold and silver and over all the riches of Egypt, and the Libyans and Cushites will also submit to him.","sources":{"KJV":{"text":"But he shall have power over the treasures of gold and of silver, and over all the precious things of Egypt: and the Libyans and the Ethiopians shall be at his steps."},"BSB":{"text":"He will gain control of the treasures of gold and silver and over all the riches of Egypt, and the Libyans and Cushites will also submit to him."}},"definableWords":["Egypt"],"peopleInVerse":[]},"44":{"text":"But tidings out of the east and out of the north shall trouble him: therefore he shall go forth with great fury to destroy, and utterly to make away many.","ref":"Daniel 11:44","synthesized":"But news from the east and the north will alarm him, and he will go out with great fury to destroy many and devote them to destruction.","sources":{"KJV":{"text":"But tidings out of the east and out of the north shall trouble him: therefore he shall go forth with great fury to destroy, and utterly to make away many."},"BSB":{"text":"But news from the east and the north will alarm him, and he will go out with great fury to destroy many and devote them to destruction."}},"definableWords":["great"],"peopleInVerse":[]},"45":{"text":"And he shall plant the tabernacles of his palace between the seas in the glorious holy mountain; yet he shall come to his end, and none shall help him.","ref":"Daniel 11:45","synthesized":"He will pitch his royal tents between the sea and the beautiful holy mountain, but he will meet his end with no one to help him.","sources":{"KJV":{"text":"And he shall plant the tabernacles of his palace between the seas in the glorious holy mountain; yet he shall come to his end, and none shall help him."},"BSB":{"text":"He will pitch his royal tents between the sea and the beautiful holy mountain, but he will meet his end with no one to help him."}},"definableWords":["sea","holy","one"],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"THE TIME OF THE END","verses":{"1":{"text":"And at that time shall Michael stand up, the great prince which standeth for the children of thy people: and there shall be a time of trouble, such as never was since there was a nation even to that same time: and at that time thy people shall be delivered, every one that shall be found written in the book.","ref":"Daniel 12:1","synthesized":"“At that time Michael, the great prince who stands watch over your people, will rise up. There will be a time of distress, the likes of which will not have occurred from the beginning of nations until that time. But at that time your people—everyone whose name is found written in the book—will be delivered.","sources":{"KJV":{"text":"And at that time shall Michael stand up, the great prince which standeth for the children of thy people: and there shall be a time of trouble, such as never was since there was a nation even to that same time: and at that time thy people shall be delivered, every one that shall be found written in the book."},"BSB":{"text":"“At that time Michael, the great prince who stands watch over your people, will rise up. There will be a time of distress, the likes of which will not have occurred from the beginning of nations until that time. But at that time your people—everyone whose name is found written in the book—will be delivered."}},"definableWords":["great","prince","people","beginning","nations","name"],"peopleInVerse":[]},"2":{"text":"And many of them that sleep in the dust of the earth shall awake, some to everlasting life, and some to shame and everlasting contempt.","ref":"Daniel 12:2","synthesized":"And many who sleep in the dust of the earth will awake, some to everlasting life, but others to shame and everlasting contempt.","sources":{"KJV":{"text":"And many of them that sleep in the dust of the earth shall awake, some to everlasting life, and some to shame and everlasting contempt."},"BSB":{"text":"And many who sleep in the dust of the earth will awake, some to everlasting life, but others to shame and everlasting contempt."}},"definableWords":["earth","everlasting","life"],"peopleInVerse":[]},"3":{"text":"And they that be wise shall shine as the brightness of the firmament; and they that turn many to righteousness as the stars for ever and ever.","ref":"Daniel 12:3","synthesized":"Then the wise will shine like the brightness of the heavens, and those who lead many to righteousness will shine like the stars forever and ever.","sources":{"KJV":{"text":"And they that be wise shall shine as the brightness of the firmament; and they that turn many to righteousness as the stars for ever and ever."},"BSB":{"text":"Then the wise will shine like the brightness of the heavens, and those who lead many to righteousness will shine like the stars forever and ever."}},"definableWords":["heavens","righteousness"],"peopleInVerse":[]},"4":{"text":"But thou, O Daniel, shut up the words, and seal the book, even to the time of the end: many shall run to and fro, and knowledge shall be increased.","ref":"Daniel 12:4","synthesized":"But you, Daniel, shut up these words and seal the book until the time of the end. Many will roam to and fro, and knowledge will increase.”","sources":{"KJV":{"text":"But thou, O Daniel, shut up the words, and seal the book, even to the time of the end: many shall run to and fro, and knowledge shall be increased."},"BSB":{"text":"But you, Daniel, shut up these words and seal the book until the time of the end. Many will roam to and fro, and knowledge will increase.”"}},"definableWords":["knowledge"],"peopleInVerse":["Daniel"]},"5":{"text":"Then I Daniel looked, and, behold, there stood other two, the one on this side of the bank of the river, and the other on that side of the bank of the river.","ref":"Daniel 12:5","synthesized":"Then I, Daniel, looked and saw two others standing there, one on this bank of the river and one on the opposite bank.","sources":{"KJV":{"text":"Then I Daniel looked, and, behold, there stood other two, the one on this side of the bank of the river, and the other on that side of the bank of the river."},"BSB":{"text":"Then I, Daniel, looked and saw two others standing there, one on this bank of the river and one on the opposite bank."}},"definableWords":["saw","one"],"peopleInVerse":["Daniel"]},"6":{"text":"And one said to the man clothed in linen, which was upon the waters of the river, How long shall it be to the end of these wonders?","ref":"Daniel 12:6","synthesized":"One of them said to the man dressed in linen, who was above the waters of the river, “How long until the fulfillment of these wonders?”","sources":{"KJV":{"text":"And one said to the man clothed in linen, which was upon the waters of the river, How long shall it be to the end of these wonders?"},"BSB":{"text":"One of them said to the man dressed in linen, who was above the waters of the river, “How long until the fulfillment of these wonders?”"}},"definableWords":["one","man","waters"],"peopleInVerse":[]},"7":{"text":"And I heard the man clothed in linen, which was upon the waters of the river, when he held up his right hand and his left hand unto heaven, and sware by him that liveth for ever that it shall be for a time, times, and an half; and when he shall have accomplished to scatter the power of the holy people, all these things shall be finished.","ref":"Daniel 12:7","synthesized":"And the man dressed in linen, who was above the waters of the river, raised his right hand and his left hand toward heaven, and I heard him swear by Him who lives forever, saying, “It will be for a time, and times, and half a time. When the power of the holy people has finally been shattered, all these things will be completed.”","sources":{"KJV":{"text":"And I heard the man clothed in linen, which was upon the waters of the river, when he held up his right hand and his left hand unto heaven, and sware by him that liveth for ever that it shall be for a time, times, and an half; and when he shall have accomplished to scatter the power of the holy people, all these things shall be finished."},"BSB":{"text":"And the man dressed in linen, who was above the waters of the river, raised his right hand and his left hand toward heaven, and I heard him swear by Him who lives forever, saying, “It will be for a time, and times, and half a time. When the power of the holy people has finally been shattered, all these things will be completed.”"}},"definableWords":["man","waters","heaven","holy","people"],"peopleInVerse":[]},"8":{"text":"And I heard, but I understood not: then said I, O my Lord, what shall be the end of these things?","ref":"Daniel 12:8","synthesized":"I heard, but I did not understand. So I asked, “My lord, what will be the outcome of these things?”","sources":{"KJV":{"text":"And I heard, but I understood not: then said I, O my Lord, what shall be the end of these things?"},"BSB":{"text":"I heard, but I did not understand. So I asked, “My lord, what will be the outcome of these things?”"}},"definableWords":["Lord"],"peopleInVerse":[]},"9":{"text":"And he said, Go thy way, Daniel: for the words are closed up and sealed till the time of the end.","ref":"Daniel 12:9","synthesized":"“Go on your way, Daniel,” he replied, “for the words are closed up and sealed until the time of the end.","sources":{"KJV":{"text":"And he said, Go thy way, Daniel: for the words are closed up and sealed till the time of the end."},"BSB":{"text":"“Go on your way, Daniel,” he replied, “for the words are closed up and sealed until the time of the end."}},"definableWords":["way"],"peopleInVerse":["Daniel"]},"10":{"text":"Many shall be purified, and made white, and tried; but the wicked shall do wickedly: and none of the wicked shall understand; but the wise shall understand.","ref":"Daniel 12:10","synthesized":"Many will be purified, made spotless, and refined, but the wicked will continue to act wickedly. None of the wicked will understand, but the wise will understand.","sources":{"KJV":{"text":"Many shall be purified, and made white, and tried; but the wicked shall do wickedly: and none of the wicked shall understand; but the wise shall understand."},"BSB":{"text":"Many will be purified, made spotless, and refined, but the wicked will continue to act wickedly. None of the wicked will understand, but the wise will understand."}},"definableWords":["made"],"peopleInVerse":[]},"11":{"text":"And from the time that the daily sacrifice shall be taken away, and the abomination that maketh desolate set up, there shall be a thousand two hundred and ninety days.","ref":"Daniel 12:11","synthesized":"And from the time the daily sacrifice is abolished and the abomination of desolation set up, there will be 1,290 days.","sources":{"KJV":{"text":"And from the time that the daily sacrifice shall be taken away, and the abomination that maketh desolate set up, there shall be a thousand two hundred and ninety days."},"BSB":{"text":"And from the time the daily sacrifice is abolished and the abomination of desolation set up, there will be 1,290 days."}},"definableWords":["sacrifice","days"],"peopleInVerse":[]},"12":{"text":"Blessed is he that waiteth, and cometh to the thousand three hundred and five and thirty days.","ref":"Daniel 12:12","synthesized":"Blessed is he who waits and reaches the end of the 1,335 days.","sources":{"KJV":{"text":"Blessed is he that waiteth, and cometh to the thousand three hundred and five and thirty days."},"BSB":{"text":"Blessed is he who waits and reaches the end of the 1,335 days."}},"definableWords":["blessed","days"],"peopleInVerse":[]},"13":{"text":"But go thou thy way till the end be: for thou shalt rest, and stand in thy lot at the end of the days.","ref":"Daniel 12:13","synthesized":"But as for you, go on your way until the end. You will rest, and will arise to your inheritance at the end of the days.”","sources":{"KJV":{"text":"But go thou thy way till the end be: for thou shalt rest, and stand in thy lot at the end of the days."},"BSB":{"text":"But as for you, go on your way until the end. You will rest, and will arise to your inheritance at the end of the days.”"}},"definableWords":["way","rest","days"],"peopleInVerse":[]}}}};